item.description:
 &lt;h2 id=&#34;接口&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#接口&#34;&gt;#&lt;/a&gt; 接口&lt;/h2&gt;
&lt;p&gt;JAVA 通过接口来实现多继承&lt;/p&gt;
&lt;h3 id=&#34;定义接口&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#定义接口&#34;&gt;#&lt;/a&gt; 定义接口&lt;/h3&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public interface interface1 &amp;#123;  //public intaerfasce 接口名&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    //变量全是静态变量&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public void Print();  //接口中的方法默认都是抽象方法(public abstract), public abstract可以省略&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;实现 (继承) 接口时，使用 &lt;code&gt;implements&lt;/code&gt;  关键字来实现，而不是 &lt;code&gt;extends&lt;/code&gt; 。&lt;/p&gt;
&lt;p&gt;而接口继承接口时，使用 &lt;code&gt;extends&lt;/code&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;35&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;36&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;37&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;38&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;39&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;40&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;interface interface1 &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public void PrintInterFace();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;interface interface2 extends interface1&amp;#123;  //extends继承接口&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public void PrintInterFace2();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;abstract class TestClass&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public void PrintClass()&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;PrintClass&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;public class TestInterface extends TestClass implements interface1,interface2&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    @Override&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public void PrintInterFace() &amp;#123;  //重写接口1的PrintInterFace静态方法&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;PrintInterFace1&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    @Override&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public void PrintInterFace2() &amp;#123;  //重写接口2的PrintInterFace2静态方法&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;PrintInterFace2&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    @Override&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public void PrintClass() &amp;#123;  //重写抽象类的抽象方法&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        super.PrintClass();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        TestInterface TestInterface = new TestInterface();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        TestInterface.PrintInterFace();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        TestInterface.PrintInterFace2();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        TestInterface.PrintClass();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;内部类&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#内部类&#34;&gt;#&lt;/a&gt; 内部类&lt;/h2&gt;
&lt;p&gt;内部类可以直接使用父类的私有 ( &lt;code&gt;private&lt;/code&gt; ) 变量，而继承无法使用。&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;class OutClass&amp;#123;  //外部类&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    private int A = 10 ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    class InClass&amp;#123;  //内部类&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        public void PrintIn()&amp;#123;   //内部类方法&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            System.out.println(A+10);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    static class StatiInClass&amp;#123;  //内部静态类&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        public static void PrintStatic()&amp;#123;  //内部静态类方法&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            System.out.println(&amp;quot;StaticInClass&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public void PrintOut()&amp;#123;  //外部类方法&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(A);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;public class Demo &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        OutClass OC = new OutClass();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        OC.PrintOut();  //外部类 PrintOut()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        OutClass.InClass IC = OC.new InClass();  //通过外部类对象来定义内部类的对象&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        //格式为 ： 外部类名.内部类名 对象名 = 外部类对象 . new 内部类（） ；&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        IC.PrintIn();  //内部类 PrintIn()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        //直接使用 外部类名.内部类名 对象名 = new 外部类名.内部类名(); 来实例化&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        OutClass.StatiInClass  SC= new OutClass.StatiInClass();  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        SC.PrintStatic(); &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;要在内部类方法中调用外部类中的值，使用  &lt;code&gt;外部类名.this.变量名&lt;/code&gt;  来实现。&lt;/p&gt;
&lt;h2 id=&#34;api&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#api&#34;&gt;#&lt;/a&gt; API&lt;/h2&gt;
&lt;p&gt;可以直接调用的方法集合&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;35&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;36&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;37&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;38&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;39&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;40&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;41&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;42&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;43&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;44&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;45&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;46&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;47&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;48&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;49&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;50&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;51&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;52&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;53&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;54&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;55&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;56&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;57&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;58&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;59&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;60&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;61&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;62&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;63&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;64&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;65&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;66&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;67&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;68&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;69&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;70&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;71&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;72&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;73&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;74&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;75&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;76&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;77&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;78&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;79&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;80&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;81&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;82&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;83&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;84&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;85&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;86&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;87&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;88&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;89&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;90&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;91&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;92&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;93&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;94&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;95&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;96&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;97&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;98&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;99&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;100&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;101&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;102&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;103&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;104&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;105&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    String S1 = &amp;quot;HEKHHKjpg&amp;quot;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    String S2 = &amp;quot;123123&amp;quot;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    String S3 = S1.concat(S2);  //使用concat连接字符串&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    System.out.println(S3);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    System.out.println(&amp;quot;=================1. replace===================&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    //replace来替换字符串&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    String S4 = S2.replace(&amp;#x27;2&amp;#x27;,&amp;#x27;R&amp;#x27;);//使用API将所有的2替换为R&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    System.out.println(S4);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    System.out.println(&amp;quot;===================2.substring=================&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    //substring截取字符串&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    String S5 = S1.substring(1,3);//去索引值，包含开不包含最后一个&amp;#x27;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    String S6 = S2.substring(1); //&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    System.out.println(S5);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    System.out.println(S6);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    System.out.println(&amp;quot;====================================&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    //toLowerCase将所有字符转为小写,toUpperCase转为大写&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    String S7 = S1.toLowerCase();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    String S8 = &amp;quot;lllllll&amp;quot;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    String S9 = S8.toUpperCase();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    System.out.println(S7);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    System.out.println(S9);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    System.out.println(&amp;quot;====================================&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    //trim将首尾的空格去掉&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    String S10 = &amp;quot;    HE    EH       &amp;quot;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    System.out.println(&amp;quot;&amp;quot; + S10 + &amp;quot;&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    String S11 = S10.trim();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    System.out.println(&amp;quot;&amp;quot; + S11+ &amp;quot;&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    System.out.println(&amp;quot;====================================&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    //charAt返回固定位置的字符&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    char S12 = S1.charAt(1);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    System.out.println(S12);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    System.out.println(&amp;quot;====================================&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    //endsWith判断末尾是否为某字段结尾&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    boolean B1 = S1.endsWith(&amp;quot;.jpg&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    System.out.println(B1);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    System.out.println(&amp;quot;================indexOf====================&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    //indexOf判断字符或者字符串再当前字符串中的位置&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    int I1 = S1.indexOf(&amp;quot;.jpg&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    System.out.println(I1);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    System.out.println(&amp;quot;===============length=====================&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    //length判断字符长度&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    int I2 = S1.length();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    System.out.println(I2);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    System.out.println(&amp;quot;===============equals=====================&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    //equals判断两个字符串是否相等&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    boolean B2 = S1.equals(S2);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    boolean B3 = S1.equals(S1);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    boolean B4 = S1.equals(S1.toLowerCase());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    System.out.println(&amp;quot;S1.equals(S2)&amp;quot; + B2);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    System.out.println(&amp;quot;S1.equals(S1)&amp;quot; + B3);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    System.out.println(&amp;quot;S1.equals(S1.toLowerCase())&amp;quot; + B4);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    System.out.println(&amp;quot;===============split=====================&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    //split分割字符串&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    String[] SP13 = S1.split(&amp;quot;K&amp;quot;);  //遇到K分割，返回数组&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    for (int i = 0;i &amp;lt; SP13.length;i++)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(SP13[i]);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    System.out.println(&amp;quot;====================================&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    //ceil向上取整 ,floor向下取整,round四舍五入&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    double D1 = -3.1415926;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    double D2 = Math.ceil(D1);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    System.out.println(D2);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    System.out.println(&amp;quot;==================Max==================&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    //Max最大,Min最小,Abs绝对值&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    double D3 = Math.max(1,2);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    double D4 = Math.min(1,2);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    double D5 = Math.abs(-12);//绝对值&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    System.out.println(D3);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    System.out.println(D4);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    System.out.println(&amp;quot;=================三角函数===================&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    //正弦&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    double DS1 = Math.sin(Math.PI/6);  //弧度制表示角度&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    //余弦&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    double DS2 = Math.cos(Math.PI/6);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    //正切&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    double DS3 = Math.tan(Math.PI/6);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    System.out.println(&amp;quot;Math.sin(Math.PI):  &amp;quot; + DS1 + &amp;quot;\n Math.cos(Math.PI): &amp;quot; + DS2 + &amp;quot;\n Math.tan(Math.PI): &amp;quot; + DS3);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    System.out.println(&amp;quot;=================幂运算===================&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    //pow幂运算 sqrt平方根 log10以10为底的对数&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    double D6 = Math.pow(3,4);  //三的四次方&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    double D7 = Math.sqrt(25);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    double D8 = Math.log10(233);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    System.out.println(&amp;quot;=================随机数===================&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    //random 获得随机数&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    double D9 = Math.random();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

 &lt;h2 id=&#34;项目介绍&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#项目介绍&#34;&gt;#&lt;/a&gt; 项目介绍&lt;/h2&gt;
&lt;p&gt;项目要求：&lt;/p&gt;
&lt;p&gt;使用 JAVA 制作爬虫，操作 API 爬取网页的信息，保存到本地。&lt;/p&gt;
&lt;h2 id=&#34;实现原理&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#实现原理&#34;&gt;#&lt;/a&gt; 实现原理&lt;/h2&gt;
&lt;p&gt;使用 Jsoup 解析 HTML，获取网站源代码，通过解析 HTML 获取需要的数据，并保存本地。&lt;/p&gt;
&lt;h2 id=&#34;maven框架&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#maven框架&#34;&gt;#&lt;/a&gt; Maven 框架&lt;/h2&gt;
&lt;h3 id=&#34;maven配置&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#maven配置&#34;&gt;#&lt;/a&gt; Maven 配置&lt;/h3&gt;
&lt;h4 id=&#34;配置maven环境&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#配置maven环境&#34;&gt;#&lt;/a&gt; 配置 Maven 环境&lt;/h4&gt;
&lt;p&gt;首先要去下载 Maven，这里是在 Maven 的下载地址: &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9tYXZlbi5hcGFjaGUub3JnL2Rvd25sb2FkLmNnaQ==&#34;&gt;Maven – Download Apache Maven&lt;/span&gt;, 然后解压到你想要的地方，然后打开 bin 文件夹，复制路径&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/05/Maven_path.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;然后配置环境变量（MAVEN_HOME 和 Path 都设置成你安装目录下的 bin 目录 ）。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/05/Maven_path1.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/05/Maven_path2.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;然后 Windows + R 输入 CMD, 接着输入  &lt;code&gt;mvn -v&lt;/code&gt;  来看看是否配置成功环境变量。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/05/Maven_path3-1024x145.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;如果输出版本，就说明配置成功。&lt;/p&gt;
&lt;h4 id=&#34;配置maven设置&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#配置maven设置&#34;&gt;#&lt;/a&gt; 配置 Maven 设置&lt;/h4&gt;
&lt;p&gt;紧接着要开始设置 Maven 了&lt;/p&gt;
&lt;p&gt;首先打开 conf 文件夹，打开 settings.xml&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/05/Maven_setting.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;找到  &lt;code&gt;&amp;lt;localRepository&amp;gt;/path/to/local/repo&amp;lt;/localRepository&amp;gt;&lt;/code&gt;  这句，复制出来，中间的  &lt;code&gt;`/path/to/local/repo`&lt;/code&gt;  这句是定义自己想要的 Jar 包的位置，选择自己想要的位置&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/05/Maven_setting1.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;然后配置 Jar 包下载的镜像。找到里面的  &lt;code&gt;&amp;lt;mirror&amp;gt;&lt;/code&gt;  标签，然后改为阿里云的镜像&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/05/Maven_setting2.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&amp;lt;!--阿里云镜像--&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;lt;mirror&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &amp;lt;id&amp;gt;nexus-aliyun&amp;lt;/id&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &amp;lt;mirrorOf&amp;gt;central&amp;lt;/mirrorOf&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &amp;lt;name&amp;gt;Nexus aliyun&amp;lt;/name&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      &amp;lt;url&amp;gt;http://maven.aliyun.com/nexus/content/groups/public&amp;lt;/url&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;lt;/mirror&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;然后保存，Maven 设置完成。&lt;/p&gt;
&lt;h4 id=&#34;idja上的maven设置&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#idja上的maven设置&#34;&gt;#&lt;/a&gt; IDJA 上的 Maven 设置&lt;/h4&gt;
&lt;p&gt;打开 IDJA ，点击 “文件”, 进入 &amp;quot;新项目设置&amp;quot;。（英文版为：点击 File ，进入 Other Settings Of New Project \New Project Settings）&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/05/maven_IDJA.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;搜索 Maven (英文版同理)。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/05/maven_IDJA1.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;在” 用户设置文件 “导入之前在 Setting.xml 的设置，在 “本地仓库 &amp;quot; 选择之前在 Setting.xml 中设置的 Jar 的路径，“Maven 主路径” 选择 conf 的上一级文件夹。（英文对照: “Maven 主路径” : Maven home directopry ，“用户设置文件” : User settings file，“本地仓库” : Local repository）&lt;/p&gt;
&lt;p&gt;导入 Setting.xml 后 &amp;quot;本地仓库 (Local repository)&amp;quot; 和’用户设置文件 (User settings file)“后面的 &amp;quot; 重写”(Override) 记得勾选&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/05/maven_IDJA2-1024x800.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;然后点击 &amp;quot;应用&amp;quot;(Apply)。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/05/maven_IDJA3-1024x362.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;IDJA 的 Maven 设置成功 o (〃＾▽＾〃) o&lt;/p&gt;
&lt;h3 id=&#34;maven目录结构&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#maven目录结构&#34;&gt;#&lt;/a&gt; Maven 目录结构&lt;/h3&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;Maven1//Maven项目名&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    └─src&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        ├─main&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        │  ├─java&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        │  └─resources&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        └─test&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            ├─java&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            └─resources&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;ul&gt;
&lt;li&gt;Windows 系统显示文件目录树&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;在 CMD 窗口下输入&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;Tree + [查看目录树的地址]&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;就可显示了&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/05/%E5%B1%8F%E5%B9%95%E6%88%AA%E5%9B%BE-2022-05-15-111235.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;Maven 仓库依赖&lt;/p&gt;
&lt;p&gt;点击&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9tdm5yZXBvc2l0b3J5LmNvbS8=&#34;&gt;此链接&lt;/span&gt;进入&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9tdm5yZXBvc2l0b3J5LmNvbS8=&#34;&gt; Maven 仓库&lt;/span&gt;，点击选择需要的 API 版本，点击在需要的 API 找到 Maven 点击即可复制。&lt;/p&gt;
&lt;h3 id=&#34;cmd编译和运行maven项目&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#cmd编译和运行maven项目&#34;&gt;#&lt;/a&gt; CMD 编译和运行 Maven 项目&lt;/h3&gt;
&lt;p&gt;cmd 找到项目的根目录，找到 maven 项目的根目录，在地址框输入 cmd，回车（或者 win + R, 输入 cmd 打开 cmd 窗口然后  &lt;code&gt;cd maven项目路径&lt;/code&gt;  ）, 在弹出的 cmd 窗口中输入  &lt;code&gt;mvn compile&lt;/code&gt;  编译。输出 “BUILD SUCCESS” 说明编译成功。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/05/maven_cmd_build1-1024x483.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;我们看到了出现了这样的提示：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/05/maven_cmd_build2-1024x90.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;是因为编码设置的不正确，这时候要打开项目的 pom.xml 文件，在 &lt;code&gt;&amp;lt;properties&amp;gt;&lt;/code&gt;  里加入下面这句&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&amp;lt;project.build.sourceEncoding&amp;gt;UTF-8&amp;lt;/project.build.sourceEncoding&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;然后再运行 &lt;code&gt;mvn compile&lt;/code&gt;  就不报错啦。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/05/maven_cmd_build3-1024x467.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;运行 Maven 项目&lt;/p&gt;
&lt;p&gt;写一个 JAVA 程序&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class Main &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;Hello,Maven!&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;然后在当前 Cmd 窗口下输入  &lt;code&gt;mvn exec:java -Dexec.mainClass=&amp;quot;PC&amp;quot;&lt;/code&gt;  就可以运行在 main 问减价下的 Main 类中的 Main 方法。&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;mvn exec:java -Dexec.mainClass=&amp;quot;PC&amp;quot;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;//注意: PC是我自己写的JAVA类名，-Dexec.mainClass会让Maven从项目目录的main文件夹开始&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;mvn exec:java -Dexec.mainClass=&amp;quot;&amp;quot; &lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;编译完成输出结果：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/05/maven_cmd_build4.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;java爬虫&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#java爬虫&#34;&gt;#&lt;/a&gt; JAVA 爬虫&lt;/h2&gt;
&lt;p&gt;配置到 Maven 框架，就可以愉快的编写 JAVA 爬虫了。&lt;/p&gt;
&lt;p&gt;爬虫 ： 按照一定的规则，自动地抓取万维网信息的程序或者脚本&lt;/p&gt;
&lt;h3 id=&#34;环境配置&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#环境配置&#34;&gt;#&lt;/a&gt; 环境配置&lt;/h3&gt;
&lt;p&gt;前提：&lt;/p&gt;
&lt;p&gt;IntelliJ IDEA&lt;/p&gt;
&lt;p&gt;Maven 框架&lt;/p&gt;
&lt;p&gt;JDK 1.8&lt;/p&gt;
&lt;h4 id=&#34;安装需要的jar包&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#安装需要的jar包&#34;&gt;#&lt;/a&gt; 安装需要的 Jar 包&lt;/h4&gt;
&lt;p&gt;&lt;strong&gt;以下的所有 Jar 包均可再 Maven 仓库 &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9tdm5yZXBvc2l0b3J5LmNvbS8=&#34;&gt;https://mvnrepository.com/&lt;/span&gt; 下载&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;接着要安装 Jsoup 包，用于解析 HTML 并查找 (均放在 &lt;code&gt;&amp;lt;dependencies&amp;gt;&amp;lt;/dependencies&amp;gt;&lt;/code&gt;  标签中 )&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&amp;lt;!-- https://mvnrepository.com/artifact/org.jsoup/jsoup --&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;lt;dependency&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;lt;groupId&amp;gt;org.jsoup&amp;lt;/groupId&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;lt;artifactId&amp;gt;jsoup&amp;lt;/artifactId&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;lt;version&amp;gt;1.14.3&amp;lt;/version&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;lt;/dependency&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;还有 SLF4J 包，用来记录日志。&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&amp;lt;!-- https://mvnrepository.com/artifact/org.slf4j/slf4j-log4j12 --&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;lt;dependency&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;lt;groupId&amp;gt;org.slf4j&amp;lt;/groupId&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;lt;artifactId&amp;gt;slf4j-log4j12&amp;lt;/artifactId&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;lt;version&amp;gt;1.7.25&amp;lt;/version&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;lt;scope&amp;gt;test&amp;lt;/scope&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;lt;/dependency&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;Commons-io, 常用的工具类&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&amp;lt;!-- https://mvnrepository.com/artifact/commons-io/commons-io --&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;lt;dependency&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;lt;groupId&amp;gt;commons-io&amp;lt;/groupId&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;lt;artifactId&amp;gt;commons-io&amp;lt;/artifactId&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;lt;version&amp;gt;2.11.0&amp;lt;/version&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;lt;/dependency&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;以及处理字符串的 common-lang3&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&amp;lt;!-- https://mvnrepository.com/artifact/org.apache.commons/commons-lang3 --&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;lt;dependency&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;lt;groupId&amp;gt;org.apache.commons&amp;lt;/groupId&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;lt;artifactId&amp;gt;commons-lang3&amp;lt;/artifactId&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;lt;version&amp;gt;3.12.0&amp;lt;/version&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;lt;/dependency&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;配置slf4j&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#配置slf4j&#34;&gt;#&lt;/a&gt; 配置 SLF4J&lt;/h4&gt;
&lt;p&gt;在 resources 下创建一个 SLF4J 配置文件，名为  &lt;code&gt;log4j.properties&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/05/PaChong_Start1-1024x510.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/05/PaChong_Start2.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;写入配置代码：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/05/PaChong_Start3-1024x230.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;log4j.rootLogger=DEBUG,A1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;log4j.logger.cn.itcast = DEBUG&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;log4j.appender.A1=org.apache.log4j.ConsoleAppender&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;log4j.appender.A1.layout=org.apache.log4j.PatternLayout&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;log4j.appender.A1.layout.ConversionPattern=%-d&amp;#123;yyyy-MM-dd HH:mm:ss, SSS&amp;#125; [%t] [%c]-[%p] %m%n&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;至此 Java 的环境配置完成。&lt;/p&gt;
&lt;h3 id=&#34;java爬虫编写&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#java爬虫编写&#34;&gt;#&lt;/a&gt; JAVA 爬虫编写&lt;/h3&gt;
&lt;h4 id=&#34;使用-jsoup-实现爬取文章封面&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#使用-jsoup-实现爬取文章封面&#34;&gt;#&lt;/a&gt; 使用 Jsoup 实现爬取文章封面&lt;/h4&gt;
&lt;p&gt;分析源代码，找出封面位置，是在 &lt;code&gt;&amp;lt;div class=&amp;quot;cover&amp;quot;&amp;gt;&lt;/code&gt;  中的 &lt;code&gt;&amp;lt;img&amp;gt;&lt;/code&gt;  标签的 &lt;code&gt;data-src&lt;/code&gt;  属性&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/05/Maven_HTML-1024x96.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;接下来的操作，将围绕这个 &lt;code&gt;&amp;lt;div&amp;gt;&lt;/code&gt;  框和里面的 &lt;code&gt;&amp;lt;img&amp;gt;&lt;/code&gt;  标签展开&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;35&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;36&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;37&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;38&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;39&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;40&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;41&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;42&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;43&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;44&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;45&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;46&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;47&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;48&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;49&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;50&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;51&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;52&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;53&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;54&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;55&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;56&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;57&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;58&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;59&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;60&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;61&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;62&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;63&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;64&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;import org.jsoup.Connection;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;import org.jsoup.Jsoup;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;import org.jsoup.nodes.Document;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;import org.jsoup.nodes.Element;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;import org.jsoup.select.Elements;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;import org.apache.commons.io.*;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;import java.io.*;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;import java.net.URL;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;import java.net.URLConnection;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;public class Main &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) throws IOException&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        /*获取HTML*/&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        //String Url = &amp;quot;https://xenolies.xyz/&amp;quot;;  //爬取网站2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        String Url = &amp;quot;https://xenolies.github.io/&amp;quot;;//需要爬取的网站URL&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        //使用Jsoup.connect()方法链接Url,获取HTML文件&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Connection connection =  Jsoup.connect(Url);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        //设置延时，避免出现Connection reset错误&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        connection.timeout(3000); &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        //使用Get(),解析HTML，使用Document来接受返回的信息&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Document document = connection.get();  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        /*使用各种选择器来解析获取获取到的HTML*/ &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        //使用Class选择元素，获取所有名为cover的元素&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Elements cover = document.getElementsByClass(&amp;quot;cover&amp;quot;); &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        //创建list来保存爬出的图片URL&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        String[] UrlList = new String[cover.size()];  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        //for循环持续爬取图片,.size()获取循环次数&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        for (int Time = 0;Time &amp;lt; cover.size();Time++)&amp;#123; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            /*从获取的元素中获取数据*/&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            //获取属性值&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            //获取cover中的包含&amp;lt;img&amp;gt;标签的第几个&amp;lt;div&amp;gt;(数组排列)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            Element div = cover.get(Time);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            Elements imgUrl = div.getElementsByTag(&amp;quot;img&amp;quot;);  //获取到&amp;lt;img标签&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            String ImgUrl = imgUrl.attr(&amp;quot;data-src&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            System.out.println(&amp;quot;第&amp;quot; + (Time+1) + &amp;quot;张图片&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            UrlList[Time] = ImgUrl;  //将单个的图片地址添加进数组&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        String filePath = &amp;quot;C:\\Users\\35367\\Desktop\\Webps&amp;quot; ;  //图片保存的位置&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        for (int i = 0;i &amp;lt; cover.size();i++)&amp;#123;  //遍历,下载&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            File dir = new File(filePath);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            //substring()方法来截取字符串，lastIndexOf()来截取最后一个 &amp;quot;/&amp;quot;出现时候的位置（要+1来跳过）&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            String fileName = UrlList[i].substring(UrlList[i].lastIndexOf(&amp;quot;/&amp;quot;) + 1,UrlList[i].length());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            //File.separator为分隔符，在什么系统使用法对应的分隔符，用于保存&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            File file = new File(filePath + File.separator + fileName);  //输出的路径&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            Connection connectionIMG = Jsoup.connect(UrlList[i]);  //建立新的connection&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            URL url =new URL(UrlList[i]);  //new成为Url以便后面使用&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            URLConnection ConnectionIMG = url.openConnection();  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            InputStream in = ConnectionIMG.getInputStream();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            OutputStream out = new BufferedOutputStream(new FileOutputStream(file));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            byte[] buf = new byte[1024];&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            int len = -1;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            while ((len = in.read(buf)) != -1) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                out.write(buf, 0, len);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;爬取结果:&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/05/BXBEELFKTPOELV_SSY-1024x573.jpg&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;h4 id=&#34;jsoup-hssfworkbook-爬取生成表格&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#jsoup-hssfworkbook-爬取生成表格&#34;&gt;#&lt;/a&gt; Jsoup + HSSFWorkbook 爬取，生成表格&lt;/h4&gt;
&lt;p&gt;这次爬取的网页时 LR2 的段位表&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/05/LR2_IR-1024x469.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;F12 打开控制台，查看源代码，&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/05/LR2_IR1-1024x476.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;发现我们要找的东西在  &lt;code&gt;&amp;lt;tr&amp;gt;&lt;/code&gt;  框的  &lt;code&gt;&amp;lt;th&amp;gt;&lt;/code&gt;  标签和  &lt;code&gt;&amp;lt;td&amp;gt;标签&lt;/code&gt; 里面，单纯的提取  &lt;code&gt;&amp;lt;tr&amp;gt;&lt;/code&gt;  会导致混乱，所以要加入一个判断。&lt;/p&gt;
&lt;p&gt;因为段位表是表格，所以我们要引入一个新的 Jar 包 Poi , 来制作导出表格&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&amp;lt;!-- https://mvnrepository.com/artifact/org.apache.poi/poi --&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;lt;dependency&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;lt;groupId&amp;gt;org.apache.poi&amp;lt;/groupId&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;lt;artifactId&amp;gt;poi&amp;lt;/artifactId&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;lt;version&amp;gt;4.1.2&amp;lt;/version&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;lt;/dependency&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;使用教程可以参考这个 ：&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cuamlhbnNodS5jb20vcC9kZDFlNGYyODc1N2I=&#34;&gt;使用 HSSFWorkbook 导出、操作 excell&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;代码如下 ：&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&