=&#34;line&#34;&gt;204&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;205&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;206&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;207&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;208&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;209&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;210&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;211&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;212&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;213&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;214&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;215&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;216&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;217&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;218&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;import org.apache.poi.hssf.usermodel.*;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;import org.jsoup.Connection;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;import org.jsoup.Jsoup ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;import org.jsoup.nodes.Document;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;import org.jsoup.nodes.Element;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;import org.jsoup.select.Elements;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;import java.io.FileOutputStream;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;import java.io.IOException;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;public class Main &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) throws IOException &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        //确认爬取的HTML网页,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        String url = &amp;quot;http://www.dream-pro.info/~lavalse/LR2IR/search.cgi?mode=gradelist&amp;quot;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        //链接网页&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Connection connection = Jsoup.connect(url);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        //获取网站源代码&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Document document = connection.get();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        SPRank(document);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        DPRank(document);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void SPRank(Document document) throws IOException &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Elements Table = document.getElementsByTag(&amp;quot;table&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Element table = Table.get(0);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Elements Tr = table.getElementsByTag(&amp;quot;tr&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        //System.out.println(Tr);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Elements H3 = document.getElementsByTag(&amp;quot;h3&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        //System.out.println(H3);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        String h31 = H3.get(0).text();  //SP段位名&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        HSSFWorkbook hssfWorkbook = new HSSFWorkbook();  //创建Excal表&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        HSSFSheet hssfSheetSP = hssfWorkbook.createSheet(h31);  //创建名为 :&amp;quot;段位認定　シングル(2018) &amp;quot; Excel&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        //设置单元格宽度&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        hssfSheetSP .setColumnWidth(1, 8000);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        HSSFCellStyle cellStyle= hssfWorkbook.createCellStyle();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        //设置水平对齐的样式为居中对齐;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        cellStyle.setAlignment(HSSFCellStyle.ALIGN_CENTER);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        //设置字体&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        HSSFFont font = hssfWorkbook.createFont();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        font.setFontName(&amp;quot;黑体&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int Th1 = 0;  //列数&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int Tr1 = Tr.size();  //行数&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        String star = &amp;quot;&amp;quot;;  //小段位星级&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        String gradename = &amp;quot;&amp;quot;;  //小段位名&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        String crossnum = &amp;quot;&amp;quot;;  //小合格人数&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        String challengesnum = &amp;quot;&amp;quot;;  //小挑战人数&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        String yield = &amp;quot;&amp;quot;;  //小合格率&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        String Star = &amp;quot;&amp;quot;;  //段位星级&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        String GradeName = &amp;quot;&amp;quot;;  //段位名&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        String CrossNum = &amp;quot;&amp;quot;;  //合格人数&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        String ChallengesNum = &amp;quot;&amp;quot;;  //挑战人数&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        String Yield = &amp;quot;&amp;quot;;  //合格率&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        for (int Tri = 0; Tri &amp;lt; Tr.size(); Tri++) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            Element TrTitle = Tr.get(Tri);  //第几个Tr框&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            Elements Td = TrTitle.getElementsByTag(&amp;quot;td&amp;quot;);  //合格率等标题 : &amp;lt;th&amp;gt; 其他的时 : &amp;lt;td&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            Elements Th = TrTitle.getElementsByTag(&amp;quot;th&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            HSSFRow hssfRow = hssfSheetSP.createRow(Tri);  //在对应的行中填入数据，定位行&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            HSSFCell cell1 = hssfRow.createCell(0);  //第rowi行第一个单元格&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            HSSFCell cell2 = hssfRow.createCell(1);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            HSSFCell cell3 = hssfRow.createCell(2);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            HSSFCell cell4 = hssfRow.createCell(3);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            HSSFCell cell5 = hssfRow.createCell(4);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            if (Td.size() == 0) &amp;#123;  //获取小段位内容&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125; else &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                star = Td.get(0).text();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                gradename = Td.get(1).text();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                crossnum = Td.get(2).text();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                challengesnum = Td.get(3).text();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                yield = Td.get(4).text();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                cell1.setCellValue(star);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                cell2.setCellValue(gradename);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                cell3.setCellValue(crossnum);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                cell4.setCellValue(challengesnum);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                cell5.setCellValue(yield);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            if (Th.size() == 0) &amp;#123;  //获取段位表内容&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125; else &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                Th1 = Th.size();  //获取列数&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                Star = Th.get(0).text();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                GradeName = Th.get(1).text();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                CrossNum = Th.get(2).text();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                ChallengesNum = Th.get(3).text();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                Yield = Th.get(4).text();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                cell1.setCellValue(Star);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                cell2.setCellValue(GradeName);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                cell3.setCellValue(CrossNum);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                cell4.setCellValue(ChallengesNum);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                cell5.setCellValue(Yield);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            //表名  : 段位認定　シングル(2018) (h31)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            //项目名 : 1.星级 Star 2.段位名 GradeName 3.合格人数 CrossNum 4.挑战人数 ChallengesNum 5.通过率 Yield&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            //行数: Tr1 , 列数 : Th1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        FileOutputStream fos = new FileOutputStream(&amp;quot;C:\\Users\\35367\\Desktop\\LR2(SP).xls&amp;quot;);  //IO流写入&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        hssfWorkbook.write(fos);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        fos.close();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;SPRank创建成功&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void DPRank(Document document) throws IOException&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Elements Table = document.getElementsByTag(&amp;quot;table&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Element table = Table.get(1);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Elements Tr = table.getElementsByTag(&amp;quot;tr&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        //System.out.println(Tr);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Elements H3 = document.getElementsByTag(&amp;quot;h3&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        //System.out.println(H3);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        String h32 = H3.get(1).text();  //SP段位名&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        HSSFWorkbook hssfWorkbook = new HSSFWorkbook();  //创建Excal表&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        HSSFSheet hssfSheetDP = hssfWorkbook.createSheet(h32);  //创建名为 :&amp;quot;段位認定　DP(2018) &amp;quot; Excel表&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        //设置单元格宽度&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        hssfSheetDP .setColumnWidth(1, 8400);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        HSSFCellStyle cellStyle= hssfWorkbook.createCellStyle();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        //设置水平对齐的样式为居中对齐;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        cellStyle.setAlignment(HSSFCellStyle.ALIGN_CENTER);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        //设置字体&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        HSSFFont font = hssfWorkbook.createFont();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        font.setFontName(&amp;quot;黑体&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int Th1 = 0;  //列数&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int Tr1 = Tr.size();  //行数&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        String star = &amp;quot;&amp;quot;;  //小段位星级&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        String gradename = &amp;quot;&amp;quot;;  //小段位名&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        String crossnum = &amp;quot;&amp;quot;;  //小合格人数&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        String challengesnum = &amp;quot;&amp;quot;;  //小挑战人数&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        String yield = &amp;quot;&amp;quot;;  //小合格率&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        String Star = &amp;quot;&amp;quot;;  //段位星级&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        String GradeName = &amp;quot;&amp;quot;;  //段位名&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        String CrossNum = &amp;quot;&amp;quot;;  //合格人数&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        String ChallengesNum = &amp;quot;&amp;quot;;  //挑战人数&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        String Yield = &amp;quot;&amp;quot;;  //合格率&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        for (int Tri = 0; Tri &amp;lt; Tr.size(); Tri++) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            Element TrTitle = Tr.get(Tri);  //第几个Tr框&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            Elements Td = TrTitle.getElementsByTag(&amp;quot;td&amp;quot;);  //合格率等标题 : &amp;lt;th&amp;gt; 其他的时 : &amp;lt;td&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            Elements Th = TrTitle.getElementsByTag(&amp;quot;th&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            HSSFRow hssfRow = hssfSheetDP.createRow(Tri);  //在对应的行中填入数据，定位行&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            HSSFCell cell1 = hssfRow.createCell(0);  //第rowi行第一个单元格&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            HSSFCell cell2 = hssfRow.createCell(1);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            HSSFCell cell3 = hssfRow.createCell(2);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            HSSFCell cell4 = hssfRow.createCell(3);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            HSSFCell cell5 = hssfRow.createCell(4);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            if (Td.size() == 0) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;else &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                star = Td.get(0).text();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                gradename = Td.get(1).text();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                crossnum = Td.get(2).text();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                challengesnum = Td.get(3).text();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                yield = Td.get(4).text();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                cell1.setCellValue(star);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                cell2.setCellValue(gradename);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                cell3.setCellValue(crossnum);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                cell4.setCellValue(challengesnum);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                cell5.setCellValue(yield);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            if (Th.size() == 0) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;else  &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                Th1 = Th.size();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                Star = Th.get(0).text();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                GradeName = Th.get(1).text();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                CrossNum = Th.get(2).text();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                ChallengesNum = Th.get(3).text();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                Yield = Th.get(4).text();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                cell1.setCellValue(Star);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                cell2.setCellValue(GradeName);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                cell3.setCellValue(CrossNum);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                cell4.setCellValue(ChallengesNum);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                cell5.setCellValue(Yield);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        //表名  : 段位認定　シングル(2018) (h31)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        //项目名 : 1.星级 Star 2.段位名 GradeName 3.合格人数 CrossNum 4.挑战人数 ChallengesNum 5.通过率 Yield&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        //行数: Tr1 , 列数 : Th1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        FileOutputStream fos = new FileOutputStream(&amp;quot;C:\\Users\\35367\\Desktop\\LR2(DP).xls&amp;quot;);  //IO流写入&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        hssfWorkbook.write(fos);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        fos.close();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;DPRank创建成功&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;输出结果:&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/05/HSSF_Jsoup-1024x583.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;

 &lt;h2 id=&#34;初始化块&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#初始化块&#34;&gt;#&lt;/a&gt; 初始化块&lt;/h2&gt;
&lt;p&gt;初始化块&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;作用类似构造方法，可以对对象进行初始化操作。&lt;/li&gt;
&lt;li&gt;无法传入任何参数，可以理解为提前执行的代码&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;使用初始化块&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;//class 类名&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;//[修饰符]&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;//        初始化块的可执行代码&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;//    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;//&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;class Demo&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;初始化块&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public Demo()&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;构造方法&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;public class Demo1 &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Demo Demo = new Demo();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;[buy] 如果有静态初始化块，会优先执行 [/buy]&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;class Demo&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    static &amp;#123;　//属于类&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;静态初始化块&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#123;　//属于对象  在初始化块中的变量属于局部变量，需要初始化&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;初始化块&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public Demo()&amp;#123;　//属于对象&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;构造方法&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;public class Demo1 &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Demo Demo = new Demo();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;运行结果：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/05/%E5%B1%8F%E5%B9%95%E6%88%AA%E5%9B%BE-2022-05-06-093142.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;final-修饰符&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#final-修饰符&#34;&gt;#&lt;/a&gt; Final 修饰符&lt;/h2&gt;
&lt;p&gt;final 关键字可用于修饰类，变量和方法。用来表示修饰的变量不可改变。&lt;/p&gt;
&lt;p&gt;一旦初始化就无法赋值了。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/05/Final1.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;[warning] final 只能在定义时，构造方法里以及初始化块中，无法在 Main 方法中赋值 [/warning]&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;Final 修饰变量&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;定义必须初始化，一旦初始化就无法赋值&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;35&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;36&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;37&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;38&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;39&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;class Demo&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    final static int A  ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    final int B  ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    final int C = 10 ;  //定义&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    static &amp;#123;  //静态初始化块&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        A = 10 ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public Demo ()&amp;#123; //构造方法&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        B = 10 ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public int getA()&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        return A ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public int getB()&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        return B ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public int getC()&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        return C;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;public class Demo1 &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Demo Demo = new Demo();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(Demo.getA());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(Demo.getB());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(Demo.getC());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;ul&gt;
&lt;li&gt;Final 修饰数组&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;指向的地址无法改变，可以改变数组中元素的值&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class Demo &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        final int[] Arr = &amp;#123;1,2,3&amp;#125;;  //定义数组Arr 元素有 1,2,3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        for (int i = 0;i&amp;lt;Arr.length;i++)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            Arr[i] = Arr[i] * 2 ;  //元素大小乘2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            System.out.print(Arr[i] +&amp;quot; ,&amp;quot; );  //遍历输出&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;输出结果：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/05/Fianl2.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;Final 修饰方法&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;如果有子类，则无法对加 Final 的方法进行重写&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/05/Final3.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;Final 修饰类&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;将无法被继承&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/05/Final4.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;抽象类abstract&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#抽象类abstract&#34;&gt;#&lt;/a&gt; 抽象类 (abstract )&lt;/h2&gt;
&lt;p&gt;不包含方法体的方法称为 “抽象方法”，（在 JAVA 中只要有花括号括起来的都是方法体）&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;作用＆注意&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;拿来当父类使用，无法被实例化，abstract 方法只能存在于 abstract 类中，abstract 方法只能被重写&lt;/p&gt;
&lt;p&gt;无法修饰属性，无法修饰构造方法，abstract 只有重写才有意义&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;abstract class DemoAbstract &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public abstract void Print1();  //抽象方法 Print1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public void Print2()&amp;#123; //普通方法 Print2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;DemoAbstract.Print2&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;public class Demo extends DemoAbstract&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public void Print1()&amp;#123;  //重写抽象方法&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            System.out.println(&amp;quot;Demo.Print&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Demo Demo = new Demo();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Demo.Print1();  //继承重写的抽象方法&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Demo.Print2();  //抽象类写的普通方法&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;[noway] abstract 无法和 final 同时使用 [/noway]&lt;/p&gt;
&lt;p&gt;abstract 构造方法&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;abstract class DemoAbstract &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    String Name ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public DemoAbstract(String Name)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        this.Name = Name;  //抽象类中的构造方法 DemoAbstract&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;public class Demo extends DemoAbstract&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public Demo(String Name)&amp;#123;  //子类的构造方法&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        super(Name); //super调用父类 DemoAbstract 的构造方法&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Demo Demo = new Demo(&amp;quot;Name&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(Demo.Name);  //输出父类 DemoAbstract 的属性 Name 的值&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

 &lt;h2 id=&#34;隐藏封装和继承&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#隐藏封装和继承&#34;&gt;#&lt;/a&gt; 隐藏，封装和继承&lt;/h2&gt;
&lt;p&gt;private 关键字&lt;/p&gt;
&lt;h3 id=&#34;封装&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#封装&#34;&gt;#&lt;/a&gt; 封装&lt;/h3&gt;
&lt;p&gt;封装是面向对象的三大特征之一，将对象的状态信息隐藏在内部，不允许外部程序直接访问对象。&lt;/p&gt;
&lt;h4 id=&#34;private关键字&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#private关键字&#34;&gt;#&lt;/a&gt; Private 关键字&lt;/h4&gt;
&lt;p&gt;在变量前加  &lt;code&gt;private&lt;/code&gt;  可以封装变量，封装后只能在同一个类中修改。&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class Demo1 &amp;#123; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    private int G = 10; //封装变量G &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;public class Demo &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    Demo1.G = 100;  //修改变量G，这时会报错&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;报错提示:&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/04/%E5%B1%8F%E5%B9%95%E6%88%AA%E5%9B%BE-2022-04-23-153900.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;翻译过来就是:&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/04/%E5%B1%8F%E5%B9%95%E6%88%AA%E5%9B%BE-2022-04-23-154119.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;要使用方法来赋值:&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class Demo1 &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    private int G = 10;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public int SetG(int G)&amp;#123;  //在原来的类中写方法&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        this.G = G ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        return this.G;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;public class Demo &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    Demo1 demo1 = new Demo1();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;     int P = demo1.SetG(1000); //通过方法赋值&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    System.out.println(P);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;继承&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#继承&#34;&gt;#&lt;/a&gt; 继承&lt;/h3&gt;
&lt;p&gt;extends&lt;/p&gt;
&lt;p&gt;继承是面向对象的三大特征之一&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;//[修饰符] class 子类名 extends 父类名()&amp;#123;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;重写父类方法&lt;/p&gt;
&lt;p&gt;直接添加方法&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;//父类&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;public class Person &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    String name ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    int age;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public Person()&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public Person(String name ,int age)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        this.name = name;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        this.age = age;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public void say()&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(name + &amp;quot; say,I`m &amp;quot; + age +&amp;quot; years old&amp;quot; );&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;//子类&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;public class Person1 extends Person&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public void say()&amp;#123; //这里重写了say的无参方法&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(name + &amp;quot; no say &amp;quot; );&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Person1 Qin = new Person1();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Qin.name =&amp;quot;Qin&amp;quot;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Qin.say();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;输出结果:&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/04/extends1.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;这样做的问题是会导致继承的类中方法无法使用，就要用 &lt;code&gt;super&lt;/code&gt;  来代替父类调用:&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class Person1 extends Person&amp;#123;  //子类&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public void say()&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        super.say();//用super来调用父类的say方法&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(name + &amp;quot; no say &amp;quot; );&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Person1 Qin = new Person1();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Qin.name =&amp;quot;Qin&amp;quot;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Qin.say();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;输出结果:&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/04/extend2.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;[noway] 如果父类中有构造方法，子类中必须有构造方法，而且必须调用 [/noway]&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;35&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;36&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;37&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;38&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;39&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;40&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;41&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;42&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;43&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;44&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;45&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;46&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;47&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;48&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;49&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;//使用super继承父类的构造方法&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;//子类&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;public class Trees extends Tree&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    int number ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Trees Trees = new Trees();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Trees.number = 100 ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Trees.flower();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public Trees ()&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;子类无参构造&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    //如果父类中有不带参数的构造方法，子类会自动调用&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public Trees (String name ,String kind,int number)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        super(name,kind); //注意:父类的构造方法必须要在子类构造方法的第一行&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        this.number = number;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public void flower()&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;这是 &amp;quot; + kind + &amp;quot; ,名为 &amp;quot; +name + &amp;quot; ,一共&amp;quot; + number + &amp;quot;棵&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;//父类&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;public class Tree &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    String name  = &amp;quot;桃树&amp;quot;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    String kind = &amp;quot;果树&amp;quot;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public Tree()&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;父类无参构造&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public Tree(String name ,String kind)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        this.name = name ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        this.kind = kind ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public void flower()&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;这是 &amp;quot; + kind + &amp;quot; ,名为 &amp;quot; +name + &amp;quot; .&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;输出结果:&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/04/extend3.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;多态&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#多态&#34;&gt;#&lt;/a&gt; 多态&lt;/h3&gt;
&lt;p&gt;指同样的操作作用于不同的对象，，可以有不同的解释，产生不同的执行结果.&lt;/p&gt;
&lt;p&gt;只能调用父类中有的方法&lt;/p&gt;
&lt;p&gt;向上转型 (向上转型只能调用父类中有的或者父类和子类共有的方法)&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;35&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;36&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;37&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;38&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;class Animal1&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    String Name = &amp;quot;Aninal&amp;quot; ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    String Say = &amp;quot;SAYYY&amp;quot;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public Animal1(String name, String say) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        this.Name = name;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        this.Say = say;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public Animal1() &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public void Say()&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println( &amp;quot; Name: &amp;quot; +  Name +  &amp;quot; Say: &amp;quot; + Say);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;class Dogs extends Animal1&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public void Say()&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println( &amp;quot; Say: &amp;quot; + Say + &amp;quot; Name: &amp;quot; + Name );&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public void Run() &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(Name + &amp;quot;Run&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;public class Test &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Dogs Dog = new Dogs();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Dog.Say();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Dogs Dog1 = (Dogs)Dog;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Dog1.Say();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;输出结果：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/05/%E5%B1%8F%E5%B9%95%E6%88%AA%E5%9B%BE-2022-05-06-095331.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;向下转型 (强制转型来调用子类的单独的方法)&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class Test &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Dogs Dog1 = (Dogs)Dog;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Dog1.Say();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;输出结果：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/05/%E5%B1%8F%E5%B9%95%E6%88%AA%E5%9B%BE-2022-05-06-095413.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;

 &lt;h2 id=&#34;引子&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#引子&#34;&gt;#&lt;/a&gt; 引子&lt;/h2&gt;
&lt;p&gt;马里奥的游戏总是可以给人欢乐，而这样的欢乐却和其他的游戏大为相反，比起画面，马里奥往往给人新鲜感和单纯的乐趣。因此我就以马里奥 3D 大陆为基础，把马里奥的设计思路总结，做个了小总结。一共总结成为了三个方面：引导 (Guide)－－－&amp;gt; 认知 (Cognition)－－&amp;gt; 突破 (Breakthrough)（GCB 方法），这三个一直在指导玩家，让不同层次玩家能有着不同层次的游戏方法，以及舒适的游戏体验。&lt;/p&gt;
&lt;p&gt;同时，也感谢 Indienova 中一篇文章的帮助，把我上一篇中提到的模糊概念讲的十分透彻，本文也是在这篇文章的启发下写出来的，同时也感谢译者，翻译的相当有水平，鄙人感激不尽。&lt;/p&gt;
&lt;p&gt;相关链接&lt;/p&gt;
&lt;p&gt;Indienova 文章链接：&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9pbmRpZW5vdmEuY29tL2luZGllLWdhbWUtZGV2ZWxvcG1lbnQvaG93LXRvLWRlc2lnbi1sZXZlbHMtd2l0aC10aGUtc3VwZXItbWFyaW8td29ybGQtbWV0aG9kLWluLWNoaW5lc2Uv&#34;&gt;使用 “马里奥方法” 设计游戏关卡 indienova 独立游戏&lt;/span&gt;&lt;br&gt;
所翻译的原文链接：&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9nYW1lZGV2ZWxvcG1lbnQudHV0c3BsdXMuY29tL2FydGljbGVzL2hvdy10by1kZXNpZ24tbGV2ZWxzLXdpdGgtdGhlLXN1cGVyLW1hcmlvLXdvcmxkLW1ldGhvZC0tY21zLTI1MTc3&#34;&gt;How to Design Levels With the “Super Mario World Method”&lt;/span&gt;&lt;br&gt;
 上一篇链接：&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly94ZW5vbGllcy54eXovYXJjaGl2ZXMvMTEzNQ==&#34;&gt;我的一些关卡设计心得&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;我在上文中提到了 GCB 方法了，以下将用马里奥 3D 大陆世界 1 的第一关来说明。&lt;/p&gt;
&lt;h2 id=&#34;合适的引导玩家&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#合适的引导玩家&#34;&gt;#&lt;/a&gt; 合适的引导玩家&lt;/h2&gt;
&lt;p&gt;整个第一关，我将它分为三个部分。&lt;/p&gt;
&lt;p&gt;第一个部分是引导&lt;/p&gt;
&lt;p&gt;这里在马里奥第一个场景就有体现（由于实际机器无法录屏只好这样了）&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/04/%E5%B1%8F%E5%B9%95%E6%88%AA%E5%9B%BE97-1024x576.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;这里设计了一大块空地给玩家自己探索，可以练习跳跃等操作。在这里，玩家可以去尝试在说明书中的各种操作。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://pic1.zhimg.com/0f47b318e2c935a878dfeba4c6c2b1ea_r.jpg?source=1940ef5c&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;说明书的图来自这个知乎回答 ： &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cuemhpaHUuY29tL3F1ZXN0aW9uLzIyNDIzMDkxL2Fuc3dlci8yMTMwNjU0MA==&#34;&gt;《超级马里奥兄弟》为什么可以不用新手引导？ - Leon Lee 的回答 - 知乎 、&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;这样的引导只是玩家的基础，而我这里提到的是后面的地方&lt;/p&gt;
&lt;p&gt;在跳上一个坎后，碰到了一个写着问号的方块。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/04/%E5%B1%8F%E5%B9%95%E6%88%AA%E5%9B%BE99-1024x576.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;这时候，很可能有玩家会跳一下，顶这个方块，这时候方块蹦出一个金币。这时候玩家会知道，带问号的黄色方块有好东西。这样一个引导完成了。&lt;/p&gt;
&lt;p&gt;在这里，就是我所说的引导，即为：&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;一个 引导 是指让玩家了解 游戏机制 的 事件&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;而下面，无不体现着任天堂的引导：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/04/%E5%B1%8F%E5%B9%95%E6%88%AA%E5%9B%BE101-1024x576.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;河道上会飞的金币&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/04/%E5%B1%8F%E5%B9%95%E6%88%AA%E5%9B%BE101-1-1024x576.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;会追着玩家的板栗仔（Goomba）&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/04/%E5%B1%8F%E5%B9%95%E6%88%AA%E5%9B%BE146-1024x576.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;旗杆的金币&lt;/p&gt;
&lt;h2 id=&#34;让引导循序渐进&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#让引导循序渐进&#34;&gt;#&lt;/a&gt; 让引导循序渐进&lt;/h2&gt;
&lt;p&gt;注意，这样的引导并不是一下子全部给你，有些还是要靠你发现的。&lt;/p&gt;
&lt;p&gt;比如下面这个场景：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/04/%E5%B1%8F%E5%B9%95%E6%88%AA%E5%9B%BE133-1024x576.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;图片的左下角有个用尾巴击打会蹦出金币的砖块，这是在引导你，说如果用尾巴连续击打一些特殊砖块，会有奖励。而在接下来，就立马出现了个砖块，这时候你被引导去击打这方块。&lt;/p&gt;
&lt;p&gt;在这时候，出现了意想不到的事情，一个轮盘！击打它还会上升。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/04/%E5%B1%8F%E5%B9%95%E6%88%AA%E5%9B%BE134-1024x576.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;而这样的情况，不属于游戏设计者主动要求你的，是你自己探索出来的，我把它称之为：认知（Cognition），在引导之上，你自己探索出来的新东西。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;一个 认知 是 玩家 在 经过引导 之后 自我探索 出来的 事件&lt;/strong&gt;&lt;/p&gt;
&lt;h2 id=&#34;建立在认知之上的突破&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#建立在认知之上的突破&#34;&gt;#&lt;/a&gt; 建立在认知之上的突破&lt;/h2&gt;
&lt;p&gt;这里，我们把视角转换下，从一个开发者的角度转为一个玩家的角度：我了解了一系列操作，我也知道了一些技巧。这时候，我需要有些挑战性的来试一下。所以，任天堂设计的突破，也就出现了。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;一个 突破 是 建立在玩家 认知 之上 的 有挑战性 的 事件&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;而任天堂设计的，是一个环环相扣的关卡。&lt;/p&gt;
&lt;p&gt;这里拿第一关的过程来说明：&lt;/p&gt;
&lt;p&gt;玩家会在游戏过程中遇到一个结合的敌人，可以使用跳踩或者甩尾来击败敌人&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/04/42943516504719892-1024x576.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;这里玩家碰到新的板栗仔，并没有什么难度&lt;/p&gt;
&lt;p&gt;而在之后的关卡中，玩家会遇到更大的板栗仔，而且还碰到不要掉出去和碰到敌人的尾巴这样的挑战。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/04/32258416504720762-1024x576.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;此时的玩家的心理将是个相对紧张的状态，但是由于有前面的认知，玩家会试着跳下去，踩死那只大板栗仔，这样完成一个 “突破”。而在这期间玩家心理有个舒缓到紧张，再到舒缓的过程，就有了游戏的节奏。&lt;/p&gt;
&lt;h2 id=&#34;节奏的安排&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#节奏的安排&#34;&gt;#&lt;/a&gt; 节奏的安排&lt;/h2&gt;
&lt;p&gt;游戏节奏的设计更像是写文章，所谓 “文似看山不喜平” 这样的道理也可以体现在游戏上。&lt;/p&gt;
&lt;p&gt;这里用世界 1 的 BOSS 战来解释节奏：&lt;/p&gt;
&lt;h3 id=&#34;关卡前期&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#关卡前期&#34;&gt;#&lt;/a&gt; 关卡前期&lt;/h3&gt;
&lt;h4 id=&#34;关卡前期-1&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#关卡前期-1&#34;&gt;#&lt;/a&gt; 关卡前期 - 1&lt;/h4&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/04/Mario_BOSS1-1024x632.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;关卡前期 - 1 相对平缓&lt;/p&gt;
&lt;p&gt;关卡开始，主要的任务是给玩家些许紧张感，这里相对于前面关卡开场的风平浪静，加入了一个会攻击的敌人，塑造 BOSS 战的紧张感，同时，地图也在引导玩家前进。这样的关卡玩家在前面已经遇到，所以这里节奏是比较平缓的。&lt;/p&gt;
&lt;h4 id=&#34;关卡前期-2&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#关卡前期-2&#34;&gt;#&lt;/a&gt; 关卡前期 - 2&lt;/h4&gt;
&lt;p&gt;这里出现了新的设计来激发玩家兴趣，这里由于齿轮的滚动，导致玩家会对位置判断失误，在这里开始，节奏开始加快，同时这里玩家也认识到了齿轮这一个全新的设计。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/04/Mario_BOSS2-1024x618.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;关卡前期 - 2 节奏加快&lt;/p&gt;
&lt;h4 id=&#34;关卡前期-3&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#关卡前期-3&#34;&gt;#&lt;/a&gt; 关卡前期 - 3&lt;/h4&gt;
&lt;p&gt;经历过刚才节奏的变快，任天堂并没有一直增加难度，而是设计了个有些难度的平缓段，所谓的难度就是会复活的敌人给玩家的威胁，这里的难度是在 前期 - 1 的之上的，整体节奏在向上走。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/04/Mario_BOSS3-1024x618.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;关卡前期 - 3&lt;/p&gt;
&lt;h3 id=&#34;关卡中期&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#关卡中期&#34;&gt;#&lt;/a&gt; 关卡中期&lt;/h3&gt;
&lt;h4 id=&#34;关卡中期-1&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#关卡中期-1&#34;&gt;#&lt;/a&gt; 关卡中期 - 1&lt;/h4&gt;
&lt;p&gt;跳上一个上下移动的平台，进入到了关卡中期。这里基本是复刻前面的节奏，不过多赘述。一个略有挑战的平缓段来当个引子。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/04/Mario_BOSS5-1024x617.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;h4 id=&#34;关卡中期-2&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#关卡中期-2&#34;&gt;#&lt;/a&gt; 关卡中期 - 2&lt;/h4&gt;
&lt;p&gt;这出现了新敌人，会向玩家扔东西，这里玩家会本能的躲避，并且利用前面关卡中学到的利用踩或者能力来打败敌人，同时也认识到了新的敌人类型，重新激发了新鲜感。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/04/Mario_BOSS6-1024x617.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;h4 id=&#34;关卡中期-3&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#关卡中期-3&#34;&gt;#&lt;/a&gt; 关卡中期 - 3&lt;/h4&gt;
&lt;p&gt;这里进入了个平缓段，和前期节奏基本一致。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/04/Mario_BOSS7-1-1024x617.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;关卡后期&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#关卡后期&#34;&gt;#&lt;/a&gt; 关卡后期&lt;/h3&gt;
&lt;h4 id=&#34;关卡后期-1&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#关卡后期-1&#34;&gt;#&lt;/a&gt; 关卡后期 - 1&lt;/h4&gt;
&lt;p&gt;这里任天堂设计了金币这样的奖励来鼓励玩家向上探索。，同时也利用地图来引导玩家了解新的敌人。这里因为石板怪给人强烈的压迫感，节奏加快，紧张感也上升到了新的高度。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/04/Mario_BOSS8-1-1024x612.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;后面就出现了代表成就的星星徽章。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/04/Mario_BOSS81-1024x617.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;h4 id=&#34;关卡后期-2&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#关卡后期-2&#34;&gt;#&lt;/a&gt; 关卡后期 - 2&lt;/h4&gt;
&lt;p&gt;这里任天堂在此设计了一个非常简单的过渡（只有一只不死乌龟），来用后面更大的节奏跳跃来凸显 BOSS 战的紧张。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/04/Mario_BOSS9-1-1024x619.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;h4 id=&#34;关卡后期-3&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#关卡后期-3&#34;&gt;#&lt;/a&gt; 关卡后期 - 3&lt;/h4&gt;
&lt;p&gt;这里 boss 出现，节奏迅速加快。这里也分为三个阶段来提升玩家的紧张感的。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;关卡后期 - 3.1&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;由于 BOSS 是吐火球攻击的，所以玩家距离越远，玩家就有更多的反应时间，紧张感就越小。&lt;/p&gt;
&lt;p&gt;此时 boss 里玩家较远，紧张感不是很强。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/04/Mario_BOSS10-1024x613.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;关卡后期 - 3.2&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;这里 BOSS 里玩家的距离开始缩短，玩家的紧张感上升.&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/04/Mario_BOSS102-1024x614.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;关卡后期 - 3.3&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;这里玩家离 BOSS 距离最近，紧张感最强，节奏发展称为整个关卡最快阶段，玩家的紧张感在此时也达到顶峰。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/04/Mario_BOSS11-1024x618.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;关卡末尾&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#关卡末尾&#34;&gt;#&lt;/a&gt; 关卡末尾&lt;/h3&gt;
&lt;p&gt;在此时，作为一个玩家此时是充满成就感的，为了迎合或者说配合这样的成就感，特意设计的最简单的方式：只有跳跃的关卡，同时结束的地方设计的也非常像个领奖台。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/04/Mario_BOSS12-1024x617.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;回看&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#回看&#34;&gt;#&lt;/a&gt; 回看&lt;/h3&gt;
&lt;p&gt;整个分析结束，我们来整体看一下整个游戏的节奏&lt;/p&gt;
&lt;p&gt;最开始的相对平缓，接着紧张，之后平缓紧张，到最后，接着突然上升到顶点之后骤然放慢。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/04/Mario_JIEXZOU-1024x294.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;整个过程，开始的平缓引导，到后面需要寻找时机的 “认知” 关卡，再到最后充满挑战型的 “突破” 设计，整体如同山峦一般的引人入胜的难度曲线，真是佩服任天堂的关卡设计之出色。&lt;/p&gt;
&lt;h2 id=&#34;结语&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#结语&#34;&gt;#&lt;/a&gt; 结语&lt;/h2&gt;
&lt;p&gt;用引导来合理的让游戏者熟悉玩法来转化玩家，利用合理设计培养玩家认知来提升综合体验，用充满挑战性的突破来满足核心玩家的需求，这样的 GCB 方法是我从《马里奥 3D 大陆》这款游戏中学到的。&lt;/p&gt;
&lt;h2 id=&#34;修改记录&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#修改记录&#34;&gt;#&lt;/a&gt; 修改记录&lt;/h2&gt;
&lt;h3 id=&#34;202248&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#202248&#34;&gt;#&lt;/a&gt; &lt;strong&gt;2022.4.8&lt;/strong&gt;&lt;/h3&gt;
&lt;p&gt;将原文中 &amp;quot;引导 (Guide)－－－&amp;gt; 认识 (Know)－－&amp;gt; 突破 (Breakthrough)&amp;quot; 中的 &amp;quot;认识 (Know)“改为&amp;quot; 认知 (Cognition)” ，“认识” 一词的意思为：&lt;strong&gt;指人的头脑对客观世界的反映&lt;/strong&gt; ，这个和我本来想表达的那种探索的心理活动不同，所以改为了有心理活动的认知 (Cognition) 一词。同时也集合了我之前了解到的 “心流”(flow) 的概念。游戏这样有着互动属性的一种娱乐形式，这样一种先天的具有了挑战和回馈的娱乐形式，是很容易进入到 “心流” 中去的。&lt;/p&gt;
&lt;h3 id=&#34;2022420&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2022420&#34;&gt;#&lt;/a&gt; &lt;strong&gt;2022.4.20&lt;/strong&gt;&lt;/h3&gt;
&lt;p&gt;更新完最后的 “突破” 部分，鸽了好久，咕咕咕。。。&lt;/p&gt;
&lt;h3 id=&#34;2022421&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2022421&#34;&gt;#&lt;/a&gt; &lt;strong&gt;2022.4.21&lt;/strong&gt;&lt;/h3&gt;
&lt;p&gt;&lt;strong&gt;重写 “突破” 部分&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;原突破部分&lt;/p&gt;
&lt;p&gt;(1) 将 “这里，我们把视角转换下，从一个开发者的角度转为一个玩家的角度：我知道了一系列操作，我也知道了一些进阶技巧。这时候，光有这些简单的挑战是完全没意思的，我需要更有些挑战性的来试一下。所以，任天堂设计的突破，也就诞生了。” 修改为 “这里，我们把视角转换下，从一个开发者的角度转为一个玩家的角度：我了解了一系列操作，我也知道了一些技巧。这时候，我需要有些挑战性的来试一下。所以，任天堂设计的突破，也就出现了。”&lt;/p&gt;
&lt;p&gt;(2) 将 “突破” 部分的提示&lt;/p&gt;
&lt;p&gt;注意：这里的挑战不止是那种考验操作的挑战，还包括探索的挑战&lt;/p&gt;
&lt;p&gt;删除。&lt;/p&gt;
&lt;p&gt;(3) 删除原来 “突破” 里 “探索的挑战” 和 “操作的挑战” 所有内容&lt;/p&gt;
&lt;p&gt;以下为原内容：&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;探索的挑战&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/04/%E5%B1%8F%E5%B9%95%E6%88%AA%E5%9B%BE121-1024x576.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;这里，玩家右边的树可以爬上去，爬上去会得到一个变身狸猫状态的奖励，这里玩家建立了一个认识：树是可以爬上去的。而挑战在哪里呢，在于让玩家探索的挑战。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/04/%E5%B1%8F%E5%B9%95%E6%88%AA%E5%9B%BE125-1024x576.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;这里玩家爬上树探索会发现有这样的方块&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/04/%E5%B1%8F%E5%B9%95%E6%88%AA%E5%9B%BE127-1024x576.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;通过方块跳上台子会发现水管&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/04/%E5%B1%8F%E5%B9%95%E6%88%AA%E5%9B%BE130-1024x576.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;这里的银色物品是星星徽章，就是给玩家的突破奖励了&lt;/p&gt;
&lt;p&gt;这时候，玩家会产生另一个成就感：就是挑战的成就感。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;操作的挑战&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;这里拿世界一第二关的地牢场景来说明&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/04/%E5%B1%8F%E5%B9%95%E6%88%AA%E5%9B%BE195-1024x576.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;玩家需要得到星星徽章，必须注意移动的平台和吐遮挡视线的墨水。这里就构成了操作的挑战，也构成了一个突破。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;重写 “节奏的安排” 部分&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;原内容如下：&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;节奏的安排&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;Indienova 的这篇文章已经说过足够详尽，这里就不过多赘述了。&lt;/p&gt;
&lt;p&gt;文章链接： &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9pbmRpZW5vdmEuY29tL2luZGllLWdhbWUtZGV2ZWxvcG1lbnQvaG93LXRvLWRlc2lnbi1sZXZlbHMtd2l0aC10aGUtc3VwZXItbWFyaW8td29ybGQtbWV0aG9kLWluLWNoaW5lc2Uv&#34;&gt;使用 “马里奥方法” 设计游戏关卡 indienova 独立游戏&lt;/span&gt;&lt;/p&gt;
&lt;h3 id=&#34;2022422&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2022422&#34;&gt;#&lt;/a&gt; 2022.4.22&lt;/h3&gt;
&lt;p&gt;完成最后 “节奏的安排” 部分&lt;/p&gt;
&lt;h3 id=&#34;202255&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#202255&#34;&gt;#&lt;/a&gt; 2022.5.5&lt;/h3&gt;
&lt;p&gt;1. 修正一些错字，认知部分 “就立马出现了给砖块，” 更正为 “就立马出现了个砖块”，&lt;/p&gt;
&lt;p&gt;突破部分 “这样完成一个突破‘’。” 更正为 “这样完成一个 “突破”。&lt;/p&gt;
&lt;p&gt;2. 将一些概念进行特殊化处理，这样更加适合阅读了&lt;/p&gt;

 &lt;h2 id=&#34;约束&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#约束&#34;&gt;#&lt;/a&gt; 约束&lt;/h2&gt;
&lt;h3 id=&#34;何为约束&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#何为约束&#34;&gt;#&lt;/a&gt; 何为约束？&lt;/h3&gt;
&lt;p&gt;对字段添加限制，称为约束。&lt;/p&gt;
&lt;h3 id=&#34;约束的增加&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#约束的增加&#34;&gt;#&lt;/a&gt; 约束的增加&lt;/h3&gt;
&lt;p&gt;[collapse title=“约束关键字以及定义语句”] 主体部分，由于对于字段取值的各种不同的限定，因此，表中的约束也分为若干种，每种约束的关键字不同。约束的定义语句也不同。[/collapse]&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;constraint 约束名  &lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;创建表的时候，直接为字段定义约束&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;create table 表名(字段 数据类型 [约束定义语句])；&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;创建表后，修改字段定义增加约束&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;alter table 表名 add[constraint + 约束名]+约束的定义语句&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;主键约束primary-key&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#主键约束primary-key&#34;&gt;#&lt;/a&gt; 主键约束 (PRIMARY KEY)&lt;/h3&gt;
&lt;p&gt;确定表中的标识列（主键字段不能为空，必须唯一）&lt;/p&gt;
&lt;p&gt;定义主键约束&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;create table DDD(&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;DDDid char(10) primary key,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;DDDname varchar(10));//创建名为DDD的表。创建时，将DDDid约束为主键&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;create table DDD(&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;DDDid char(10),&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;DDDname varchar(10),&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;primary key(DDDid));//创建表后，约束主键&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;为约束命名&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;create table DDD(&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;DDDid char(10),&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;DDDname varchar(10),&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;primary key(DDDid),&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;constraint pk_id primary key(DDDid))；&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;组合主键&lt;/p&gt;
&lt;p&gt;表中主键字段需要多个字段组合起来充当，来满足主键约束的要求&lt;/p&gt;
&lt;p&gt;特征 ： 每个字段允许有重复值，但是组合在一起不许重复，而组合中每个字段都不可以取空值，&lt;/p&gt;
&lt;p&gt;格式 :&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;[constraint 约束名]primary key[(字段名1，字段名2)];&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;注意：由于组合主键萨河及多个字段因此，组合主键只能定义表级约束，定义在表的最后或者被约束字段完成之后。&lt;/p&gt;
&lt;h3 id=&#34;唯一约束unique&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#唯一约束unique&#34;&gt;#&lt;/a&gt; 唯一约束 (UNIQUE)&lt;/h3&gt;
&lt;p&gt;不可重复，可以有空值。&lt;/p&gt;
&lt;p&gt;格式:&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;--建表时添加约束&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;CREATE TABLE 表名(&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;字段名 int(10) UNIQUE);  --定义唯一约束&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;--建表后添加约束&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ALTER TABLE 表名 ADD CONSTRAINT 唯一约束名 UNIQUE 字段名 ;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;unique index_name [字段名]; --索引命名&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;非空约束not-null&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#非空约束not-null&#34;&gt;#&lt;/a&gt; 非空约束（NOT NULL）&lt;/h3&gt;
&lt;p&gt;不允许空值&lt;/p&gt;
&lt;p&gt;如果省略关键字，默认值为 null&lt;/p&gt;
&lt;p&gt;not null 只能放在字符后面&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;--建表时添加&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Create table Student(&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Name varchar(100) not null )； --定义非空约束&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;--建表后添加&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ALTER TABLE student MODIFY Name varchar(100) NOT NULL ; --MODIFY 添加非空约束&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;检查约束check&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#检查约束check&#34;&gt;#&lt;/a&gt; 检查约束（CHECK）&lt;/h3&gt;
&lt;p&gt;控制特定列中的值的完整性约束&lt;/p&gt;
&lt;p&gt;使用场景：&lt;/p&gt;
&lt;p&gt;订购册数 ：（1-100），出版时间等。&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;--建表时添加约束&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;create table s2(&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;学号 char(10) not null,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;性别 char(10) not null,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;check ( 学号 in ( select 学号 from student)));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;--建表后添加约束&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ALTER TABLE s2 ADD CONSRAINT 检查约束名&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; CHECK ( 学号 in ( select 学号 from student));&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;外键约束foreign-key&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#外键约束foreign-key&#34;&gt;#&lt;/a&gt; 外键约束 (FOREIGN KEY)&lt;/h3&gt;
&lt;p&gt;foreign key 定义在子表中。&lt;/p&gt;
&lt;p&gt;一个表中的某一个字段是参考另一个表中某个字段的取值，被称为外键约束。&lt;/p&gt;
&lt;p&gt;受约束的称为子表，约束子表的表称为父表。&lt;/p&gt;
&lt;p&gt;四个限制&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;子表中的外键字段必须和父表中的参考字段的数据类型一致。&lt;/li&gt;
&lt;li&gt;父表中的参考字段必须被主键约束或者唯一键约束，才能约束子表中的外键约束&lt;/li&gt;
&lt;li&gt;父表中的主键值一旦被子表参照，那么这些值就不能随意修改和删除。&lt;/li&gt;
&lt;li&gt;子表的外键字段的值可以为空值，但是如果有值必须是在父表的参照列的取值范围内&lt;/li&gt;
&lt;/ol&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;--建表时定义&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;CREATE TABLE 表名(&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;字段名  int(10),&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;CONSTRAINT 外键约束名 &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;FOREIGN KEY 字段名 &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;REFERENCES 主表名[主表字段1,主表字段2] ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;--建表后定义&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ALTER TABLE 表名 &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ADD CONSTRAINT 外键约束名 &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;FOREIGN KEY 字段名 REFERENCES 主表名[主表字段1,主表字段2] ;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;默认约束default&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#默认约束default&#34;&gt;#&lt;/a&gt; 默认约束 (DEFAULT)&lt;/h3&gt;
&lt;p&gt;如果该行没有指定数据，那么系统将默认值赋给该列，如果我们不设置默认值，系统默认为 NULL。&lt;/p&gt;
&lt;p&gt;定义默认约束&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;--建表时定义&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;CREATE TABLE 表名(&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;字段名 int(10) default 10);  --10为默认值&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;--建表后定义&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ALTER TABLE 表名 ADD DEFAULT 10 FOR 字段名 ;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

 &lt;h2 id=&#34;面向对象&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#面向对象&#34;&gt;#&lt;/a&gt; 面向对象&lt;/h2&gt;
&lt;h3 id=&#34;类的定义&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#类的定义&#34;&gt;#&lt;/a&gt; 类的定义&lt;/h3&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;/**&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[修饰符]class 类名&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;//成员变量&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;//构造方法&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;//成员方法&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;*/&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;成员变量&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#成员变量&#34;&gt;#&lt;/a&gt; 成员变量&lt;/h3&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;/**&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[修饰符]变量类型 变量名字 [= 默认值] ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;其中&amp;quot;修饰符&amp;quot;和&amp;quot;默认值&amp;quot;不是必须的。&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;修饰符有:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[public  protexted  private]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[static](static只执行一次)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;[final]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;定义在类里面&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;*/&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;int A ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;int B = 10 ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;public int C ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;protected int D ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;private int E ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;static int F ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;final int G ;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;定义成员变量&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#定义成员变量&#34;&gt;#&lt;/a&gt; 定义成员变量&lt;/h3&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class Demo &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    int A = 10; //成员变量 A&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    Demo Demo = new Demo();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public Demo() &amp;#123;  //构造方法Demo&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;Hello,World!&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;构造方法&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#构造方法&#34;&gt;#&lt;/a&gt; 构造方法&lt;/h3&gt;
&lt;p&gt;和类名相同，自动调用&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class Demo &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    Demo Demo = new Demo();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public Demo() &amp;#123;  //构造方法Demo&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;Hello,World!&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public Demo(int R,int E)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;使用两个参数的构造方法&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;成员方法&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#成员方法&#34;&gt;#&lt;/a&gt; 成员方法&lt;/h3&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;/**&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; [修饰符]返回值类型 方法名&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;语句&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; */&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;public int NP(int G)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    return G;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;构造方法重载&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#构造方法重载&#34;&gt;#&lt;/a&gt; 构造方法重载&lt;/h3&gt;
&lt;p&gt;两个方法方法名相同，但是参数列表不同，称为重载&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public Demo(double U)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    System.out.println(&amp;quot;使用构造方法&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;public Demo(int Y)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    System.out.println(&amp;quot;使用构造方法重载&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;调用以上方法&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class PPP &amp;#123;//新建PPP的类&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        AAA N = new AAA(1.2);//将带有成员方法和构造方法的类实例化&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;成员方法&amp;quot; + N.NP(8)); //成员方法调用&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        AAA N1 = new AAA(1);//调用&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        AAA N2 = new AAA(7,4);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class AAA &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public int NP(int G)&amp;#123; //成员方法&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        return G;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public AAA(double U)&amp;#123; //构造方法&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;使用构造方法&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public AAA(int Y)&amp;#123; //构造方法&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;使用构造方法重载&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public AAA(int R,int E)&amp;#123; //构造方法&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;使用两个参数的构造方法&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;输出结果:&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/04/GZFF.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;this-关键字&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#this-关键字&#34;&gt;#&lt;/a&gt; This 关键字&lt;/h3&gt;
&lt;p&gt;在类的方法中引用自身&lt;/p&gt;
&lt;p&gt;Student 类代码&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class Student &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    String name = &amp;quot;&amp;quot;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    int age ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    double Math ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    double Chinese ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    double English ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   public Student(String name,int age,int English,int Math,int Chinese)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;       this.name = name;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;       this.age = age ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;       this.English = English ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;       this.Math = Math ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;       this.Chinese = Chinese ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   public void printStudentInfo()&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;姓名：&amp;quot; + this.name + &amp;quot; 年龄:&amp;quot;+ this.age + &amp;quot; 各科成绩:&amp;quot; + &amp;quot;语文:&amp;quot; + this.Chinese + &amp;quot;数学:&amp;quot; + this.Math + &amp;quot;英语:&amp;quot; + this.English );&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public void printStudentInfo(String E , int A)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;姓名：&amp;quot; + name + &amp;quot; 年龄：&amp;quot;+ age);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;调用 Student 代码&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class TestStudent &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Student Student1 = new Student(&amp;quot;&amp;quot;,0,0,0,0);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Student1.name = &amp;quot;哈吉&amp;quot;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Student1.age = 12;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Student1.English = 123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Student1.Math = 123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Student1.Chinese=123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Student1.printStudentInfo(&amp;quot;123&amp;quot;,123);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Student1.printStudentInfo();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;===================&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Student Student2 = new Student(&amp;quot;张天&amp;quot;,12,92,86,87);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Student2.printStudentInfo();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Student2.printStudentInfo(&amp;quot;张天&amp;quot;,12);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;方法的参数传递&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#方法的参数传递&#34;&gt;#&lt;/a&gt; 方法的参数传递&lt;/h3&gt;
&lt;p&gt;当初参数是基本数据类型的时候，经过方法输出后参数不变，如果是引用数据类型，会改变&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;//引用数据类型当参数&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;public class Demo &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int[] AA = &amp;#123;50,100&amp;#125;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Data(AA);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;AA[0]= &amp;quot; + AA[0] + &amp;quot;, AA[1]= &amp;quot; + AA[1]);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void Data(int[] BB)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int AP = BB[0];&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        BB[0] = BB[1];&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        BB[1] = AP;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;BB[0]= &amp;quot;+ BB[0] + &amp;quot; ,BB[1]= &amp;quot; + BB[1]);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;输出结果:&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/04/AA1.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;//基本数据类型当参数&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;public class Demo &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int a = 100;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int b = 50;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Data(a,b);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;a= &amp;quot; + a + &amp;quot;, b= &amp;quot; + b);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void Data(int x,int y)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int AP = x;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        x = y;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        y = AP;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;x= &amp;quot;+ x + &amp;quot; ,y= &amp;quot; + y);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;输出结果:&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/04/abxy.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;可变长参数&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class GongSi &amp;#123; //输出&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public void BuMen (String A,String...B)&amp;#123;  //String... 为可变长参数，需要遍历输出，String为数据类型&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;部门为 &amp;quot; + A);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        for (int i =0; i &amp;lt;B.length;i++)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            System.out.println(&amp;quot;人员为 &amp;quot; + B[i]);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;public class Demo &amp;#123; // 赋值输出&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        GongSi GongSi = new GongSi();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        GongSi.BuMen(&amp;quot;123不mean&amp;quot;,&amp;quot;123123123人&amp;quot;,&amp;quot;123123啊的时间弄多久哦爱仕达&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

 &lt;h2 id=&#34;排序算法&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#排序算法&#34;&gt;#&lt;/a&gt; 排序算法&lt;/h2&gt;
&lt;h3 id=&#34;冒泡排序&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#冒泡排序&#34;&gt;#&lt;/a&gt; 冒泡排序&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;比较数组中，两个相邻的元素，如果第一个数比第二个数大，我们就交换它的位置&lt;/li&gt;
&lt;li&gt;每一次比较，都会产生一个最大，或者最小的数字&lt;/li&gt;
&lt;li&gt;下一轮则可以减少一次排序&lt;/li&gt;
&lt;li&gt;一次循环直到结束&lt;/li&gt;
&lt;/ol&gt;
&lt;h4 id=&#34;代码实现&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#代码实现&#34;&gt;#&lt;/a&gt; 代码实现&lt;/h4&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public static int[] T(int[] a)&amp;#123;  //名为T的冒泡排序&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    int Y = 0;//临时变量&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    for (int Q = 0;Q&amp;lt;a.length-1;Q++)&amp;#123; //列表多少个元素，循环次数的作用&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        for (int W = 0;W&amp;lt;a.length-1-Q;W++)&amp;#123; //每次循环减少，循环次数&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            if (a[W]&amp;gt;a[W+1])&amp;#123;//比大小&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                Y = a[W] ; //大的值赋给临时变量&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                a[W] = a[W+1] ; //小的值前移&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                a[W+1] = Y ; //大的值赋给后面&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    return a ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;完整代码&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#完整代码&#34;&gt;#&lt;/a&gt; 完整代码&lt;/h4&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class Demo1 &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    int [] a = &amp;#123;1,3,4,2,5,6,9,7&amp;#125; ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    Text(T(a)) ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static int[] T(int[] a)&amp;#123;  //名为T的冒泡排序&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int Y = 0;//临时变量&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        for (int Q = 0;Q&amp;lt;a.length-1;Q++)&amp;#123; //列表多少个元素，循环次数的作用&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            for (int W = 0;W&amp;lt;a.length-1-Q;W++)&amp;#123; //每次循环减少，循环次数&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                if (a[W]&amp;gt;a[W+1])&amp;#123;//比大小&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    Y = a[W] ; //大的值赋给临时变量&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    a[W] = a[W+1] ; //小的值前移&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    a[W+1] = Y ; //大的值赋给后面&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        return a ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void Text (int[] a)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        for (int b = 0 ;b&amp;lt;a.length;b++)&amp;#123;  //遍历数组元素显示&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            System.out.print(a[b] + &amp;quot;\n&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;稀疏数组&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#稀疏数组&#34;&gt;#&lt;/a&gt; 稀疏数组&lt;/h3&gt;
&lt;h4 id=&#34;定义&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#定义&#34;&gt;#&lt;/a&gt; 定义&lt;/h4&gt;
&lt;p&gt;当一个数组中大部分的元素为 0，或为同一个值的数组时，可以使用稀疏数组来保存该数组。&lt;/p&gt;
&lt;h4 id=&#34;代码&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#代码&#34;&gt;#&lt;/a&gt; 代码&lt;/h4&gt;
&lt;p&gt;打印输出二维数组&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;35&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;36&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;37&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;38&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;39&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;40&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;41&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;42&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;43&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;44&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;45&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;46&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class Demo1 &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        /** 创建一个原始的二维数组(11行11列)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;         0:表示没有棋子&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;         1:表示黑子&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;         2:表示白子*/&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int Arrays[][] = new int[11][11];&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Arrays[10][2] = 1;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Arrays[3][3] = 2;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;最初的二维数组为:&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int Value = 0;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        for (int row = 0;row &amp;lt; Arrays.length;row++) &amp;#123;//循环行（遍历）&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            for (int column =0;column &amp;lt; Arrays[row].length;column++) &amp;#123;//循环列（遍历）&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                System.out.printf(&amp;quot;%d\t&amp;quot;, Arrays[row][column]);//遍历数组输出 , %d表示转为十进制数，\t是制表符&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                Value ++ ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            System.out.println();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;=================================&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int[][] Array1 =new  int[Value+1][3];&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int Time = 0 ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        for (int row = 0;row &amp;lt; Arrays.length;row++) &amp;#123;//循环行（遍历）&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            for (int column = 0; column &amp;lt; Arrays[row].length; column++)&amp;#123;//循环列（遍历）&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                if(Arrays[row][column] != 0)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    Array1[Time][0] = row;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    Array1[Time][1]= column;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    Array1[Time][2] = Arrays[row][column];&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    Time ++ ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;稀疏数组&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Array1[3][0] = 11;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Array1[3][1] = 11 ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Array1[3][2] = 2 ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        for (int i = 0;i&amp;lt;Array1[i].length;i++)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            System.out.println(Array1[i][0] + &amp;quot;\t&amp;quot;+ Array1[i][2] + &amp;quot;\t&amp;quot; + Array1[i][2] + &amp;quot;\t&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;输出结果：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/05/Xishushuzu.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;

 &lt;h2 id=&#34;数组&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#数组&#34;&gt;#&lt;/a&gt; 数组&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;数组是相同类型数据的有序集合&lt;/li&gt;
&lt;li&gt;数组描述的是相同类型的若干的数据，按照一定的先后次序排列组合而成&lt;/li&gt;
&lt;li&gt;其中，每个数据称作每个数组元素，每个数组元素可以通过一个下标来访问&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;数组的声明与创建&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#数组的声明与创建&#34;&gt;#&lt;/a&gt; 数组的声明与创建&lt;/h3&gt;
&lt;p&gt;声明数组变量，才能在程序中使用数组&lt;/p&gt;
&lt;p&gt;数组里的元素是按照索引访问的，索引从零开始。&lt;/p&gt;
&lt;h4 id=&#34;声明数组变量&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#声明数组变量&#34;&gt;#&lt;/a&gt; 声明数组变量&lt;/h4&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;/*&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;声明数组&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;dataType[] arrayRefVar;   // 首选的方法&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;或&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;dataType arrayRefVar[];  // 效果相同，但不是首选方法&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;*/&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;/*&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;创建数组并赋值&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;arrayRefVar = new dataType[arraySize];&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;arrayRefVar [] = value ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;*/&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;public class Demo &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int[] int1 ;//声明int数组，名为int1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int1 = new  int [10] ;//创建有10个空间数组&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int1[0] =  10 ;//给数组第一个数赋值10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println (&amp;quot;int1 [0]=&amp;quot; + int1 [0]);//输出&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;输出结果为&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/03/shuzu.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;h4 id=&#34;给数组元素循环赋值&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#给数组元素循环赋值&#34;&gt;#&lt;/a&gt; 给数组元素循环赋值&lt;/h4&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class Demo &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int[] int1 ;//声明int数组，名为int1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int1 = new  int [10] ;//创建有10个空间数组&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        for (int i = 0 ;i &amp;lt;int1.length;i ++)&amp;#123; /*定义整数i,arrays.length获取数组长度*/&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            int1 [i] = i ; //将i循环赋值给数组对应的元素&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            System.out.println ( int1 [i]);//输出各个元素&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;初始化以及内存分析&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#初始化以及内存分析&#34;&gt;#&lt;/a&gt; 初始化以及内存分析&lt;/h3&gt;
&lt;h4 id=&#34;内存分析&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#内存分析&#34;&gt;#&lt;/a&gt; 内存分析&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;堆&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;存放 New 的对象和数组&lt;/p&gt;
&lt;p&gt;所有线程共享，不会存放别的对象引用&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;栈&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;存放基本变量类型（会包含那个基本类型的具体数值）&lt;/p&gt;
&lt;p&gt;引用对象的变量（会保存这个引用在堆里面的具体地址）&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;方法区&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;可以被所有线程共享&lt;/p&gt;
&lt;p&gt;包含了所有 class 和 static 变量&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/03/%E5%A0%86%E6%A0%88%E6%96%B9%E6%B3%95%E5%8C%BA.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;h4 id=&#34;三种初始化&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#三种初始化&#34;&gt;#&lt;/a&gt; 三种初始化&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;静态初始化&lt;/li&gt;
&lt;/ul&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;int [] a = &amp;#123;1,2,3&amp;#125; ;  //创建 + 赋值  (静态初始化)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Man [] mans = &amp;#123;new Man(1,1),new Man(2,2)&amp;#125; ;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;ul&gt;
&lt;li&gt;动态初始化&lt;/li&gt;
&lt;/ul&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;int [] a = new int[2] ; //包含默认初始化 (动态初始化,默认值为0)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;a [0] = 1 ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;a [1] = 2 ;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;ul&gt;
&lt;li&gt;数组的默认初始化&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;数组是引用类型，它的元素相当于实例变量，一旦定义将被默认初始化，默认值为 0.&lt;/p&gt;
&lt;h3 id=&#34;数组的使用&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#数组的使用&#34;&gt;#&lt;/a&gt; 数组的使用&lt;/h3&gt;
&lt;h4 id=&#34;基础使用&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#基础使用&#34;&gt;#&lt;/a&gt; 基础使用&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;遍历数组中所有元素&lt;/li&gt;
&lt;/ul&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class Demo &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int[] a = &amp;#123;1,2,3,4,5&amp;#125; ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        for (int b = 0 ;b&amp;lt;a.length;b++)&amp;#123;  //遍历数组元素&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            System.out.println(a[b]);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;ul&gt;
&lt;li&gt;所有元素的和&lt;/li&gt;
&lt;/ul&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class Demo &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int d = 0 ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int[] a = &amp;#123;1,2,3,4,5&amp;#125; ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        for (int c = 0 ;c &amp;lt;a.length; c++)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            d = d + a[c] ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;所有元素和 =&amp;quot; + d);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;ul&gt;
&lt;li&gt;数组中元素最大值&lt;/li&gt;
&lt;/ul&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class Demo &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int[] a = &amp;#123;1,2,3,4,5&amp;#125; ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int Max = a[0] ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        for (int e = 0 ; e&amp;lt;a.length ; e++)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            if (Max &amp;lt; a[e])&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    Max = a[e] ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;Max =&amp;quot; + Max);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;进阶使用&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#进阶使用&#34;&gt;#&lt;/a&gt; 进阶使用&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;For - Each 循环&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;JDK1.5 以上出现的功能，相当于 jAVA 自己自带循环&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class Demo &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int[] a = &amp;#123;1,2,3,4,5&amp;#125; ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        for (int b : a )&amp;#123;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;//for - each遍历数组&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            System.out.println(b);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;ul&gt;
&lt;li&gt;输出数组的元素&lt;/li&gt;
&lt;/ul&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class Demo &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int[] a = &amp;#123;1,2,3,4,5&amp;#125;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Text(a) ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void Text (int[] a)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        for (int b = 0 ;b&amp;lt;a.length;b++)&amp;#123;  //遍历数组元素&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            System.out.print(a[b] + &amp;quot;\n&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;ul&gt;
&lt;li&gt;反转数组&lt;/li&gt;
&lt;/ul&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class Demo &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int[] a = &amp;#123;1,2,3,4,5&amp;#125;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;       int[] II =  TText(a) ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;       Text(II);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void Text (int[] a)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        for (int b = 0 ;b&amp;lt;a.length;b++)&amp;#123;  //遍历数组元素&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            System.out.print(a[b] + &amp;quot;\n&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static int[] TText (int[] a) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int[] G = new int[a.length] ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        for (int Y = 0,U = a.length - 1;Y&amp;lt;a.length;Y++,U--)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            G[U] = a[Y] ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        return  G;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;二维数组&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#二维数组&#34;&gt;#&lt;/a&gt; 二维数组&lt;/h3&gt;
&lt;p&gt;每个元素都是一维数组的数组&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;int[] [] a = new int [2] [5] ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;int [] [] a = &amp;#123;&amp;#123;1,2,3,4,5&amp;#125;,&amp;#123;6,7,8,9,0&amp;#125;&amp;#125; ;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;遍历二维数组&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class Demo &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int[] [] a = &amp;#123;&amp;#123;1,2&amp;#125;,&amp;#123;3,4&amp;#125;,&amp;#123;5,6&amp;#125;&amp;#125;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        for (int i = 0;i&amp;lt;a.length;i++)&amp;#123; //&amp;#123;1,2&amp;#125;&amp;#123;3,4&amp;#125;&amp;#123;5,6&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            for (int t =0;t&amp;lt;a[i].length;t++)&amp;#123; //1,2,3,4,5,6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                System.out.println(a[i][t]);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

 &lt;h2 id=&#34;方法&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#方法&#34;&gt;#&lt;/a&gt; 方法&lt;/h2&gt;
&lt;h3 id=&#34;何为方法&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#何为方法&#34;&gt;#&lt;/a&gt; 何为方法&lt;/h3&gt;
&lt;p&gt;JAVA 方法是语句的结合，组合在一起来实现某种功能。（可以理解为 Python 的函数）&lt;/p&gt;
&lt;p&gt;本质是功能块，是实现功能的语句块的有序集合&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;方法包含在类和对象中&lt;/li&gt;
&lt;li&gt;方法在程序中被创建，在其他地方被调用&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;在 JAVA 中，方法不能独立存在（必须在类里面建立方法）&lt;/p&gt;
&lt;p&gt;方法定义的原则：&lt;/p&gt;
&lt;p&gt;保持方法原子性 (一个方法实现一个功能)&lt;/p&gt;
&lt;h3 id=&#34;方法的定义和调用&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#方法的定义和调用&#34;&gt;#&lt;/a&gt; 方法的定义和调用&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;** 修饰符：** 修饰符，这是可选的，告诉编译器如何调用该方法。定义了该方法的访问类型。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;返回值类型 ：&lt;strong&gt;方法可能会返回值。returnValueType 是方法返回值的数据类型。有些方法执行所需的操作，但没有返回值。在这种情况下，returnValueType 是关键字&lt;/strong&gt; void&lt;/strong&gt;。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;** 方法名：** 是方法的实际名称。方法名和参数表共同构成方法签名。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;** 参数类型：** 参数像是一个占位符。当方法被调用时，传递值给参数。这个值被称为实参或变量。参数列表是指方法的参数类型、顺序和参数的个数。参数是可选的，方法可以不包含任何参数。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;** 方法体：** 方法体包含具体的语句，定义该方法的功能。&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;例 1&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;/**&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;修饰符 返回值类型 方法名(参数类型 参数名)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    ...&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    方法体&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    ...&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    return 返回值;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;*/&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;public class Demo &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;  //main&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;       int  add =  add (1,  2) ;  //给方法的参数赋值&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(add);  //调用方法使用&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static int add (int a, int b)&amp;#123; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; /*&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;修饰符public static&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;返回类型 int&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;方法名 add &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;数据类型是 int&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;数据名是 a , b&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;*/&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int c = a + b ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        return c ; //返回c 值&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;例 2&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class Demo &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;       int  add =  add (1,  2) ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println( &amp;quot;add方法: &amp;quot; + add);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        N(0);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static int add (int a, int b)&amp;#123;  //整数加法方法&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int c = a + b ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        return c ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static int N (int a)&amp;#123;  //循环输出数字方法，这里的a是形参&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    for (int  b = 0 ; b &amp;lt;= 5 ; b++)&amp;#123; // 这里的b为实参&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(b);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        a = b ; //将实参的值赋给形参&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    return a ;  //返回a值&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;方法调用&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#方法调用&#34;&gt;#&lt;/a&gt; 方法调用&lt;/h4&gt;
&lt;p&gt;对象名。方法名 (实参列表)&lt;/p&gt;
&lt;p&gt;如果返回是个值，方法调用一般是一个值。&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;int larger = max(30, 40);&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;如果是 viod，返回值是个语句&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;System.out.println(&amp;quot;Hello,World！&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;例如下&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;35&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class Demo &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;       int  add =  add (1,  2) ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println( &amp;quot;add方法: &amp;quot; + add);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println( &amp;quot;N方法: &amp;quot; + N(0));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Text( 2) ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;//      Text() ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static int add (int a, int b)&amp;#123;  ///add方法，返回值int&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int c = a + b ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        return c ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static int N (int a)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    for (int  b = 0 ; b &amp;lt;= 2 ; b++)&amp;#123;  //N方法，返回值int&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        a = b ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    return a ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void Text(int a )&amp;#123; //Text方法,返回值void，不用加return&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        if (a == 2)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            System.out.println(&amp;quot;Text:&amp;quot; + a);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;//  public static void Text()&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;//          System.out.println(&amp;quot;Text&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;//  &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;方法的重载&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#方法的重载&#34;&gt;#&lt;/a&gt; 方法的重载&lt;/h3&gt;
&lt;p&gt;在一个类中方法名相同，但参数不一致的方法&lt;/p&gt;
&lt;p&gt;重载规则&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;方法名相同&lt;/li&gt;
&lt;li&gt;方法的参数类型，参数个不一样&lt;/li&gt;
&lt;li&gt;方法的返回类型可以不相同&lt;/li&gt;
&lt;li&gt;方法的修饰符可以不相同&lt;/li&gt;
&lt;li&gt;main 方法也可以被重载&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;实例&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class Demo &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        double a = N(1) ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int b = N(2) ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(a);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(b);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    //int&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static int N (int a)&amp;#123;  //方法N,返回值 int&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    return a ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    //double&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static double N (double c)&amp;#123;  //方法N,返回值 double &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        return c ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;可变参数&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#可变参数&#34;&gt;#&lt;/a&gt; 可变参数&lt;/h3&gt;
&lt;p&gt;可以接受多个值的形参&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;在方法声明中，指定参数类型要加省略号 (…)&lt;/li&gt;
&lt;li&gt;可变参数只能作为函数的最后一个参数，但其前面可以有也可以没有任何其他参数&lt;/li&gt;
&lt;/ul&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class Demo1 &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Demo1 Demo1 = new Demo1() ; //定义一个demo1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Demo1.Text(1,2,3);  //调用Text方法&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void Text (int ...i)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(i[0]);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(i[1]);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(i[2]);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;递归&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#递归&#34;&gt;#&lt;/a&gt; 递归&lt;/h3&gt;
&lt;p&gt;方法 A 调用方法 A, 自己调用自己&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class Demo1 &amp;#123;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    int b = 0 ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Text(1,0) ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static int Text (int i ,int b )&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        if (b &amp;lt; 100)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            System.out.println(i);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            b ++ ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        return Text(i,b) ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;运行结果如下&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/03/DG-1024x327.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;对象之间相互引用，最终会导致栈溢出&lt;/p&gt;
&lt;p&gt;所以就需要加入边界条件了。&lt;/p&gt;
&lt;p&gt;递归结构包括两个部分：&lt;/p&gt;
&lt;p&gt;递归头：什么时候不调用自身方法，没有递归头，会陷入死循环&lt;/p&gt;
&lt;p&gt;递归体：什么时候需要调用自身方法&lt;/p&gt;
&lt;p&gt;所以之前的代码是没有递归头，有递归体。&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class Demo &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;//            Text(0) ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            Text(9999);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static int Text (int b )&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        if (b &amp;lt;= 10)&amp;#123; //递归体&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            System.out.println(b);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            return 10 ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;else &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            return Text(b-1) ;//递归头&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;修饰符-static&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#修饰符-static&#34;&gt;#&lt;/a&gt; 修饰符 Static&lt;/h3&gt;
&lt;h4 id=&#34;static-修饰的变量&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#static-修饰的变量&#34;&gt;#&lt;/a&gt; static 修饰的变量&lt;/h4&gt;
&lt;p&gt;没加 static&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class MI&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    int P = 10;  //普通变量 P&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public void BB ()&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(P);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;调用输出&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class iiuiu &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    MI M1 = new MI();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    M1.P = 100; //给实例 M1的变量 P 赋值&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    M1.BB();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    MI M2 = new MI();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    M2.BB();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;输出的结果：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/04/NO-static.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;加入 static （在同一个类里面创建的所有对象共享一个值）&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class MI&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    static int P = 10; //静态变量 P&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public void BB ()&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(P);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;调用输出&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class iiuiu &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    MI M1 = new MI();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    M1.P = 100;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    M1.BB();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    MI M2 = new MI();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    M2.BB();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;输出结果:&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/04/static.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;h4 id=&#34;static-修饰的方法&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#static-修饰的方法&#34;&gt;#&lt;/a&gt; static 修饰的方法&lt;/h4&gt;
&lt;p&gt;用 static 修饰的方法，不属于某一个对象，属于某一个类。&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class House &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    static int A ; //静态变量A&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void DDD()&amp;#123; //静态方法DDD&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        A = 10;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;在静态方法中只能使用静态变量，而普通方法中可使用普通变量和静态变量&lt;/p&gt;

 &lt;h2 id=&#34;流程控制语句&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#流程控制语句&#34;&gt;#&lt;/a&gt; 流程控制语句&lt;/h2&gt;
&lt;h3 id=&#34;顺序结构&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#顺序结构&#34;&gt;#&lt;/a&gt; 顺序结构&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;java 的基本结构就是顺序结构，除非特别指明，否则就按照顺序一句一句执行&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;顺序结构是最简单的算法结构&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;语句与语句之间，框与框之间是按照从上到下的顺序进行的，它是由若干个依次执行的处理步骤组成的，它是任何一个算法都离不开的一种基本算法结构。&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class Demo &amp;#123;  //创建demo类&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args)&amp;#123;  //main方法&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;1&amp;quot;);  //顺序结构将从上往下依次进行&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;2&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;3&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;4&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;5&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;分支语句&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#分支语句&#34;&gt;#&lt;/a&gt; 分支语句&lt;/h3&gt;
&lt;h4 id=&#34;if语句&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#if语句&#34;&gt;#&lt;/a&gt; if 语句&lt;/h4&gt;
&lt;p&gt;一个 if 语句包含一个布尔表达式和一条或多条语句。&lt;/p&gt;
&lt;h5 id=&#34;单if-语句&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#单if-语句&#34;&gt;#&lt;/a&gt; 单 if 语句&lt;/h5&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;/**&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;if (logic expression)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;statments&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;*/&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;public class Demo &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int a = 10 ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        if (a &amp;gt; 1)  &amp;#123;  //单选择if&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            System.out.println(&amp;quot;a &amp;gt; 1 &amp;quot;) ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;if-else语句&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#if-else语句&#34;&gt;#&lt;/a&gt; if - else 语句&lt;/h5&gt;
&lt;p&gt;if 和 else 之间不能有任何其他语句 (else if 这样的选择语句除外)&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;/**&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;if (logic expression)&amp;#123;  // logic expression为布尔类型&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;statments&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;else&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;statments&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;*/&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;public class Demo &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;int a = 10 ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;int b = 5 ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;boolean c = true ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;boolean d = false ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;if (a &amp;lt; b) &amp;#123;  //if 语句分支&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;System.out.print(c);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;else &amp;#123; // else 语句分支&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;System.out.println(d);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;if-else-if-else-语句&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#if-else-if-else-语句&#34;&gt;#&lt;/a&gt; if - else if - else 语句&lt;/h5&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;35&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;36&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;/**&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;if (logic expression)&amp;#123;  // logic expression为布尔类型&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;statments&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;else if (logic expression)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;statments&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;else&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;statments&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;*/&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;public class Demo &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;int a = 10 ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;int b = 5 ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;int c = 10 ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;boolean d = true ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;boolean e = false ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;if (a == b) &amp;#123;  // if分支&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;System.out.print(d);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;else if (a == c ) &amp;#123; // else if 分支&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;System.out.println(&amp;quot;a == 10&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;else &amp;#123;  // else 分支&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;System.out.println(e);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;嵌套if语句&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#嵌套if语句&#34;&gt;#&lt;/a&gt; 嵌套 if 语句&lt;/h5&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;/**&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;if (logic expression)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    if (logic expression)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        statments&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;*/&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;public class Demo &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int a = 9 ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        if (a == 9)&amp;#123; // if语句A&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            if (a != 10)&amp;#123;  // if语句B`&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                System.out.println(&amp;quot;Ture&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;switch语句&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#switch语句&#34;&gt;#&lt;/a&gt; switch 语句&lt;/h4&gt;
&lt;p&gt;switch case 语句判断一个变量与一系列值中某个值是否相等，每个值称为一个分支。&lt;/p&gt;
&lt;p&gt;switch 语句中的变量类型可以是： byte、short、int 或者 char。 switch 支持字符串 String 类型了，同时 case 标签必须为字符串常量或字面量。&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;35&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;36&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;37&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;38&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;39&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;40&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;41&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;42&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;43&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;/**&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;switch (expression)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    case value1 :&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    statments&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    break;//用于控制单个选项输出,否则就会输出剩下的语句&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    case value2 :&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    statments&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    break;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   default:&amp;#123;  //前面case都没有执行的话运行&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   statments&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;*/&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;public class Demo &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int a = 9 ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        switch (a)&amp;#123;  //switch语句&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            case 8 :  //case a&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                System.out.println(&amp;quot;a = 8&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                break;//用于控制单个选项输出&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            case 9 :  //case b&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                System.out.println(&amp;quot;a = 9&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                break;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            default :&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                System.out.println(&amp;quot;a = default&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;循环语句&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#循环语句&#34;&gt;#&lt;/a&gt; 循环语句&lt;/h3&gt;
&lt;h4 id=&#34;while循环语句&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#while循环语句&#34;&gt;#&lt;/a&gt; while 循环语句&lt;/h4&gt;
&lt;p&gt;while 循环特点：先判断是否满足循环条件，然后进入循环&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;/**&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;while (条件) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;//语句&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;*/&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;public class Demo &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int a = 0 ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;         while (a &amp;lt; 10) &amp;#123;  //while循环，判断变量a 小于零，执行循环&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             a++;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;             System.out.println(a);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;         &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;while循环练习&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#while循环练习&#34;&gt;#&lt;/a&gt; while 循环练习&lt;/h5&gt;
&lt;p&gt;100 以内的奇数和以及偶数和&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class Demo1 &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int x = 0 ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int x1 = 0 ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int y1 = 0 ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        while (x&amp;lt;100)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            if (x % 2 == 0) &amp;#123; //偶数&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                x1 = x1 + x ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            else &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                y1 = y1 + x ; //奇数&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            x++ ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;偶数和&amp;quot; + x1);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;奇数和&amp;quot; + y1);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;do-while循环语句&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#do-while循环语句&#34;&gt;#&lt;/a&gt; do - while 循环语句&lt;/h4&gt;
&lt;p&gt;do - while 循环特点 ：至少循环一次，先执行后判断。先 do 再 while&lt;/p&gt;
&lt;p&gt;至少循环一次是 do - while 语句和 while 语句主要的差别&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;/**&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; do&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; //代码&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &amp;#125;while(不布尔表达式);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; */&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;public class Demo &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int a = 0 ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int b = 0 ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        do&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            ++a ;  //是do - while语句，a将输出10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;while (a&amp;lt;10);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(a);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        while(a&amp;lt;0); //while语句，直接跳出循环，b为0&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(b);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;do-while-循环练习&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#do-while-循环练习&#34;&gt;#&lt;/a&gt; do-while 循环练习&lt;/h5&gt;
&lt;p&gt;100 以内的奇数和以及偶数和&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class Demo1 &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int x = 0;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int x1 = 0;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int y1 = 0;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        do &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            if (x % 2 == 0) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                x1 = x1 + x;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            else &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                y1 = y1 + x;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            x++;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;while (x &amp;lt; 100) ; //)~100&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            System.out.println(&amp;quot;偶数和&amp;quot; + x1);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            System.out.println(&amp;quot;奇数和&amp;quot; + y1);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;for循环语句&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#for循环语句&#34;&gt;#&lt;/a&gt; for 循环语句&lt;/h4&gt;
&lt;p&gt;格式&lt;/p&gt;
&lt;p&gt;for (初始化，布尔表达式，迭代){&lt;/p&gt;
&lt;p&gt;代码语句&lt;/p&gt;
&lt;p&gt;}&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;/**&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;for (初始化，布尔表达式,迭代)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;//代码语句&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;*/&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;public class Demo &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        for ( int a = 0 ; a&amp;lt;10 ; a++)&amp;#123;  //for (初始化,布尔表达式,迭代)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            System.out.println(a);  //输出a&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;多变量&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class Demo1 &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    for(int a=0,b=0,c=0;a&amp;lt;10 &amp;amp;&amp;amp; b&amp;lt;10 &amp;amp;&amp;amp; c&amp;lt;10;a++,b++,c++) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    System.out.println(a) ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    System.out.println(b) ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    System.out.println(c) ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;for循环练习&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#for循环练习&#34;&gt;#&lt;/a&gt; for 循环练习&lt;/h5&gt;
&lt;p&gt;100 以内的奇数和以及偶数和&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class Demo1 &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int x1 = 0 ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int y1 = 0 ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        for (int x = 0;x &amp;lt; 100; x++)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            if (x % 2 == 0)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                x1 = x1 + x ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        for (int y = 0 ;y &amp;lt; 100 ;y++)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            if (y % 2 == 1)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                y1 = y1 + y ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;偶数和&amp;quot; + x1);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;奇数和&amp;quot; + y1);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;嵌套 for 循环打印九九乘法表&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class TTT &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            for (int a = 1;a &amp;lt; 10;a++)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                for (int b = 1; b &amp;lt;= a;b++)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                    System.out.print(b + &amp;quot;X&amp;quot; + a + &amp;quot;=&amp;quot; + a*b + &amp;quot;\t&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                System.out.println();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;增强for循环&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#增强for循环&#34;&gt;#&lt;/a&gt; 增强 for 循环&lt;/h5&gt;
&lt;p&gt;格式&lt;/p&gt;
&lt;p&gt;for (声明语句：表达式){&lt;/p&gt;
&lt;p&gt;// 语句&lt;/p&gt;
&lt;p&gt;}&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class Demo1 &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int [] num = &amp;#123;1,2,3,4,5,6,7,8,9,0&amp;#125; ;  //定义数组&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        for ( int x : num )&amp;#123;  //for (声明语句:表达式)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            System.out.println(x);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;break-语句&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#break-语句&#34;&gt;#&lt;/a&gt; break 语句&lt;/h3&gt;
&lt;p&gt;用来终止循环&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class Demo1 &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        for (int x = 0 ;x &amp;lt;=100 ;x++)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            System.out.println(x);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            if (x==10)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                break;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;输出结果:&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/03/break.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;break&lt;/p&gt;
&lt;h3 id=&#34;continue-语句&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#continue-语句&#34;&gt;#&lt;/a&gt; continue 语句&lt;/h3&gt;
&lt;p&gt;终止循环，跳到下一个循环&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class Demo1 &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        for (int x = 0 ;x &amp;lt;=11 ;x++)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            if (x %10 == 0)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                System.out.println(&amp;quot;ZZZ&amp;quot;);//x被10整除的时候输出,并且跳出if。进入循环&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                continue;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            System.out.println(x);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;输出结果:&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/03/continue-1024x364.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;continue&lt;/p&gt;

 &lt;h2 id=&#34;用户交互-scanner&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#用户交互-scanner&#34;&gt;#&lt;/a&gt; 用户交互 Scanner&lt;/h2&gt;
&lt;p&gt;java.util.Scanner 是 Java5 的新特征，我们可以通过 Scanner 类来获取用户的输入。&lt;/p&gt;
&lt;h3 id=&#34;基本语法&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#基本语法&#34;&gt;#&lt;/a&gt; 基本语法&lt;/h3&gt;
&lt;p&gt;首先用 import 来引用 Scanner 类库 (内裤)。&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;import java.util.Scanner ; //引用Scanner类库&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;通过 Scanner 类的 next () 与 nextLine () 方法获取输入的字符串，&lt;/p&gt;
&lt;p&gt;在读取前我们一般需要使用 hasNext 与 hasNextLine 判断是否还有输入的数据。&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;Scanner s = new Scanner(System.in);  //Scanner 基本语法&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;使用例&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#使用例&#34;&gt;#&lt;/a&gt; 使用例&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;输入什么，就输出什么.&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;(使用 scan.hasNext () 和 scan.next () 分别执行 检测和接受输入 )&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;import java.util.Scanner ; //引用Scanner类库&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;public class Demo1 &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Scanner scan = new Scanner(System.in);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        //创建Scanner来检测用户输入&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;请输入&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        if (scan.hasNext())&amp;#123;  //scan.hasNext（）判断是否输入&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            String input =  scan.next() ;  //用scan.next()来获取输入的内容&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            System.out.println(&amp;quot;输入的是&amp;quot; + input);  //输出&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        //Scanner属于IO流，不用的时候应该关掉,否则会一直占用资源&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        scan.close(); //停止运行&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;ul&gt;
&lt;li&gt;输入什么，就输出什么.&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;(使用 scan.hasNextLine () 和 scan.nextLine () 分别执行 检测和接受输入 )&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;import java.util.Scanner ; //引用Scanner类库&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;public class Demo1 &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Scanner scan = new Scanner(System.in);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        //创建Scanner来检测用户输入&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                System.out.println(&amp;quot;请输入&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        if (scan.hasNextLine())&amp;#123;  //scan,hasNextLine（）判断是否输入&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            String input =  scan.nextLine() ;  //用scan.nextLine()来获取输入的内容&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            System.out.println(&amp;quot;输入的是&amp;quot; + input);  //输出&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        //Scanner属于IO流，不用的时候应该关掉,否则会一直占用资源&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        scan.close(); //停止运行&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;next-与-nextline-的区别&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#next-与-nextline-的区别&#34;&gt;#&lt;/a&gt; next () 与 nextLine () 的区别&lt;/h3&gt;
&lt;p&gt;next() :&lt;/p&gt;
&lt;p&gt;一定检测到有效字符后才能结束输入&lt;/p&gt;
&lt;p&gt;如果输入的有效字符之间由空白，如 Hello World，next () 方法会自动去掉&lt;/p&gt;
&lt;p&gt;next () 以空白作为结束符或分割符&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;next () 不接受带有空格的字符串&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;nextLine() :&lt;/p&gt;
&lt;p&gt;以 Enter 为结束符，nextLine () 方法返回的是输入回车之前的所有字符&lt;/p&gt;
&lt;h3 id=&#34;scanner进阶&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#scanner进阶&#34;&gt;#&lt;/a&gt; Scanner 进阶&lt;/h3&gt;
&lt;p&gt;输入一组数，计算平均值&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class Demo1 &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        Scanner scan = new Scanner(System.in);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        //创建Scanner来检测用户输入&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        //和&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        double All = 0 ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        //输入的数字数量&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int sum = 0 ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        //输入的数字&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        double a = 0 ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;输入&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    while ( scan.hasNextDouble() )&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        a = scan.nextDouble() ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        sum++ ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        All = All + a ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;已经输入了&amp;quot; + sum +&amp;quot;个数字,当前结果为&amp;quot; + All );&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;一共输入了&amp;quot; + sum +&amp;quot;个数字&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;平均值为&amp;quot; + All/sum);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

 &lt;p&gt;&lt;strong&gt;这篇文章并不是专业的，只是我自己总结体会，有错误之处，欢迎评论区指出，感激不尽。&lt;/strong&gt;&lt;/p&gt;
&lt;h3 id=&#34;如何让玩家知道游戏的基本机制&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#如何让玩家知道游戏的基本机制&#34;&gt;#&lt;/a&gt; 如何让玩家知道游戏的基本机制&lt;/h3&gt;
&lt;p&gt;优秀的设计往往第一时间让玩家知道游戏的玩法，如果玩家长时间不知道玩法，就会导致失去兴趣。&lt;/p&gt;
&lt;p&gt;拿小岛秀夫的合金装备为例，主要玩法是潜行等多样的玩法，如何体现这个玩法呢？&lt;/p&gt;
&lt;p&gt;其实在序章给出了答案：在序章的中间部分，会出现一个完全交给玩家的逃离任务，有两个路线可走（此时玩家手上有枪支），一为直接走下走廊，被敌人发现，然后玩家反击，跑向门口的 “突突突” 玩法，这里成为 “突击流”; 另一个是转头会找到一个被坍塌的楼梯组成的矮墙，同时末端有个洞，提示玩家趴下，然后慢慢爬到门口，这里成为 “潜入流”。这两个设计直接体现了玩法，让玩家对游戏有了大概的认知。这样玩家在游玩的时候，就不会感觉难度跨越太大。&lt;/p&gt;
&lt;p&gt;因此，让玩家第一时间知道游戏的基本机制，才是最重要的一点。&lt;/p&gt;
&lt;p&gt;那么转到游戏，将要如何设计呢。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/03/%E7%AC%AC%E4%B8%80%E5%85%B3-1024x612.webp&#34; alt=&#34;第一关&#34;&gt;&lt;/p&gt;
&lt;p&gt;第一关&lt;/p&gt;
&lt;p&gt;拿我设计的第一关为例，乍一看，感觉无非是墙，灯和地面，但是我们把它的主体提出来看看。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/03/%E7%AC%AC%E4%B8%80%E5%85%B3-%E8%AE%BE%E8%AE%A1-1024x612.webp&#34; alt=&#34;第一关设计&#34;&gt;&lt;/p&gt;
&lt;p&gt;第一关设计&lt;/p&gt;
&lt;p&gt;我设计的也是一款潜入游戏，那么如何让玩家了解到游戏的机制呢？&lt;/p&gt;
&lt;p&gt;玩家向左走不通，会向右走，碰到了障碍，这时候，玩家就会通过跳跃来越过障碍，这样玩家就学会了最基础的操作：移动，跳跃。&lt;/p&gt;
&lt;p&gt;那么如何让引入游戏机制呢？这时侯，玩家就会发现一个敌人，敌人在不断巡逻。这时候玩家在想，这个既然是敌人，我们就要杀死他。&lt;/p&gt;
&lt;p&gt;在这样的心理下，玩家就会思索，如何杀掉敌人，这里我引入了射击。这样玩家就会冲过去杀掉敌人。这时候，潜入的机制就开始发挥作用了。&lt;/p&gt;
&lt;p&gt;敌人会给玩家造成大量的伤害，这样玩家意识到，正面进攻（“突击流”）是极为困难的。这时，玩家就会思考其他的过关方法，头顶的平台就起了作用。这时候玩家就会意识到，自己要跳上平台来躲避敌人的视线，这样，玩家就了解了游戏的机制以及操作的方法。&lt;/p&gt;
&lt;h3 id=&#34;让玩家了解新机制&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#让玩家了解新机制&#34;&gt;#&lt;/a&gt; 让玩家了解新机制&lt;/h3&gt;
&lt;p&gt;一个游戏如果自始至终都是单一机制会非常无聊，所以就要引入新机制来丰富游戏内容。&lt;/p&gt;
&lt;p&gt;这里我们以 3ds 上的 “马里奥 3d 大陆” 为例，如何引入新机制。&lt;/p&gt;
&lt;p&gt;马里奥中有个形态是 “狸猫 “，此时的马里奥会得到一个杀死一定范围内的敌人的效果，而在此游戏里，有一个一样的敌人，也是有一样的能力。玩家碰到这样的怪物就会死亡，这是非常有特点的从敌人上了解游戏机制的设计。&lt;/p&gt;
&lt;p&gt;放到游戏里面，可以这样来设计。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/03/%E7%AC%AC%E4%BA%8C%E5%85%B3%E8%AE%BE%E8%AE%A1-1024x613.webp&#34; alt=&#34;第二关设计1&#34;&gt;&lt;/p&gt;
&lt;p&gt;第二关设计 1&lt;/p&gt;
&lt;p&gt;这里的横杆是可以跳跃上去的，那么如何让玩家了解这个新机制呢？&lt;/p&gt;
&lt;p&gt;在这里，我设计了个 boss，可以发射上中下三个方向子弹来攻击。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/03/%E7%AC%AC%E4%BA%8C%E5%85%B3%E8%AE%BE%E8%AE%A12-1024x613.webp&#34; alt=&#34;第二关设计2&#34;&gt;&lt;/p&gt;
&lt;p&gt;第二关设计 2&lt;/p&gt;
&lt;p&gt;玩家此时要躲避，就需要跳跃。这时候就会发现自己跳到了横杆上，并且借助横杆，可以跳的更高来更好的躲避 boss 攻击。通过这样的设计，玩家就了解到了新机制。&lt;/p&gt;
&lt;h3 id=&#34;让玩家运用新机制以及心里反馈&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#让玩家运用新机制以及心里反馈&#34;&gt;#&lt;/a&gt; 让玩家运用新机制以及心里反馈&lt;/h3&gt;
&lt;p&gt;对于游戏来说，良好的难度曲线是并不可少的，因此难度曲线在玩家心里的反馈，就成了重中之重。&lt;/p&gt;
&lt;p&gt;前面两个关卡，第一关用于熟悉操作以及游戏机制，第二关用于了解新机制，第三关当然理所当然的是前面结合的关卡。&lt;/p&gt;
&lt;p&gt;由于当时时间，人力等等限制，就把这段设计做到了最后 boss 战环节，也就是第三关。同时也为 体现进入神秘组织内部的感觉，跟换了背景以及整体色调，暗调配合黑色背景给人一种神秘感。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/03/%E7%AC%AC%E4%B8%89%E5%85%B3-1024x616.webp&#34; alt=&#34;第三关&#34;&gt;&lt;/p&gt;
&lt;p&gt;第三关&lt;/p&gt;
&lt;p&gt;为了激发玩家的兴奋点，我设计了 boss 发射导弹的动作，导弹对玩家是一击必杀的，但是玩家可以跳上导弹来接着攻击 boss。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/03/%E7%AC%AC%E4%B8%89%E5%85%B3%E8%AE%BE%E8%AE%A1-1024x616.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;第三关设计&lt;/p&gt;
&lt;p&gt;这个设计迫使玩家去练习，去熟悉 boss 的攻击节奏。同时死亡在给玩家挫败感的同时，也在激发玩家的兴奋，这样游戏的乐趣会更多，难度曲线才有了一些。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;这就是我的一些游戏设计心得，本人并非专业人士，理解和思考不是很深刻，欢迎评论区指正并相互学习。&lt;/strong&gt;&lt;/p&gt;

 &lt;h2 id=&#34;运算符和表达式&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#运算符和表达式&#34;&gt;#&lt;/a&gt; 运算符和表达式&lt;/h2&gt;
&lt;h3 id=&#34;运算符&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#运算符&#34;&gt;#&lt;/a&gt; 运算符&lt;/h3&gt;
&lt;h4 id=&#34;运算符分类&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#运算符分类&#34;&gt;#&lt;/a&gt; 运算符分类&lt;/h4&gt;
&lt;h5 id=&#34;算数运算符&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#算数运算符&#34;&gt;#&lt;/a&gt; 算数运算符&lt;/h5&gt;
&lt;p&gt;+ （加）, - （减） , * （乘） , / （除） , %（取模） , ++ (自增，加一) , – （自减，减一）,&lt;/p&gt;
&lt;h5 id=&#34;关系运算符&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#关系运算符&#34;&gt;#&lt;/a&gt; 关系运算符&lt;/h5&gt;
&lt;p&gt;&amp;gt; （大于）, &amp;lt;（小于） ,&amp;gt;=（大于等于） , ==（等于） , != （不等于）&lt;/p&gt;
&lt;h5 id=&#34;逻辑运算符&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#逻辑运算符&#34;&gt;#&lt;/a&gt; 逻辑运算符&lt;/h5&gt;
&lt;p&gt;&amp;amp;&amp;amp;(与) ， （或） ，!(非) ,^（抑或）&lt;/p&gt;
&lt;h5 id=&#34;条件运算符&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#条件运算符&#34;&gt;#&lt;/a&gt; 条件运算符&lt;/h5&gt;
&lt;p&gt;表示为 “? :” ，是 JAVA 中唯一一个三目运算符，&lt;/p&gt;
&lt;p&gt;&amp;lt;1&amp;gt; ? &amp;lt;2&amp;gt; : &amp;lt;3&amp;gt;&lt;/p&gt;
&lt;p&gt;1 为真，1 赋为 2 的值，1 为假，1 赋为 3 的值。&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class Example09&amp;#123; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;public static void main(String[] args) &amp;#123; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;int x = 5 ;  //&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;int y = 10 ; //&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;int z ;  //&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;z = y &amp;gt; x ? y : x ;  // y &amp;gt; x 为true, 返回10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;System.out.println(z);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;运算符优先级&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#运算符优先级&#34;&gt;#&lt;/a&gt; 运算符优先级&lt;/h4&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/03/JAVA_%E4%BC%98%E5%85%88%E7%BA%A7-923x1024.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;优先级&lt;/p&gt;
&lt;p&gt;优先级&lt;/p&gt;
&lt;p&gt;运算符&lt;/p&gt;
&lt;p&gt;结合性&lt;/p&gt;
&lt;p&gt;1&lt;/p&gt;
&lt;p&gt;()、[]、{}&lt;/p&gt;
&lt;p&gt;从左向右&lt;/p&gt;
&lt;p&gt;2&lt;/p&gt;
&lt;p&gt;!、+、-、~、++、–&lt;/p&gt;
&lt;p&gt;从右向左&lt;/p&gt;
&lt;p&gt;3&lt;/p&gt;
&lt;p&gt;*、/、%&lt;/p&gt;
&lt;p&gt;从左向右&lt;/p&gt;
&lt;p&gt;4&lt;/p&gt;
&lt;p&gt;+、-&lt;/p&gt;
&lt;p&gt;从左向右&lt;/p&gt;
&lt;p&gt;5&lt;/p&gt;
&lt;p&gt;«、»、&amp;gt;&amp;gt;&amp;gt;&lt;/p&gt;
&lt;p&gt;从左向右&lt;/p&gt;
&lt;p&gt;6&lt;/p&gt;
&lt;p&gt;&amp;lt;、&amp;lt;=、&amp;gt;、&amp;gt;=、instanceof&lt;/p&gt;
&lt;p&gt;从左向右&lt;/p&gt;
&lt;p&gt;7&lt;/p&gt;
&lt;p&gt;==、!=&lt;/p&gt;
&lt;p&gt;从左向右&lt;/p&gt;
&lt;p&gt;8&lt;/p&gt;
&lt;p&gt;&amp;amp;&lt;/p&gt;
&lt;p&gt;从左向右&lt;/p&gt;
&lt;p&gt;9&lt;/p&gt;
&lt;p&gt;^&lt;/p&gt;
&lt;p&gt;从左向右&lt;/p&gt;
&lt;p&gt;10&lt;/p&gt;
&lt;p&gt;从左向右&lt;/p&gt;
&lt;p&gt;11&lt;/p&gt;
&lt;p&gt;&amp;amp;&amp;amp;&lt;/p&gt;
&lt;p&gt;从左向右&lt;/p&gt;
&lt;p&gt;12&lt;/p&gt;
&lt;p&gt;从左向右&lt;/p&gt;
&lt;p&gt;13&lt;/p&gt;
&lt;p&gt;?:&lt;/p&gt;
&lt;p&gt;从右向左&lt;/p&gt;
&lt;p&gt;14&lt;/p&gt;
&lt;p&gt;=、+=、-=、*=、/=、&amp;amp;=、=、^=、~=、«=、»=、&amp;gt;&amp;gt;&amp;gt;=&lt;/p&gt;
&lt;p&gt;从右向左&lt;/p&gt;
&lt;p&gt;JAVA 运算符优先级&lt;/p&gt;
&lt;p&gt;此表来自这篇&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cDovL2MuYmlhbmNoZW5nLm5ldC92aWV3Lzc5NC5odG1s&#34;&gt;文章&lt;/span&gt;&lt;/p&gt;
&lt;h4 id=&#34;其他&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#其他&#34;&gt;#&lt;/a&gt; 其他&lt;/h4&gt;
&lt;h5 id=&#34;在运算中-a-和-a-的区别&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#在运算中-a-和-a-的区别&#34;&gt;#&lt;/a&gt; 在运算中 a++ 和 ++a 的区别&lt;/h5&gt;
&lt;p&gt;如果是 a++，a 先参加运算然后在加一，和优先级无关，如果是 ++a，则反，&lt;/p&gt;
&lt;h5 id=&#34;前后自增自减运算规则&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#前后自增自减运算规则&#34;&gt;#&lt;/a&gt; &lt;strong&gt;前后自增自减&lt;/strong&gt;运算规则&lt;/h5&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;前自增 / 自减（++a , --a）的运算规则是&lt;/strong&gt;：先进行自增或者自减运算，再进行表达式运算；&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;后自增 / 自减 (a++ , a–) 的运算规则是&lt;/strong&gt;：先进行表达式运算，再进行自增或者自减运算。&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;上面的运算规则来自 &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cuaW1vb2MuY29tL3dpa2kvamF2YWxlc3Nvbi9leHByZXNzaW9ucy5odG1s&#34;&gt;这篇文章&lt;/span&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class Example01&amp;#123; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;public static void main(String[] args) &amp;#123; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;int x = 5 ;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;int y = 10 ; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;int z ;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;z = ++x + y++ ;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;System.out.println(z);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;// 1+5+10,运算完成后，y+1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;表达式&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#表达式&#34;&gt;#&lt;/a&gt; 表达式&lt;/h3&gt;
&lt;p&gt;表达式是根据 Java 语法由&lt;strong&gt;变量&lt;/strong&gt;、&lt;strong&gt;运算符&lt;/strong&gt;和&lt;strong&gt;方法调用&lt;/strong&gt;组成的结构，表达式的结算结果为&lt;strong&gt;单个值&lt;/strong&gt;。&lt;/p&gt;
&lt;h4 id=&#34;表达式实例&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#表达式实例&#34;&gt;#&lt;/a&gt; 表达式实例&lt;/h4&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class Expression &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      int a = 10, b = 20;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      // (a + b) * 2 就是一个算数表达式&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      int c = (a + b) * 2;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      // c &amp;gt; b 就是一个布尔表达式&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      if (c &amp;gt; b) &amp;#123; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;          System.out.println(&amp;quot;c大于b&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;表达式中的数据类型转换&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#表达式中的数据类型转换&#34;&gt;#&lt;/a&gt; 表达式中的数据类型转换&lt;/h4&gt;
&lt;p&gt;转换规律：&lt;/p&gt;
&lt;p&gt;高精度（float,double 等）&lt;strong&gt;不可以&lt;/strong&gt;向低精度 (int,long,byte 等) 转换&lt;/p&gt;
&lt;p&gt;可以从低精度向着高精度转换&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/03/%E8%A1%A8%E8%BE%BE%E5%BC%8F%E6%95%B0%E6%8D%AE%E7%B1%BB%E5%9E%8B%E8%BD%AC%E6%8D%A2-1024x576.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;

 &lt;h2 id=&#34;mysql基本操作&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#mysql基本操作&#34;&gt;#&lt;/a&gt; MySQL 基本操作&lt;/h2&gt;
&lt;h3 id=&#34;数据库基本操作&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#数据库基本操作&#34;&gt;#&lt;/a&gt; 数据库基本操作&lt;/h3&gt;
&lt;h4 id=&#34;创建数据库&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#创建数据库&#34;&gt;#&lt;/a&gt; 创建数据库&lt;/h4&gt;
&lt;p&gt;使用 Create database + 库名 来创建&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;Create database T1 ; #创建一个名为&amp;quot;T1&amp;quot;的数据库&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;创建成功会显示这个：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/03/Create-database-T1.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;使用参数 if not exists 可以在创建数据库时，出现相同数据库的时候不报错 (一般情况下创建相同名称数据库会报错)。&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;Create database if not exists T1 ; #创建一个名为&amp;quot;T1&amp;quot;的数据库&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;当然也是可以设置数据库字符集。&lt;/p&gt;
&lt;p&gt;创建字符集为 gb2312 的数据库&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;Create database if not exists T1 default character set gb2312 ; #创建名为“T1”的数据库，字符集设定为gb2312&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;排序规则（校对规则）: 是指对指定字符集下不同字符的比较规则。&lt;/p&gt;
&lt;p&gt;查看可用的排序规则&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;show collsation ; #查看可用的排序规则&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;创建数据库 T1，修改字符集为 utf8，更改排序规则为 utf8_unicode_ci&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;Create database T1 default character set utf8 default collate utf8_unicode_ci ; #创建数据库T1，修改字符集为 utf8，更改排序规则为utf8_unicode_ci&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;查看数据库&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#查看数据库&#34;&gt;#&lt;/a&gt; 查看数据库&lt;/h4&gt;
&lt;p&gt;查看数据库定义（字符集和排序规则）&lt;/p&gt;
&lt;p&gt;show create database + 空格 + 库名&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;show create database T1 ; #查询T1数据库定义&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;使用数据库&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#使用数据库&#34;&gt;#&lt;/a&gt; 使用数据库&lt;/h4&gt;
&lt;p&gt;use + 库名&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;use T1 ; #使用T1数据库&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;修改数据库&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#修改数据库&#34;&gt;#&lt;/a&gt; 修改数据库&lt;/h4&gt;
&lt;p&gt;alter database + 库名 default character set + 新字符集 default collate + 新排序规则&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;alter database T1 default character set gbk ;#将T1数据库的字符集改为gbk&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;删除数据库&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#删除数据库&#34;&gt;#&lt;/a&gt; 删除数据库&lt;/h4&gt;
&lt;p&gt;drop database + 库名来删除数据库 (此命令不可以用来删除数据库中的表)&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;drop database T1 ; #删除T1数据库&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;数据库的一些其他指令&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#数据库的一些其他指令&#34;&gt;#&lt;/a&gt; 数据库的一些其他指令&lt;/h4&gt;
&lt;p&gt;MySQL 默认结束符为分号 (&amp;quot;;&amp;quot;)&lt;/p&gt;
&lt;p&gt;修改结束符:&lt;/p&gt;
&lt;p&gt;delimiter + 空格 + 新结束符&lt;/p&gt;
&lt;p&gt;修改结束符只能单次使用，重启后将转为默认&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;delimiter ！ #将结束符换为 &amp;quot;!&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;可以用指令验证&lt;/p&gt;
&lt;p&gt;show databases + 新结束符：展示数据库&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;show databases ! #展示数据库&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;退出 MySQL：&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;quit #退出数据库&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;exit&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;查看服务器信息:&lt;/p&gt;
&lt;p&gt;Status + 空格 + 结束符&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;Status ; #显示服务器信息&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;数据表基本操作&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#数据表基本操作&#34;&gt;#&lt;/a&gt; 数据表基本操作&lt;/h3&gt;
&lt;h4 id=&#34;数据类型&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#数据类型&#34;&gt;#&lt;/a&gt; 数据类型&lt;/h4&gt;
&lt;h5 id=&#34;整型&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#整型&#34;&gt;#&lt;/a&gt; 整型&lt;/h5&gt;
&lt;p&gt;int 占用四个字节&lt;/p&gt;
&lt;p&gt;bigint 占用八个字节&lt;/p&gt;
&lt;p&gt;Tinyint 占用一个字节&lt;/p&gt;
&lt;p&gt;smallint 占用两个字节&lt;/p&gt;
&lt;p&gt;mediumint 占用三个字节&lt;/p&gt;
&lt;p&gt;整型类型&lt;/p&gt;
&lt;p&gt;占用字节&lt;/p&gt;
&lt;p&gt;int&lt;/p&gt;
&lt;p&gt;4&lt;/p&gt;
&lt;p&gt;bigint&lt;/p&gt;
&lt;p&gt;8&lt;/p&gt;
&lt;p&gt;Tinyint&lt;/p&gt;
&lt;p&gt;1&lt;/p&gt;
&lt;p&gt;smallint&lt;/p&gt;
&lt;p&gt;2&lt;/p&gt;
&lt;p&gt;mediumint&lt;/p&gt;
&lt;p&gt;3&lt;/p&gt;
&lt;p&gt;整型类型&lt;/p&gt;
&lt;p&gt;适用于 ：有数值，有大小比较的。&lt;/p&gt;
&lt;h5 id=&#34;浮点型&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#浮点型&#34;&gt;#&lt;/a&gt; 浮点型&lt;/h5&gt;
&lt;p&gt;有小数点的数值&lt;/p&gt;
&lt;p&gt;Float (m,d)&lt;/p&gt;
&lt;p&gt;double(m,d)&lt;/p&gt;
&lt;p&gt;其中:&lt;/p&gt;
&lt;p&gt;m 表示该数值有几位整数，&lt;/p&gt;
&lt;p&gt;d 表示小数点后面有几位&lt;/p&gt;
&lt;p&gt;float (3,2) ; -9.99 — +9.99&lt;/p&gt;
&lt;h5 id=&#34;字符串&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#字符串&#34;&gt;#&lt;/a&gt; 字符串&lt;/h5&gt;
&lt;p&gt;字母，汉字，数字符号，特殊符号构成的数据对象&lt;/p&gt;
&lt;p&gt;适用于：身份证号，编号，电话号码。联系地址，名称等&lt;/p&gt;
&lt;p&gt;char：定长字符串，长度为 0 - 255。保存 char 时，在右边填充空格来达到指定长度&lt;/p&gt;
&lt;p&gt;varchar ：可变字符串，长度为 0 - 65535。只保存需要的字符数，另外再加一个字节来记录&lt;/p&gt;
&lt;p&gt;如果超出规定长度，char 和 varchar 会对值裁剪以适应，如果裁剪的字符不是空格，会发出警告。&lt;/p&gt;
&lt;p&gt;如果超出规定长度，char 和 varchar 会对值裁剪以适应，如果裁剪的字符不是空格，会发出警告。&lt;/p&gt;
&lt;h5 id=&#34;blob-和text类型&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#blob-和text类型&#34;&gt;#&lt;/a&gt; blob 和 text 类型&lt;/h5&gt;
&lt;p&gt;(非二进制字符串）&lt;/p&gt;
&lt;p&gt;存储声音，视频，头像等设置&lt;/p&gt;
&lt;h5 id=&#34;时间和日期类型&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#时间和日期类型&#34;&gt;#&lt;/a&gt; 时间和日期类型&lt;/h5&gt;
&lt;p&gt;date , time 和 datatime&lt;/p&gt;
&lt;p&gt;固定的格式数据，存储的是日期和时间&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;date 类型&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;存储格式 ： yyyy - mm - dd&lt;/p&gt;
&lt;p&gt;支持范围 ： 1000 - 01 - 01 ~~9999 - 12 - 31&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;time 类型&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;存储格式 : hh : mm : ss&lt;/p&gt;
&lt;p&gt;支持范围；-838 : 59 : 59 ~~ 838 : 59 : 59&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;datetime 类型&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;表示日期时间&lt;/p&gt;
&lt;p&gt;存储格式 : yyyy - mm - dd hh : mm : ss&lt;/p&gt;
&lt;p&gt;支持范围 ：1000 - 01 - 01 00 : 00 : 00 ~~ 9999 - 12 -31 23 : 59 :59&lt;/p&gt;
&lt;p&gt;timestamp 类型&lt;/p&gt;
&lt;p&gt;客户端插入的时间从当前时区转化为 UTC（世界标准时间）进行存储。查询时，将其又转化为客户端当前时区进行返回&lt;/p&gt;
&lt;h4 id=&#34;创建数据表&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#创建数据表&#34;&gt;#&lt;/a&gt; 创建数据表&lt;/h4&gt;
&lt;p&gt;在数据库中新建数据表&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;create table t1 ; #创建名为 t1 数据表 &lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;创建数据表，规定长度&lt;/p&gt;
&lt;p&gt;创建前记得使用数据库&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;use t1 ;  //使用t1数据库&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;create table t0 &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;(name char(10),&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;logintime date,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;mail varchar(20),&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;score float(5,2),&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;list int(5),&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;photo text comment&amp;quot;头像&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; #创建名为 t0 数据表&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;comment ： 解释。一般放在数据类型后面，表示对于字段名的解释，可以理解成为注释。&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;comment &amp;quot;解释内容&amp;quot;  #comment使用方法&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;创建临时表&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;create temporary table (N1) ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;create temporary table () ; //创建临时数据表&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;N1 包含两个字段：id 和 name&lt;/p&gt;
&lt;h4 id=&#34;查看数据表&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#查看数据表&#34;&gt;#&lt;/a&gt; 查看数据表&lt;/h4&gt;
&lt;h5 id=&#34;查找数据表&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#查找数据表&#34;&gt;#&lt;/a&gt; 查找数据表&lt;/h5&gt;
&lt;p&gt;XX 为需要查找名&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;show table like &amp;quot;XX%&amp;quot; ; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;//可以查找多个字符,只要指定包含查找字段就会被查找到&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;//如果查找 &amp;quot;X%&amp;quot;,则会出现 XXX,XYX,XXYXY,XXYXYX&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;show table like&amp;quot;XX_&amp;quot; ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;//只能查找单个字符&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;//如果查找&amp;quot;X_&amp;quot;,则会出现XX,&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;查看数据表的列&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#查看数据表的列&#34;&gt;#&lt;/a&gt; 查看数据表的列&lt;/h5&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;//desc + 表名 +列名 ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;//查看teacher表中的teachearID列&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;desc teacher teacherID ;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/04/desc_biaominglieming.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;h5 id=&#34;查看数据表状况&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#查看数据表状况&#34;&gt;#&lt;/a&gt; 查看数据表状况&lt;/h5&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;show table status ;  //查看数据表&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/03/show-table-status-1024x156.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;但是如果数据表太多会难以查找，需要在末尾加个 \G，变为横向排列&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;show table status \G&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;如果加了 \G ，就不需要结束符了，否则会报错&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/03/show-table-status-G.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;查看存在数据表的名称&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;show table + 表名 ; #查看存在数据表的名称&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;查看数据表结构&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;desc/describe + 表名 ; #查看数据表结构&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;查看表的定义语句&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#查看表的定义语句&#34;&gt;#&lt;/a&gt; 查看表的定义语句&lt;/h5&gt;
&lt;p&gt;查看表里有什么&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;//show create table + 表名 ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;show create table score ;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/03/show-create-table.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;h5 id=&#34;查看表的结构&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#查看表的结构&#34;&gt;#&lt;/a&gt; 查看表的结构&lt;/h5&gt;
&lt;p&gt;使用 describe 可查看字段定义，键的信息，默认值等&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt; //desc / describe + 表名 ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;describe score ;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/03/describe-score.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;h5 id=&#34;根据指定条配件来查询&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#根据指定条配件来查询&#34;&gt;#&lt;/a&gt; 根据指定条配件来查询&lt;/h5&gt;
&lt;p&gt;消除结果集中的重复行&lt;/p&gt;
&lt;p&gt;使用 Distinct 关键字&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;SELECT DISTINCT [字段名1，字段名2] FROM 表名 ;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;多个字段名的话，只有两个字段完全相同。DISTINCT 关键字才会同时消除&lt;/p&gt;
&lt;p&gt;实现有条件筛选&lt;/p&gt;
&lt;p&gt;运算符&lt;/p&gt;
&lt;p&gt;运算符&lt;/p&gt;
&lt;p&gt;名称&lt;/p&gt;
&lt;p&gt;说明&lt;/p&gt;
&lt;p&gt;=&lt;/p&gt;
&lt;p&gt;等于&lt;/p&gt;
&lt;p&gt;&amp;lt;&amp;gt; !=&lt;/p&gt;
&lt;p&gt;不等于&lt;/p&gt;
&lt;p&gt;&amp;lt; &amp;lt;= &amp;gt; &amp;gt;=&lt;/p&gt;
&lt;p&gt;小于，小于等于，大于，大于等于&lt;/p&gt;
&lt;p&gt;Between&lt;/p&gt;
&lt;p&gt;在… 之间&lt;/p&gt;
&lt;p&gt;is null&lt;/p&gt;
&lt;p&gt;空值&lt;/p&gt;
&lt;p&gt;between&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;select&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;多条件查询&lt;/p&gt;
&lt;p&gt;Where 条件&lt;/p&gt;
&lt;p&gt;说明&lt;/p&gt;
&lt;p&gt;And&lt;/p&gt;
&lt;p&gt;两个或者多个条件同时满足&lt;/p&gt;
&lt;p&gt;Or&lt;/p&gt;
&lt;p&gt;两个或者多个条件满足一个&lt;/p&gt;
&lt;p&gt;In&lt;/p&gt;
&lt;p&gt;多个条件中的一个&lt;/p&gt;
&lt;p&gt;Like&lt;/p&gt;
&lt;p&gt;搭配 % 通配符或者_通配符来模糊搜索&lt;/p&gt;
&lt;h4 id=&#34;修改数据表&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#修改数据表&#34;&gt;#&lt;/a&gt; 修改数据表&lt;/h4&gt;
&lt;p&gt;alter table + 表名&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;alter table + 表名 ；&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;[warning] 注意，以下修改数据表所有操作都要加 alter table + 表名。[/warning]&lt;/p&gt;
&lt;h5 id=&#34;添加新字段&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#添加新字段&#34;&gt;#&lt;/a&gt; &lt;strong&gt;添加新字段&lt;/strong&gt;&lt;/h5&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;alter table 表名 add  字段名 + 字段名定义 ；&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;可以在末尾加 first 或者 aftear 来在指定字段前新增字段&lt;/p&gt;
&lt;h5 id=&#34;添加默认值和删除默认值&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#添加默认值和删除默认值&#34;&gt;#&lt;/a&gt; &lt;strong&gt;添加默认值和删除默认值&lt;/strong&gt;&lt;/h5&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;alter table 表名 alter  字段名 set default + 默认值 ; //修改默认值&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;alter table 表名 alter  字段名 drop default ; // 删除默认值 &lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;修改字段名&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#修改字段名&#34;&gt;#&lt;/a&gt; &lt;strong&gt;修改字段名&lt;/strong&gt;&lt;/h5&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;alter table 表名 change  旧字段名 + 新字段名 + 字段 ;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;修改字段定义&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#修改字段定义&#34;&gt;#&lt;/a&gt; &lt;strong&gt;修改字段定义&lt;/strong&gt;&lt;/h5&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;alter table 表名 modify  + 字段名 + 字段的新定义  ;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;alter table student modify  studentmark text ;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;删除字段&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#删除字段&#34;&gt;#&lt;/a&gt; &lt;strong&gt;删除字段&lt;/strong&gt;&lt;/h5&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;alter table 表名 drop + 字段名 ;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;strong&gt;删除多个字段&lt;/strong&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;alter table 表名 drop 字段1 drop 字段2 ;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;为表重命名&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#为表重命名&#34;&gt;#&lt;/a&gt; &lt;strong&gt;为表重命名&lt;/strong&gt;&lt;/h5&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;alter table 表名 rename to + 新表名 ;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;strong&gt;实例&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;为表添加备注字段，字段名为 studentremark, 数据类型为 varcgar (100)，放置在 stuname 字段之后&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;alter table score add studentremark varchar(100) after stuname ;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;为 score 添加一个字段，字段名为 classid 数据类型为 varchar (10)，默认值为 10&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;alter table score add classid varchar(10) set default 10 after studentremark ;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;验证&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;#desc + 表名 ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;desc score ;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;为字段增加内容&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#为字段增加内容&#34;&gt;#&lt;/a&gt; &lt;strong&gt;为字段增加内容&lt;/strong&gt;&lt;/h5&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;insert into 表名 values(内容1，内容2);&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;&lt;strong&gt;分字段批量增加内容&lt;/strong&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;insert into 表名(字段名1，字段名2)values(内容1,内容2) ;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;添加多组内容&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;insert into 表名 values(内容1,内容2)(内容3,内容4) ;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;将指定字段导入到新表中&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;//insert into 目标表(字段1，字段2) select (字段1，字段2) from 来源表&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;insert into student(Name，StudentID) select (Name，StudentID) from StuentClass&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;update修改表的数据&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#update修改表的数据&#34;&gt;#&lt;/a&gt; update 修改表的数据&lt;/h5&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;//update 表名 set 字段名1 = 值1，字段名2 = 值2 where 条件&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;[warning] update 修改的是表中数据，不是字段 [/warning]&lt;/p&gt;
&lt;p&gt;多表数据修改&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;update 表名列表 set 表名.字段名1 =  值1, 表名.字段名2 = 值2 where 表名.条件 ；&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;表名。字段名 表示表中的某个字段&lt;/p&gt;
&lt;h5 id=&#34;按条件删除数据&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#按条件删除数据&#34;&gt;#&lt;/a&gt; 按条件删除数据&lt;/h5&gt;
&lt;p&gt;delete , truncate 来删除&lt;/p&gt;
&lt;p&gt;使用 delete 删除&lt;/p&gt;
&lt;p&gt;删除表中 ++ 所有数据：&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;//delete from 表名 ;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;删除表中的部分数据&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;delete from 表名 where 条件 ；&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;区别&lt;/p&gt;
&lt;p&gt;Delete: 删除部分数据或者所有数据，执行速度较慢，删除后日志中可找回&lt;br&gt;
 truncate：删除表中所有数据，删除速度较快，不能使用 where 子句，无法找回&lt;/p&gt;
&lt;h4 id=&#34;复制数据表&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#复制数据表&#34;&gt;#&lt;/a&gt; 复制数据表&lt;/h4&gt;
&lt;p&gt;create [if not exists] 新表名&lt;/p&gt;
&lt;p&gt;[like 参照表名]&lt;/p&gt;
&lt;p&gt;[al {selsct 语句}]&lt;/p&gt;
&lt;p&gt;like 像：创建一个和草诏表名结果相同的新表，不复制内容，其他的都复制&lt;/p&gt;
&lt;p&gt;as 完全复制表的内容，单索引和完整性拘束不会复制，selsct 语句是一个表达式，可以是一个 selsc 语句&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;use bookstore;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;create table book like book_copy1;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;create table book_copy2 as(select * from book);&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;删除数据表&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#删除数据表&#34;&gt;#&lt;/a&gt; 删除数据表&lt;/h4&gt;
&lt;p&gt;dorp table [if not exists] + 表名&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;dorp table if not exists student ;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;其他&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#其他&#34;&gt;#&lt;/a&gt; 其他&lt;/h4&gt;
&lt;p&gt;存储引擎：对不同表类型的处理器&lt;/p&gt;
&lt;p&gt;默认:innoDB&lt;/p&gt;
&lt;p&gt;Engine = innoDB&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;create table (字段名 数据类型)engine = innoDB ;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;让其识别中文字符&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;set names gbk ;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;timestamp&lt;/p&gt;
&lt;p&gt;如果没有给定日期型&lt;/p&gt;

 &lt;h1 id=&#34;unit-1-traveling-around&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#unit-1-traveling-around&#34;&gt;#&lt;/a&gt; Unit 1 Traveling Around&lt;/h1&gt;
&lt;h2 id=&#34;words-单词&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#words-单词&#34;&gt;#&lt;/a&gt; Words 单词&lt;/h2&gt;
&lt;p&gt;wonderful adj. 极好的&lt;/p&gt;
&lt;p&gt;row n. 一排，一行&lt;/p&gt;
&lt;p&gt;blanket n. 毛毯&lt;/p&gt;
&lt;p&gt;cushion n. 垫子，坐垫&lt;/p&gt;
&lt;p&gt;rack n. 架子，支架&lt;/p&gt;
&lt;p&gt;belongings n. [pl.] 财物&lt;/p&gt;
&lt;p&gt;belt n. 皮带，腰带&lt;/p&gt;
&lt;p&gt;object n. 物品，实物&lt;/p&gt;
&lt;p&gt;clip n.（金属或塑料的）夹子&lt;/p&gt;
&lt;h2 id=&#34;phrases-词组&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#phrases-词组&#34;&gt;#&lt;/a&gt; Phrases 词组&lt;/h2&gt;
&lt;p&gt;make impressions on sb. 给某人留下印象&lt;/p&gt;
&lt;p&gt;trest sb. as 将… 视为&lt;/p&gt;
&lt;p&gt;boarding card 登机牌&lt;/p&gt;
&lt;p&gt;window seat 靠窗座位&lt;/p&gt;
&lt;p&gt;aisle seat 靠道座位&lt;/p&gt;

 &lt;h2 id=&#34;什么是mysql&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#什么是mysql&#34;&gt;#&lt;/a&gt; 什么是 MySQL？&lt;/h2&gt;
&lt;p&gt;MySQL?ˋ(° ▽、°) 当然是没压岁钱了啊 ( M (没) y (压) S (岁) Q (钱) L (了) 谐音梗扣钱 ψ(._. )&amp;gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;MySQL 是关系型数据库管理系统&lt;/strong&gt;&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;数据管理工具&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;mysql-是如何管理数据的&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#mysql-是如何管理数据的&#34;&gt;#&lt;/a&gt; MySQL 是如何管理数据的？&lt;/h3&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/03/MySQL-1024x397.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;MySQL 原理图示&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;MySQL 不是直接管理数据的，是通过对表的管理，来管理数据的&lt;/strong&gt;。&lt;/p&gt;
&lt;p&gt;(所以说 MySQL 是数据库的是错误的哦 =￣ω￣=）&lt;/p&gt;
&lt;h2 id=&#34;什么是数据库&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#什么是数据库&#34;&gt;#&lt;/a&gt; 什么是数据库？&lt;/h2&gt;
&lt;p&gt;数据库（DataBase 简称 DB ）是按照数据结构来组织，存储，管理数据的仓库。&lt;/p&gt;
&lt;h3 id=&#34;数据库的发展&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#数据库的发展&#34;&gt;#&lt;/a&gt; 数据库的发展&lt;/h3&gt;
&lt;h4 id=&#34;手工管理&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#手工管理&#34;&gt;#&lt;/a&gt; 手工管理&lt;/h4&gt;
&lt;p&gt;特点：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;数据不在计算机中长期保存&lt;/li&gt;
&lt;li&gt;没有专门的数据管理软件，数据包需要应用程序自己掌握&lt;/li&gt;
&lt;li&gt;不同程序之间无法共享数据&lt;/li&gt;
&lt;li&gt;数据不具有独立性完全依赖应用程序&lt;/li&gt;
&lt;/ul&gt;
&lt;h4 id=&#34;文件管理&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#文件管理&#34;&gt;#&lt;/a&gt; 文件管理&lt;/h4&gt;
&lt;p&gt;OS, Operating System&lt;/p&gt;
&lt;p&gt;特点：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;数据在计算机的外村设备上长期保存，可以对数据反复操作&lt;/li&gt;
&lt;li&gt;利用文件系统，可以管理和存取&lt;/li&gt;
&lt;li&gt;一定程度上实现了数据的独立性和共享性，但是非常薄弱&lt;/li&gt;
&lt;/ul&gt;
&lt;h4 id=&#34;数据库管理&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#数据库管理&#34;&gt;#&lt;/a&gt; 数据库管理&lt;/h4&gt;
&lt;p&gt;DBMS, Database Management System&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;数据结构化&lt;/li&gt;
&lt;li&gt;数据共享&lt;/li&gt;
&lt;li&gt;数据独立性高&lt;/li&gt;
&lt;li&gt;数据统一管理与控制&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;关系型数据库&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#关系型数据库&#34;&gt;#&lt;/a&gt; 关系型数据库&lt;/h3&gt;
&lt;p&gt;Oracle , SQL Server , DB2 , MySQL 等.&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/03/%E5%85%B3%E7%B3%BB%E6%95%B0%E6%8D%AE%E5%BA%93-1024x605.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;h4 id=&#34;关系型数据库的二维表关系&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#关系型数据库的二维表关系&#34;&gt;#&lt;/a&gt; 关系型数据库的二维表关系&lt;/h4&gt;
&lt;p&gt;&lt;strong&gt;二维表中每一行数据称之为一个元组，也叫记录&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;属性：二维表中的列称为属性，上图里的 “编号”， “姓名” ， “年龄” 等就是属性&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;域是指属性的取值范围，有些属性会存在。（像喜好这样的属性是没有域的╰(￣ω￣ｏ)）&lt;/p&gt;
&lt;p&gt;主键 (Primary Key) ：可以理解成关键字，具有唯一性，不可以为空。&lt;/p&gt;
&lt;p&gt;外键 (Foreign Key) : 用于关联两个表。&lt;/p&gt;
&lt;p&gt;一般主键存在于父表，外键存在于子表&lt;/p&gt;
&lt;p&gt;值 (Value) : 不唯一，可为空值。&lt;/p&gt;
&lt;p&gt;如何理解主键和外键？&lt;/p&gt;
&lt;p&gt;物品名&lt;/p&gt;
&lt;p&gt;价格&lt;/p&gt;
&lt;p&gt;数量&lt;/p&gt;
&lt;p&gt;1&lt;/p&gt;
&lt;p&gt;3&lt;/p&gt;
&lt;p&gt;7&lt;/p&gt;
&lt;p&gt;2&lt;/p&gt;
&lt;p&gt;4&lt;/p&gt;
&lt;p&gt;8&lt;/p&gt;
&lt;p&gt;3&lt;/p&gt;
&lt;p&gt;5&lt;/p&gt;
&lt;p&gt;9&lt;/p&gt;
&lt;p&gt;表一&lt;/p&gt;
&lt;p&gt;物品&lt;/p&gt;
&lt;p&gt;数量&lt;/p&gt;
&lt;p&gt;1&lt;/p&gt;
&lt;p&gt;1&lt;/p&gt;
&lt;p&gt;3&lt;/p&gt;
&lt;p&gt;3&lt;/p&gt;
&lt;p&gt;表二&lt;/p&gt;
&lt;p&gt;这里表一和表二相比，表一物品名的键对应的值多，并且关联两个表，表一的物品名为外键，而表二的物品名唯一，为主键。&lt;/p&gt;
&lt;h3 id=&#34;非关系型数据库&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#非关系型数据库&#34;&gt;#&lt;/a&gt; 非关系型数据库&lt;/h3&gt;
&lt;p&gt;Redis&lt;/p&gt;
&lt;p&gt;MongoDB&lt;/p&gt;
&lt;h3 id=&#34;sql-语言&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#sql-语言&#34;&gt;#&lt;/a&gt; SQL 语言&lt;/h3&gt;
&lt;p&gt;值得注意的是这些操作针对的是整个数据库，或者数据库的对象&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;标准语言是 SQL (英文全称：Structured Query Language)，结构化查询语言是关系数据库的标准语言。&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;SQL 分为四个部分:&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;数据定义语言（DDL）: 定义数据库，表等&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;CREATE 语句创建数据库，删除表 (对象) 等&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;数据操作语言 (DML) ：用于对数据库进行添加，修改和删除等操作。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;INSERT 语句对数据库进行添加修改删除命令，UPDATE 语句用于修改数据，DALETE 语句用于删除数据。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;数据查询语言 (DQl): 用于查询数据。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;SELECT 语句查询数据库中一条数据或者多条数据。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;数据控制语言 (DCL): 用于控制用户。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;GRANT 语句控制用户权限等&lt;/p&gt;
&lt;p&gt;值得注意的是这些操作针对的是整个数据库，或者数据库的对象。（对象 =&amp;gt; 表）&lt;/p&gt;
&lt;h2 id=&#34;mysql的安装&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#mysql的安装&#34;&gt;#&lt;/a&gt; MySQL 的安装&lt;/h2&gt;
&lt;p&gt;安装教程可以根据这个帖子来安装：&lt;/p&gt;
&lt;p&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L1dIRWVlZWUvYXJ0aWNsZS9kZXRhaWxzLzExNTI4NjgzMw==&#34;&gt;MySQL 安装教程&lt;/span&gt;&lt;/p&gt;
&lt;h3 id=&#34;开启关闭-mysql-服务&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#开启关闭-mysql-服务&#34;&gt;#&lt;/a&gt; 开启 / 关闭 MySQL 服务&lt;/h3&gt;
&lt;p&gt;使用管理员身份打开 CMD，输入&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;net start mysql &lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;可以打开 MySQL 服务，&lt;/p&gt;
&lt;p&gt;输入&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;net stop mysql&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;可以关闭 MySQL 服务&lt;/p&gt;

 &lt;h2 id=&#34;什么是java&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#什么是java&#34;&gt;#&lt;/a&gt; 什么是 JAVA&lt;/h2&gt;
&lt;p&gt;什么是 JAVA？不就是杯&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9sb2dvcy1tYXJxdWVzLmNvbS93cC1jb250ZW50L3VwbG9hZHMvMjAyMS8wMy9KYXZhLUxvZ28tMTk5Ni5wbmc=&#34;&gt;咖啡&lt;/span&gt;吗 (○｀ 3′○)( 谁说的，有可能还是个&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly96aC5tb2VnaXJsLm9yZy5jbi9KYXZhJUU1JUE4JTk4&#34;&gt;妹子&lt;/span&gt;╰(￣ω￣ｏ)（（（&lt;/p&gt;
&lt;p&gt;java 是纯面向对象编程的语言。亲身经历：学 JAVA 无法解决单身问题&lt;/p&gt;
&lt;h3 id=&#34;如何理解面向对象编程&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#如何理解面向对象编程&#34;&gt;#&lt;/a&gt; 如何理解面向对象编程？&lt;/h3&gt;
&lt;p&gt;以下转自博客园的这个&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cuY25ibG9ncy5jb20vaWRlYWwtMjAvcC8xMTA1MDE0Ni5odG1s&#34;&gt;帖子&lt;/span&gt;。&lt;/p&gt;
&lt;p&gt;例如我们设计一个桌球游戏（略过开球，只考虑中间过程）&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;A：面向过程方式思考：&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;把下述的步骤&lt;strong&gt;通过函数一步一步实现&lt;/strong&gt;，这个需求就完成了。（只为演示概念，不细究逻辑问题）。&lt;/p&gt;
&lt;p&gt;① palyer1 击球 —— ② 实现画面击球效果 —— ③ 判断是否进球及有效 —— ④ palyer2 击球&lt;/p&gt;
&lt;p&gt;⑤ 实现画面击球效果 —— ⑥ 判断是否进球及有效 —— ⑦ 返回步骤 1—— ⑧ 输出游戏结果&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;B：面向对象方式思考：&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;经过观察我们可以看到，其实在上面的流程中存在很多&lt;strong&gt;共性&lt;/strong&gt;的地方，所以我们将这些共性部分全集中起来，做成一个&lt;strong&gt;通用的结构&lt;/strong&gt;&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;&lt;strong&gt;玩家系统&lt;/strong&gt;：包括 palyer1 和 palyer2&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;击球效果系统&lt;/strong&gt;：负责展示给用户游戏时的画面&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;规则系统&lt;/strong&gt;：判断是否犯规，输赢等&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&lt;img data-src=&#34;https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/4f7d3745f0884b66ad204a412533c5a3~tplv-k3u1fbpfcp-zoom-1.image&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;我个人结合博客园帖子的理解:&lt;/p&gt;
&lt;p&gt;面向对象更像是做一个锤子，一个普遍性工具，一个实现循环显示数字的代码可以到多个地方应用，比如显示数字，让小灯循环亮起。需要这个功能调用这个类就可以了，方便快捷。但是缺点显而易见的，锤子不可能适合砸所有东西，这样面向对象也是，需要对应的库来实现。&lt;/p&gt;
&lt;p&gt;面向过程更像是定制化，效率高，但是添加新东西，需要写代码，相当于造一个专用的扳手。&lt;/p&gt;
&lt;h3 id=&#34;向世界问好&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#向世界问好&#34;&gt;#&lt;/a&gt; 向世界问好&lt;/h3&gt;
&lt;h4 id=&#34;代码&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#代码&#34;&gt;#&lt;/a&gt; 代码&lt;/h4&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class HelloWorld&amp;#123;  //JAVA系统的类，文件名必须和类名相同&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;public static void main(String[]args)&amp;#123;   //定义main方法(函数)，一个 java 程序运行必须而且有且仅有一个 main 方法。JAVA程序开始,String(str)表明数据类型,args表示数组&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;System.out.println(&amp;quot;hello,world&amp;quot;); //显示HelloWorld&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;  //注意：方法必须用大括号括起来&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;注意: Java 是大小写敏感的，这就意味着标识符 Hello 与 hello 是不同的&lt;/p&gt;
&lt;h4 id=&#34;编译java&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#编译java&#34;&gt;#&lt;/a&gt; 编译 JAVA&lt;/h4&gt;
&lt;p&gt;win+R 进入命令行，cd 到 Java 文件所在目录，输入 javac + 文件名 (带扩展名) 编译。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/03/%E7%BC%96%E8%AF%91java.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;h4 id=&#34;运行&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#运行&#34;&gt;#&lt;/a&gt; 运行&lt;/h4&gt;
&lt;p&gt;编译完成后，输入 java + 文件名（不带后缀），运行&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/03/RUNJAVA.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;h4 id=&#34;可能出现的问题&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#可能出现的问题&#34;&gt;#&lt;/a&gt; 可能出现的问题&lt;/h4&gt;
&lt;p&gt;有的时候编译完成，运行，会出现这样的问题，那是编码方式不对。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/03/java%E4%B9%B1%E7%A0%81.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;就需要修改编码格式&lt;/p&gt;
&lt;p&gt;另存为 ANSI 格式即可正常运行&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/03/JAVA%E4%BF%AE%E6%94%B9%E7%BC%96%E7%A0%81%E6%A0%BC%E5%BC%8F.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;安装eclipse&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#安装eclipse&#34;&gt;#&lt;/a&gt; 安装 Eclipse&lt;/h3&gt;
&lt;p&gt;任何东西只要娘化就会非常有趣，比如&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9temgubW9lZ2lybC5vcmcuY24vRWNsaXBzZSVFNSVBOCU5OA==&#34;&gt; Eclipse 娘&lt;/span&gt; 所以这才是程序员真正的快乐吗？&lt;/p&gt;
&lt;p&gt;具体的安装可以参考这个教程：&lt;/p&gt;
&lt;p&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly96aHVhbmxhbi56aGlodS5jb20vcC80MDc5NDgxMjU=&#34;&gt;Eclipse 安装使用教程！&lt;/span&gt;&lt;/p&gt;
&lt;h2 id=&#34;java基本语法&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#java基本语法&#34;&gt;#&lt;/a&gt; JAVA 基本语法&lt;/h2&gt;
&lt;h3 id=&#34;分隔符&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#分隔符&#34;&gt;#&lt;/a&gt; 分隔符&lt;/h3&gt;
&lt;p&gt;分号 (&amp;quot;；&amp;quot;)（英文）：语句结束标记，for 循环看分割不同成分 。&lt;/p&gt;
&lt;p&gt;圆点（“.”）：用于分割 “类” 中的函数，可以理解为 Python 里的 os.listdir 这段里圆点的作用 (调用 OS 模块里面的 listdir 函数)&lt;/p&gt;
&lt;p&gt;空格（&amp;quot; &amp;quot;）：分割源代码里的不同部分，例如 int a; int b;&lt;/p&gt;
&lt;p&gt;花括号（“}”）：用于限定某一部分的范围，成对使用&lt;/p&gt;
&lt;p&gt;例如：&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class Text &amp;#123;   &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;piblic static void main (String[]args)&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      System.out.println(&amp;quot;Hello&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;标识符&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#标识符&#34;&gt;#&lt;/a&gt; 标识符&lt;/h3&gt;
&lt;p&gt;起到表示作用的符号。(用来给类、对象、方法、变量、接口和自定义数据类型命名的。)&lt;/p&gt;
&lt;p&gt;命名规则：由数字，字母和下划线（_），美元符号（$）或人民币符号（￥）组成。&lt;/p&gt;
&lt;p&gt;例如:&lt;/p&gt;
&lt;p&gt;myName，My_name，Points，$points,_sys_ta，OK，_23b，_3_&lt;/p&gt;
&lt;p&gt;非法标识符:&lt;/p&gt;
&lt;p&gt;#name，25name，class，&amp;amp;time，if&lt;/p&gt;
&lt;h3 id=&#34;java关键字&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#java关键字&#34;&gt;#&lt;/a&gt; JAVA 关键字&lt;/h3&gt;
&lt;p&gt;Java 关键字类别&lt;/p&gt;
&lt;p&gt;Java 关键字&lt;/p&gt;
&lt;p&gt;关键字含义&lt;/p&gt;
&lt;p&gt;访问控制&lt;/p&gt;
&lt;p&gt;private&lt;/p&gt;
&lt;p&gt;一种访问控制方式：私用模式，访问控制修饰符，可以应用于类、方法或字段（在类中声明的变量）&lt;/p&gt;
&lt;p&gt;访问控制&lt;/p&gt;
&lt;p&gt;protected&lt;/p&gt;
&lt;p&gt;一种访问控制方式：保护模式，可以应用于类、方法或字段（在类中声明的变量）的访问控制修饰符&lt;/p&gt;
&lt;p&gt;访问控制&lt;/p&gt;
&lt;p&gt;public&lt;/p&gt;
&lt;p&gt;一种访问控制方式：共用模式，可以应用于类、方法或字段（在类中声明的变量）的访问控制修饰符。&lt;/p&gt;
&lt;p&gt;类、方法和变量修饰符&lt;/p&gt;
&lt;p&gt;abstract&lt;/p&gt;
&lt;p&gt;表明类或者成员方法具有抽象属性，用于修改类或方法&lt;/p&gt;
&lt;p&gt;类、方法和变量修饰符&lt;/p&gt;
&lt;p&gt;class&lt;/p&gt;
&lt;p&gt;声明一个类，用来声明新的 Java 类&lt;/p&gt;
&lt;p&gt;类、方法和变量修饰符&lt;/p&gt;
&lt;p&gt;extends&lt;/p&gt;
&lt;p&gt;表明一个类型是另一个类型的子类型。对于类，可以是另一个类或者抽象类；对于接口，可以是另一个接口&lt;/p&gt;
&lt;p&gt;类、方法和变量修饰符&lt;/p&gt;
&lt;p&gt;final&lt;/p&gt;
&lt;p&gt;用来说明最终属性，表明一个类不能派生出子类，或者成员方法不能被覆盖，或者成员域的值不能被改变，用来定义常量&lt;/p&gt;
&lt;p&gt;类、方法和变量修饰符&lt;/p&gt;
&lt;p&gt;implements&lt;/p&gt;
&lt;p&gt;表明一个类实现了给定的接口&lt;/p&gt;
&lt;p&gt;类、方法和变量修饰符&lt;/p&gt;
&lt;p&gt;interface&lt;/p&gt;
&lt;p&gt;接口&lt;/p&gt;
&lt;p&gt;类、方法和变量修饰符&lt;/p&gt;
&lt;p&gt;native&lt;/p&gt;
&lt;p&gt;用来声明一个方法是由与计算机相关的语言（如 C/C++/FORTRAN 语言）实现的&lt;/p&gt;
&lt;p&gt;类、方法和变量修饰符&lt;/p&gt;
&lt;p&gt;new&lt;/p&gt;
&lt;p&gt;用来创建新实例对象&lt;/p&gt;
&lt;p&gt;类、方法和变量修饰符&lt;/p&gt;
&lt;p&gt;static&lt;/p&gt;
&lt;p&gt;表明具有静态属性&lt;/p&gt;
&lt;p&gt;类、方法和变量修饰符&lt;/p&gt;
&lt;p&gt;strictfp&lt;/p&gt;
&lt;p&gt;用来声明 FP_strict（单精度或双精度浮点数）表达式遵循 IEEE 754 算术规范&lt;/p&gt;
&lt;p&gt;类、方法和变量修饰符&lt;/p&gt;
&lt;p&gt;synchronized&lt;/p&gt;
&lt;p&gt;表明一段代码需要同步执行&lt;/p&gt;
&lt;p&gt;类、方法和变量修饰符&lt;/p&gt;
&lt;p&gt;transient&lt;/p&gt;
&lt;p&gt;声明不用序列化的成员域&lt;/p&gt;
&lt;p&gt;类、方法和变量修饰符&lt;/p&gt;
&lt;p&gt;volatile&lt;/p&gt;
&lt;p&gt;表明两个或者多个变量必须同步地发生变化&lt;/p&gt;
&lt;p&gt;程序控制&lt;/p&gt;
&lt;p&gt;break&lt;/p&gt;
&lt;p&gt;提前跳出一个块&lt;/p&gt;
&lt;p&gt;程序控制&lt;/p&gt;
&lt;p&gt;continue&lt;/p&gt;
&lt;p&gt;回到一个块的开始处&lt;/p&gt;
&lt;p&gt;程序控制&lt;/p&gt;
&lt;p&gt;return&lt;/p&gt;
&lt;p&gt;从成员方法中返回数据&lt;/p&gt;
&lt;p&gt;程序控制&lt;/p&gt;
&lt;p&gt;do&lt;/p&gt;
&lt;p&gt;用在 do-while 循环结构中&lt;/p&gt;
&lt;p&gt;程序控制&lt;/p&gt;
&lt;p&gt;while&lt;/p&gt;
&lt;p&gt;用在循环结构中&lt;/p&gt;
&lt;p&gt;程序控制&lt;/p&gt;
&lt;p&gt;if&lt;/p&gt;
&lt;p&gt;条件语句的引导词&lt;/p&gt;
&lt;p&gt;程序控制&lt;/p&gt;
&lt;p&gt;else&lt;/p&gt;
&lt;p&gt;用在条件语句中，表明当条件不成立时的分支&lt;/p&gt;
&lt;p&gt;程序控制&lt;/p&gt;
&lt;p&gt;for&lt;/p&gt;
&lt;p&gt;一种循环结构的引导词&lt;/p&gt;
&lt;p&gt;程序控制&lt;/p&gt;
&lt;p&gt;instanceof&lt;/p&gt;
&lt;p&gt;用来测试一个对象是否是指定类型的实例对象&lt;/p&gt;
&lt;p&gt;程序控制&lt;/p&gt;
&lt;p&gt;switch&lt;/p&gt;
&lt;p&gt;分支语句结构的引导词&lt;/p&gt;
&lt;p&gt;程序控制&lt;/p&gt;
&lt;p&gt;case&lt;/p&gt;
&lt;p&gt;用在 switch 语句之中，表示其中的一个分支&lt;/p&gt;
&lt;p&gt;程序控制&lt;/p&gt;
&lt;p&gt;default&lt;/p&gt;
&lt;p&gt;默认，例如：用在 switch 语句中，表明一个默认的分支。Java8 中也作用于声明接口函数的默认实现&lt;/p&gt;
&lt;p&gt;错误处理&lt;/p&gt;
&lt;p&gt;try&lt;/p&gt;
&lt;p&gt;尝试一个可能抛出异常的程序块&lt;/p&gt;
&lt;p&gt;错误处理&lt;/p&gt;
&lt;p&gt;catch&lt;/p&gt;
&lt;p&gt;用在异常处理中，用来捕捉异常&lt;/p&gt;
&lt;p&gt;错误处理&lt;/p&gt;
&lt;p&gt;throw&lt;/p&gt;
&lt;p&gt;抛出一个异常&lt;/p&gt;
&lt;p&gt;错误处理&lt;/p&gt;
&lt;p&gt;throws&lt;/p&gt;
&lt;p&gt;声明在当前定义的成员方法中所有需要抛出的异常&lt;/p&gt;
&lt;p&gt;包相关&lt;/p&gt;
&lt;p&gt;import&lt;/p&gt;
&lt;p&gt;表明要访问指定的类或包&lt;/p&gt;
&lt;p&gt;包相关&lt;/p&gt;
&lt;p&gt;package&lt;/p&gt;
&lt;p&gt;包&lt;/p&gt;
&lt;p&gt;基本类型&lt;/p&gt;
&lt;p&gt;boolean&lt;/p&gt;
&lt;p&gt;基本数据类型之一，声明布尔类型的关键字&lt;/p&gt;
&lt;p&gt;基本类型&lt;/p&gt;
&lt;p&gt;byte&lt;/p&gt;
&lt;p&gt;基本数据类型之一，字节类型&lt;/p&gt;
&lt;p&gt;基本类型&lt;/p&gt;
&lt;p&gt;char&lt;/p&gt;
&lt;p&gt;基本数据类型之一，字符类型&lt;/p&gt;
&lt;p&gt;基本类型&lt;/p&gt;
&lt;p&gt;double&lt;/p&gt;
&lt;p&gt;基本数据类型之一，双精度浮点数类型&lt;/p&gt;
&lt;p&gt;基本类型&lt;/p&gt;
&lt;p&gt;float&lt;/p&gt;
&lt;p&gt;基本数据类型之一，单精度浮点数类型&lt;/p&gt;
&lt;p&gt;基本类型&lt;/p&gt;
&lt;p&gt;int&lt;/p&gt;
&lt;p&gt;基本数据类型之一，整数类型&lt;/p&gt;
&lt;p&gt;基本类型&lt;/p&gt;
&lt;p&gt;long&lt;/p&gt;
&lt;p&gt;基本数据类型之一，长整数类型&lt;/p&gt;
&lt;p&gt;基本类型&lt;/p&gt;
&lt;p&gt;short&lt;/p&gt;
&lt;p&gt;基本数据类型之一，短整数类型&lt;/p&gt;
&lt;p&gt;基本类型&lt;/p&gt;
&lt;p&gt;null&lt;/p&gt;
&lt;p&gt;空，表示无值，不能将 null 赋给原始类型（byte、short、int、long、char、float、double、boolean）变量&lt;/p&gt;
&lt;p&gt;基本类型&lt;/p&gt;
&lt;p&gt;true&lt;/p&gt;
&lt;p&gt;真，boolean 变量的两个合法值中的一个&lt;/p&gt;
&lt;p&gt;基本类型&lt;/p&gt;
&lt;p&gt;false&lt;/p&gt;
&lt;p&gt;假，boolean 变量的两个合法值之一&lt;/p&gt;
&lt;p&gt;变量引用&lt;/p&gt;
&lt;p&gt;super&lt;/p&gt;
&lt;p&gt;表明当前对象的父类型的引用或者父类型的构造方法&lt;/p&gt;
&lt;p&gt;变量引用&lt;/p&gt;
&lt;p&gt;this&lt;/p&gt;
&lt;p&gt;指向当前实例对象的引用，用于引用当前实例&lt;/p&gt;
&lt;p&gt;变量引用&lt;/p&gt;
&lt;p&gt;void&lt;/p&gt;
&lt;p&gt;声明当前成员方法没有返回值，void 可以用作方法的返回类型，以指示该方法不返回值&lt;/p&gt;
&lt;p&gt;保留字&lt;/p&gt;
&lt;p&gt;goto&lt;/p&gt;
&lt;p&gt;保留关键字，没有具体含义&lt;/p&gt;
&lt;p&gt;保留字&lt;/p&gt;
&lt;p&gt;const&lt;/p&gt;
&lt;p&gt;保留关键字，没有具体含义，是一个类型修饰符，使用 const 声明的对象不能更新&lt;/p&gt;
&lt;p&gt;JAVA 关键字&lt;/p&gt;
&lt;p&gt;上表转自此&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9kZXZlbG9wZXIuYWxpeXVuLmNvbS9hcnRpY2xlLzc1MzY5OQ==&#34;&gt;帖子&lt;/span&gt;&lt;/p&gt;
&lt;h3 id=&#34;注释&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#注释&#34;&gt;#&lt;/a&gt; 注释&lt;/h3&gt;
&lt;p&gt;单行注释&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class Text&amp;#123; //这是单行注释&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;多行注释&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class Text&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static viod main (String[]args)&amp;#123;/*这是多行注释&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;这是多行注释*/&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        System.out.println(&amp;quot;hello,world&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;文档注释&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;/**&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;这是文档注释&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;这是文档注释&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;*/&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;public class HelloWorld&amp;#123;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;public static void main(String[]args)&amp;#123;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;System.out.println(&amp;quot;hello,world&amp;quot;); &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;java数据类型&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#java数据类型&#34;&gt;#&lt;/a&gt; JAVA 数据类型&lt;/h2&gt;
&lt;h3 id=&#34;基本数据类型&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#基本数据类型&#34;&gt;#&lt;/a&gt; 基本数据类型&lt;/h3&gt;
&lt;h4 id=&#34;整型&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#整型&#34;&gt;#&lt;/a&gt; 整型&lt;/h4&gt;
&lt;p&gt;byte , short , int , log&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;//整型&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;int a = 1 ; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;byte b = 2 ; // 最大表示到127&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;short c = 3 ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;long d = 4 ;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;浮点型&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#浮点型&#34;&gt;#&lt;/a&gt; 浮点型&lt;/h4&gt;
&lt;p&gt;float , double&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;//浮点型&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;double e = 0.1; //双精度浮点型&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;float f = 0.2f ; //单精度浮点型&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;double e1 = 0.1d;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;[collapse title=“在 JAVA 中，如果定义 float 类型，需要后面加个 f，否则会默认转化为 double 类型”] 或者直接定义为 double 也可以 [/collapse]&lt;/p&gt;
&lt;p&gt;定义 double 可以加 d, 例如 double a = 0.455d&lt;/p&gt;
&lt;h4 id=&#34;字符型&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#字符型&#34;&gt;#&lt;/a&gt; 字符型&lt;/h4&gt;
&lt;p&gt;char 型，&lt;strong&gt;单个符号&lt;/strong&gt;，需要用&lt;strong&gt;单引号&lt;/strong&gt;引起来&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;//字符型&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;char c1 = &amp;#x27;R&amp;#x27;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;char c2 = &amp;#x27;T&amp;#x27;;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;如果使用字符串 String，不会报错，但是不会输出 (&lt;strong&gt;String 数据类型是引用数据类型)&lt;/strong&gt;。&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;String A = &amp;quot;String&amp;quot; //字符串,记得用双引号引起来&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;在 JAVA 中，字符可以定义成为字符串，整体的字符有些可以定义成字符，例如换行符 “\n”&lt;/p&gt;
&lt;h4 id=&#34;布尔类型&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#布尔类型&#34;&gt;#&lt;/a&gt; 布尔类型&lt;/h4&gt;
&lt;p&gt;true 和 false&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;boolean b1 = true ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;boolean b2 = false ;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;代码表示&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#代码表示&#34;&gt;#&lt;/a&gt; 代码表示&lt;/h4&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;//整型&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;int a = 1 ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;byte b = 2 ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;short c = 3 ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;long d = 4 ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;//浮点型&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;double e = 0.1;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;float f = 0.2f ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;//在JAVA中，如果定义float类型，需要后面加个f，否则会默认转化为double类型&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;//字符型&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;char g = &amp;#x27;G&amp;#x27;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;//布尔型&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;boolean h = true;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;//字符串&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;String i = &amp;quot;Hedio_Kojima&amp;quot; &lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;引用数据类型&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#引用数据类型&#34;&gt;#&lt;/a&gt; 引用数据类型&lt;/h3&gt;
&lt;h4 id=&#34;类对象&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#类对象&#34;&gt;#&lt;/a&gt; 类（对象）&lt;/h4&gt;
&lt;h4 id=&#34;接口&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#接口&#34;&gt;#&lt;/a&gt; 接口&lt;/h4&gt;
&lt;h4 id=&#34;数组&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#数组&#34;&gt;#&lt;/a&gt; 数组&lt;/h4&gt;
&lt;h2 id=&#34;常量和变量&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#常量和变量&#34;&gt;#&lt;/a&gt; 常量和变量&lt;/h2&gt;
&lt;h3 id=&#34;常量&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#常量&#34;&gt;#&lt;/a&gt; 常量&lt;/h3&gt;
&lt;p&gt;常量值又称为字面常量，它是通过数据直接表示的，因此有很多种数据类型，像整型和字符串型等。&lt;/p&gt;
&lt;h4 id=&#34;整型常量&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#整型常量&#34;&gt;#&lt;/a&gt; 整型常量&lt;/h4&gt;
&lt;p&gt;整型常量是整数类型的数据。它的表现有四种：&lt;/p&gt;
&lt;p&gt;二进制，八进制，十进制，十六进制&lt;/p&gt;
&lt;p&gt;例如:&lt;/p&gt;
&lt;p&gt;二进制&lt;/p&gt;
&lt;p&gt;1111&lt;/p&gt;
&lt;p&gt;八进制&lt;/p&gt;
&lt;p&gt;17&lt;/p&gt;
&lt;p&gt;十进制&lt;/p&gt;
&lt;p&gt;15&lt;/p&gt;
&lt;p&gt;十六进制&lt;/p&gt;
&lt;p&gt;f&lt;/p&gt;
&lt;p&gt;整型常量&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;int i1 = 012 ; //八进制常量，以0开始&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;int i2 = 0x12 ; //十六进制常量，以0x开始&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;int i3 = 10 ; // 十进制常量，以0开始&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h4 id=&#34;浮点数常量&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#浮点数常量&#34;&gt;#&lt;/a&gt; 浮点数常量&lt;/h4&gt;
&lt;p&gt;浮点数常量就是在数学中用到的小数。分为单浮点 (float) 和双浮点 (double)。&lt;/p&gt;
&lt;p&gt;例如&lt;/p&gt;
&lt;p&gt;0.2233f&lt;/p&gt;
&lt;p&gt;0.2333d&lt;/p&gt;
&lt;h4 id=&#34;布尔常量&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#布尔常量&#34;&gt;#&lt;/a&gt; 布尔常量&lt;/h4&gt;
&lt;p&gt;只有两个值， ture (真) 和 false (假)&lt;/p&gt;
&lt;h4 id=&#34;字符常量&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#字符常量&#34;&gt;#&lt;/a&gt; 字符常量&lt;/h4&gt;
&lt;p&gt;字符型常量值是用&lt;strong&gt;单引号&lt;/strong&gt;引起来的一个字符，例如 ‘e’ , ‘a’ , ‘E’。&lt;/p&gt;
&lt;p&gt;与 Python 不同的是，JAVA 里的单引号和双引号不能混用，双引号是用来表示字符串的&lt;/p&gt;
&lt;h3 id=&#34;变量&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#变量&#34;&gt;#&lt;/a&gt; 变量&lt;/h3&gt;
&lt;h4 id=&#34;变量的声明&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#变量的声明&#34;&gt;#&lt;/a&gt; 变量的声明&lt;/h4&gt;
&lt;h5 id=&#34;格式&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#格式&#34;&gt;#&lt;/a&gt; 格式&lt;/h5&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;//数据类型 变量名 = 初值&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;int a = 234&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;其中：&lt;/p&gt;
&lt;p&gt;int 是数据类型，&lt;/p&gt;
&lt;p&gt;a 是变量名，&lt;/p&gt;
&lt;p&gt;234　为　初值&lt;/p&gt;
&lt;h4 id=&#34;作用域&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#作用域&#34;&gt;#&lt;/a&gt; 作用域&lt;/h4&gt;
&lt;p&gt;也称变量的作用范围，即一个变量在多大的范围内可以使用。&lt;/p&gt;
&lt;h5 id=&#34;类变量&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#类变量&#34;&gt;#&lt;/a&gt; 类变量&lt;/h5&gt;
&lt;p&gt;独立于方法之外的变量，用 static 修饰。&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class LBL &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    static int p=100;  //类变量&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    System.out.println(p);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;实例变量&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#实例变量&#34;&gt;#&lt;/a&gt; 实例变量&lt;/h5&gt;
&lt;p&gt;独立于方法之外的变量，不过没有 static 修饰。&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class LBL &amp;#123;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;     String p=&amp;quot;hello world&amp;quot;;  // 实例变量    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;     public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    System.out.println(p);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;局部变量&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#局部变量&#34;&gt;#&lt;/a&gt; 局部变量&lt;/h5&gt;
&lt;p&gt;类的方法中的变量.&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class LBL &amp;#123;      &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static void main(String[] args) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    int p = 123 ;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    System.out.println(p);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h5 id=&#34;相对关系&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#相对关系&#34;&gt;#&lt;/a&gt; 相对关系&lt;/h5&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;public class Text&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    static int p1=0;    // 类变量&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    String p2=&amp;quot;hello world&amp;quot;;  // 实例变量&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;   public void method()&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        int p3 =0;  // 局部变量&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

 &lt;p&gt;假期闲来无事，与其虚度，不如做点事干 你信吗？我不信 (￣ε(#￣)☆╰╮o (￣皿￣///)。于是就买了个开发板，正好借此学一学 C 语言。&lt;/p&gt;
&lt;p&gt;于是，就立马买了需要的东西，清单如下：&lt;/p&gt;
&lt;p&gt;物品&lt;/p&gt;
&lt;p&gt;价格（元）&lt;/p&gt;
&lt;p&gt;数量&lt;/p&gt;
&lt;p&gt;备注&lt;/p&gt;
&lt;p&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9pdGVtLnRhb2Jhby5jb20vaXRlbS5odG0/c3BtPWExejA5LjIuMC4wLjQxMzIyZThkdjNUTHZCJmFtcDtpZD01NDQ4MzEwMjM3MTAmYW1wO191PXYyMGFyYjE5a21mNTI5&#34;&gt;Esp32 DevKit v1 30pin 开发板&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;21.5&lt;/p&gt;
&lt;p&gt;1&lt;/p&gt;
&lt;p&gt;有 36pin 的版本&lt;/p&gt;
&lt;p&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9pdGVtLnRhb2Jhby5jb20vaXRlbS5odG0/c3BtPWExejA5LjIuMC4wLjQxMzIyZThkdjNUTHZCJmFtcDtpZD01NTgxODI3NjE5NTgmYW1wO191PXYyMGFyYjE5a20yYTQ1&#34;&gt;40P 彩排杜邦线&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;2.81&lt;/p&gt;
&lt;p&gt;1&lt;/p&gt;
&lt;p&gt;母对母&lt;/p&gt;
&lt;p&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9pdGVtLnRhb2Jhby5jb20vaXRlbS5odG0/c3BtPWExejA5LjIuMC4wLjQxMzIyZThkdjNUTHZCJmFtcDtpZD01NzE0MDk5NTc2MjImYW1wO191PXYyMGFyYjE5a202Nzc5&#34;&gt;1.8 寸 彩色 TFT 屏幕&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;20&lt;/p&gt;
&lt;p&gt;1&lt;/p&gt;
&lt;p&gt;不带触摸&lt;/p&gt;
&lt;p&gt;开发板连接线&lt;/p&gt;
&lt;p&gt;0&lt;/p&gt;
&lt;p&gt;1&lt;/p&gt;
&lt;p&gt;家里找的&lt;/p&gt;
&lt;p&gt;物品清单&lt;/p&gt;
&lt;p&gt;[buy] 我买的屏幕型号是 MSP1803，需要连接背光才能显示 [/buy]&lt;/p&gt;
&lt;p&gt;一共 44.31 块，还行吧。&lt;/p&gt;
&lt;p&gt;之后就找了个&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cuYmlsaWJpbGkuY29tL3ZpZGVvL0JWMUM1NHkxRTcyZT9zaGFyZV9zb3VyY2U9Y29weV93ZWI=&#34;&gt;做小电视的视频&lt;/span&gt;就开始学了。&lt;/p&gt;
&lt;p&gt;然后我懵了，我没学过单片机，大一只学过 Python 和 HTML 入门，我看不懂商家给的资料，也看不懂&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9zcGFjZS5iaWxpYmlsaS5jb20vMjcwODc1NTY0P3NwbV9pZF9mcm9tPTMzMy43ODguYl83NjVmNzU3MDY5NmU2NjZmLjI=&#34;&gt; UP&lt;/span&gt; 给的教程。&lt;/p&gt;
&lt;p&gt;然后鼓捣了好久。玩了好久，才想起来有个单片机。&lt;/p&gt;
&lt;p&gt;现在才整的有些样子，现在基本完成了，那么我就把我一路上踩过的坑说一下。&lt;/p&gt;
&lt;h3 id=&#34;获取chip-id报错&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#获取chip-id报错&#34;&gt;#&lt;/a&gt; 获取 Chip ID 报错&lt;/h3&gt;
&lt;p&gt;报错显示 “exec: ‘cmd’: executable file not found in % PATH% 为开发板 ESP32 Dev Module 编译时出错。”&lt;/p&gt;
&lt;p&gt;提示没有配置环境变量，配置完成，问题解决。&lt;/p&gt;
&lt;h2 id=&#34;屏幕显示问题&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#屏幕显示问题&#34;&gt;#&lt;/a&gt; 屏幕显示问题&lt;/h2&gt;
&lt;h3 id=&#34;屏幕不显示&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#屏幕不显示&#34;&gt;#&lt;/a&gt; 屏幕不显示&lt;/h3&gt;
&lt;p&gt;检查自己的屏幕，教程里面是不接背光的，可以烧录进去，然后接背光试试。我今天 (2022.2.12) 才发现我的屏幕是一定要接背光的，我还搞了好久。&lt;/p&gt;
&lt;h3 id=&#34;图片显示不正常且有小部分花屏&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#图片显示不正常且有小部分花屏&#34;&gt;#&lt;/a&gt; 图片显示不正常，且有小部分花屏&lt;/h3&gt;
&lt;p&gt;有的人可能烧录进去以后发现屏幕是这个样子：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/02/IMG20220212145658-768x1024.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;图片显示非常不正常，还有花屏的情况。&lt;/p&gt;
&lt;p&gt;根据这个&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L3FxXzM5NDM3MDYyL2FydGljbGUvZGV0YWlscy85OTMwOTk2Mg==&#34;&gt;帖子&lt;/span&gt;的说法，是设计问题，可以通过切换配置文件的参数解决 。解决方法来自这个&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L3dlaXhpbl80MjEyOTYwNS9hcnRpY2xlL2RldGFpbHMvMTE3MjYzMDkx&#34;&gt;帖子&lt;/span&gt;。&lt;/p&gt;
&lt;p&gt;按照这样的路径（.\arduino\arduino-nightly\hardware\espressif\esp32\libraries\TFT_eSPI）打开 TFT_eSPI, 找到 User_Setup.h，打开。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/02/image-30.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;找到这样的地方，并且把原来的 #define ST7735_GREENTAB2 注释掉，把 #define ST7735_REDTAB 解除注释，就显示正常了。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/02/%E5%B1%8F%E5%B9%95%E6%88%AA%E5%9B%BE-2022-02-12-163850-1024x382.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;[buy] 此方法选择的参数有可能其他屏幕无效，可以在几个参数切换试试看 [/buy]&lt;/p&gt;
&lt;p&gt;然后重新烧录进去程序。&lt;/p&gt;
&lt;p&gt;这样就显示正常了。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/02/IMG20220212163348-768x1024.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;色彩显示错误&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#色彩显示错误&#34;&gt;#&lt;/a&gt; 色彩显示错误&lt;/h3&gt;
&lt;p&gt;烧录进去了程序，有可能出现这样的情况：本该显示蓝色的地方显示了黄色。这是因为 UP 的程序里使用的是 BGR, 而你的屏幕是 RGB, 这样导致的色彩问题。&lt;/p&gt;
&lt;p&gt;解决办法：&lt;/p&gt;
&lt;p&gt;按照这样的路径（.\arduino\arduino-nightly\hardware\espressif\esp32\libraries\TFT_eSPI）打开 TFT_eSPI, 找到 User_Setup.h，打开。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/02/image-30.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;找到 #define TFT_RGB_ORDER TFT_BGR 这样的一行，将其注释掉，启用上面的 define TFT_RGB_ORDER TFT_RGB。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/02/%E5%B1%8F%E5%B9%95%E6%88%AA%E5%9B%BE-2022-02-12-164705.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;完成以后就是这样子&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/02/IMG20220212162216-scaled-e1644656696916-768x1024.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;显示不全&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#显示不全&#34;&gt;#&lt;/a&gt; 显示不全&lt;/h3&gt;
&lt;p&gt;UP 的代码烧录进去以后会发现有个问题，就是在天气页面，如果显示三个字的地名或者显示风向为 “东北风‘的时候会显示不全，这时候就要调整一下显示的位置：&lt;/p&gt;
&lt;p&gt;我这里把调好的放在下面&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;/*******************天气界面显示****************/&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;void show_weather(uint16_t fg,uint16_t bg)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    tft.setSwapBytes(true);             //使图片颜色由RGB-&amp;gt;BGR&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    tft.pushImage(0, 0,  64, 64, weather[ph]);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    showMyFonts(75, 25, now_address.c_str(), TFT_WHITE);//因为图片大小的限制，如果是四个字的地名的话需要调整图片大小，还有本行调小X轴数值（数字75所在的位置）&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    showMyFonts(75, 45, now_wea, TFT_WHITE);//天气&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    tft.pushImage(0 , 65, 30, 30, temIcon);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    tft.pushImage(0, 95, 30, 30, humIcon);;//湿度&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    tft.pushImage(50, 65, 30, 30, rainIcon);//雨&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    tft.pushImage(45, 95, 30, 30, windIcon);//风&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    showtext(25,75,1,1,fg,bg,now_high_tem + &amp;quot;/&amp;quot; + now_low_tem);//低温高温&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;     showtext(25,75,1,1,fg,bg,now_high_tem + &amp;quot;/&amp;quot; + now_low_tem);//低温高温&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    showtext(85,75,1,1,fg,bg,now_rainfall +&amp;quot;mm&amp;quot;);//降水量&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    showtext(25,105,1,1,fg,bg,now_hum+&amp;quot;%&amp;quot;);//湿度&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    String now_wind = now_wind_direction + &amp;quot;风&amp;quot;;//什么风&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    showMyFonts(75, 100, now_wind.c_str(), TFT_WHITE);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    get_weather();// 再次运行获取天气的函数，保证天气更新&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2 id=&#34;接线问题&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#接线问题&#34;&gt;#&lt;/a&gt; 接线问题&lt;/h2&gt;
&lt;p&gt;A0 接那里？&lt;/p&gt;
&lt;p&gt;可以接到 DC 的引脚那里，性质相同 数据选择功能&lt;/p&gt;
&lt;p&gt;其他的引脚接哪里？以我的为例。&lt;/p&gt;
&lt;p&gt;屏幕引脚标注&lt;/p&gt;
&lt;p&gt;开发板引脚标注&lt;/p&gt;
&lt;p&gt;功能&lt;/p&gt;
&lt;p&gt;VCC&lt;/p&gt;
&lt;p&gt;VIN&lt;/p&gt;
&lt;p&gt;电源正极&lt;/p&gt;
&lt;p&gt;GND&lt;/p&gt;
&lt;p&gt;GND&lt;/p&gt;
&lt;p&gt;电源地&lt;/p&gt;
&lt;p&gt;CS&lt;/p&gt;
&lt;p&gt;D27&lt;/p&gt;
&lt;p&gt;片选信号&lt;/p&gt;
&lt;p&gt;RESET&lt;/p&gt;
&lt;p&gt;D26&lt;/p&gt;
&lt;p&gt;复位信号&lt;/p&gt;
&lt;p&gt;A0(DC)&lt;/p&gt;
&lt;p&gt;D25&lt;/p&gt;
&lt;p&gt;寄存器 /&lt;br&gt;
 数据选择信号&lt;/p&gt;
&lt;p&gt;SDA&lt;/p&gt;
&lt;p&gt;D23&lt;/p&gt;
&lt;p&gt;SPI 总线写数据信号&lt;/p&gt;
&lt;p&gt;SCK&lt;/p&gt;
&lt;p&gt;D18&lt;/p&gt;
&lt;p&gt;SPI 总线时钟信号&lt;/p&gt;
&lt;p&gt;LED&lt;/p&gt;
&lt;p&gt;3V3&lt;/p&gt;
&lt;p&gt;背光&lt;br&gt;
（无需控制接 3V3）&lt;/p&gt;
&lt;p&gt;引脚连接 + 功能&lt;/p&gt;
&lt;h2 id=&#34;其他&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#其他&#34;&gt;#&lt;/a&gt; 其他&lt;/h2&gt;
&lt;p&gt;1.8 寸的 TFT 屏幕，型号是 MSP1803 的相关的资料：&lt;/p&gt;
&lt;p&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cDovL3d3dy5sY2R3aWtpLmNvbS9yZXMvTVNQMTgwMy8xLjhpbmNoX1NQSV9Nb2R1bGVfTVNQMTgwM19Vc2VyX01hbnVhbF9DTi5wZGY=&#34;&gt;http://www.lcdwiki.com/res/MSP1803/1.8inch_SPI_Module_MSP1803_User_Manual_CN.pdf&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;30 引脚的 DOIT Esp32 Dev Kit v1 开发板的引脚图，可以参考下：&lt;/p&gt;
&lt;p&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cuZWxlY3Ryb25pY3NodWIub3JnL2VzcDMyLXBpbm91dC8=&#34;&gt;https://www.electronicshub.org/esp32-pinout/&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;Esp32 DevKit v1 的 30 引脚和 36 引脚的对比：&lt;/p&gt;
&lt;p&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9jbG91ZC50ZW5jZW50LmNvbS9kZXZlbG9wZXIvYXJ0aWNsZS8xNzQ5MDMy&#34;&gt;https://cloud.tencent.com/developer/article/1749032&lt;/span&gt;&lt;/p&gt;

 &lt;p&gt;Pyinstaller 是可以把 Python 工程打包成为 exe 的一个 Python 模块。网上教程有很多，但是我在使用的时候会遇到很多问题，进而搜索大量网页，非常麻烦。所以准备写一篇文章把我碰到的一些问题整合起来，这样的话免去去查找大量网站的烦恼。&lt;/p&gt;
&lt;h3 id=&#34;1如何安装pyinstaller&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1如何安装pyinstaller&#34;&gt;#&lt;/a&gt; 1. 如何安装 Pyinstaller&lt;/h3&gt;
&lt;p&gt;最简单的方法就是打开 Win+R 输入 cmd，打开 cmd 窗口输入&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;pip install pyinstaller&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;但是，&lt;/p&gt;
&lt;p&gt;有的时候你安装好了 Python，用 pip 安装的时候会出现这个问题：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/02/image-17.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;这个就说明 Python 的环境变量没有配置好，需要配置下，这时候需要找到 Python 安装目录下的 Scripts 文件夹，像我的就是 C:\Users\111\AppData\Local\Programs\Python\Python311\Scripts&lt;/p&gt;
&lt;p&gt;确认文件夹下有没有 pip.exe, 如下图：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/02/image-18.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;如果有的话，把文件夹路径复制下来，然后就去 “环境变量” 那里找到 path 变量，添加地址保存即可&lt;/p&gt;
&lt;p&gt;配置完成后记得重新打开 CMD 安装窗&lt;/p&gt;
&lt;p&gt;如何找到环境变量，请在这个&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9uZXcucXEuY29tL29tbi8yMDIxMTIwMi8yMDIxMTIwMkEwOENDVzAwLmh0bWw=&#34;&gt;帖子&lt;/span&gt;查看。&lt;/p&gt;
&lt;p&gt;如果出现这个了，说明正在安装了&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/02/image-19.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;最后显示这个，就说明成功安装了&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/02/image-21-1024x64.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;如果出现这个了，说明要升级 pip&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/02/image-20-1024x67.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;直接输入下面这个就可以了。&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;python -m pip install --upgrade pip&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h3 id=&#34;2用pyinstaller打包&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2用pyinstaller打包&#34;&gt;#&lt;/a&gt; 2. 用 Pyinstaller 打包&lt;/h3&gt;
&lt;p&gt;Pyinstaller 主要语法就是：Pyinstaller + 指令 + Python 文件&lt;/p&gt;
&lt;p&gt;下面就是些常用的指令：&lt;/p&gt;
&lt;p&gt;-F，-onefile&lt;/p&gt;
&lt;p&gt;产生单个的可执行文件&lt;/p&gt;
&lt;p&gt;-D，–onedir&lt;/p&gt;
&lt;p&gt;产生一个目录（包含多个文件）作为可执行程序&lt;/p&gt;
&lt;p&gt;-a，–ascii&lt;/p&gt;
&lt;p&gt;不包含 Unicode 字符集支持&lt;/p&gt;
&lt;p&gt;-d，–debug&lt;/p&gt;
&lt;p&gt;产生 debug 版本的可执行文件&lt;/p&gt;
&lt;p&gt;-w，–windowed，–noconsolc&lt;/p&gt;
&lt;p&gt;指定程序运行时不显示命令行窗口（仅对 Windows 有效）&lt;/p&gt;
&lt;p&gt;-c，–nowindowed，–console&lt;/p&gt;
&lt;p&gt;指定使用命令行窗口运行程序（仅对 Windows 有效）&lt;/p&gt;
&lt;p&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cDovL2MuYmlhbmNoZW5nLm5ldC92aWV3LzI2OTAuaHRtbA==&#34;&gt;上表来源&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;然后就可以在 cmd 窗口输入指令来打包了，打包的时候记得转到文件所在的文件夹&lt;/p&gt;
&lt;p&gt;转到要打包的 Python 所在的文件夹，可以使用 cd + 空格 + 文件夹地址来实现&lt;/p&gt;
&lt;p&gt;这样就说明打包成功了&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/02/image-24.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;其中这个&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/02/image-23.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;是最后 exe 文件输出的地址&lt;/p&gt;
&lt;p&gt;还要这个&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/02/image-24.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;说明已经打包成为 exe 文件了&lt;/p&gt;
&lt;p&gt;之后就可以使用了，不需要再搭建 Python 环境了&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/02/image-26.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;如果打包完成发现窗口一闪而过，可以试试在代码末尾加一个 input ()&lt;/p&gt;
&lt;p&gt;像这样&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/02/image-25.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;还有个缺少一些文件产生的问题，我自己重新打包的时候发现并没有碰到，测试了下发现无法复现，只好作罢。只记得那个要在 Pyinstaller -F 后面加一串来着。&lt;/p&gt;
&lt;h3 id=&#34;3日后谈&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#3日后谈&#34;&gt;#&lt;/a&gt; 3. 日后谈&lt;/h3&gt;
&lt;p&gt;有些问题我当时使用的时候碰到了，现在没法复现，我自己也无法找到当时找的帖子了，有不少疏忽非常抱歉。(之后要是接着更新也说不定)&lt;/p&gt;
&lt;p&gt;如有建议，欢迎留言，本人必洗耳恭听。&lt;/p&gt;

 &lt;h2 id=&#34;青年人的阅读&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#青年人的阅读&#34;&gt;#&lt;/a&gt; 青年人的阅读&lt;/h2&gt;
&lt;p&gt;余秋雨 著&lt;/p&gt;
&lt;p&gt;“生命的质量需要锻铸，阅读是锻铸的重要一环”。余秋雨将阅读看得如此重要。对此，他自有自己的心得体会，听听他的读书建议，相信对我们会有所裨益。这是余秋雨 1997 年在台湾的演讲的一部分。&lt;/p&gt;
&lt;p&gt;一个人的最佳读书状态大多产生在中年以后，但能不能取得这种状态则取决于青年时期的准备。&lt;/p&gt;
&lt;p&gt;中年以后的读书可以随心所欲，而在青年时期却不能过于随意，需要接受一些过来人的指点。&lt;/p&gt;
&lt;h3 id=&#34;一-尽早把阅读当作一件人生大事&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#一-尽早把阅读当作一件人生大事&#34;&gt;#&lt;/a&gt; 一、尽早把阅读当作一件人生大事&lt;/h3&gt;
&lt;p&gt;阅读的最大理由是想摆脱平庸。一个人如果在青年时期就开始平庸，那么今后要摆脱平庸就十分困难。&lt;/p&gt;
&lt;p&gt;何谓平庸？平庸是一种被动而又功利的谋生态度。平庸者什么也不缺少，只是无感于外部世界的精彩，人类历史的厚重，终极道义的神圣，生命涵义的丰富。而他们失去的这一切，光凭一个人有限的人生经历是无法获得的，因此平庸的队伍总是相当庞大。黄山谷说过：“人胸中久不用古今浇灌，则尘俗生其间。照镜觉面目可憎，对人亦语言无味。” 这就是平庸的写照。黄山谷认为要摆脱平庸，就要 “用古今浇灌”。&lt;/p&gt;
&lt;p&gt;只有书籍，能把辽阔的空间和漫长的时间浇灌给你，能把一切高贵生命早已飘散的信号传递给你，能把无数的智慧和美好对比着愚昧和丑陋一起呈现给你。区区五尺之躯，短短几十年光阴，居然能驰骋古今。经天纬地，这种奇迹的产生，至少有一半要归功于阅读。&lt;/p&gt;
&lt;p&gt;如此好事，如果等到成年后再来匆匆弥补就有点可惜了，最好在青年时就进入。早一天，就多一分人生的精彩；迟一天，就多一天平庸的困扰。&lt;/p&gt;
&lt;p&gt;青年人稚嫩的目光常常产生偏差，误以为是出身、财富、文凭、机运使有的人超乎一般，其实历尽沧桑的成年人都知道，最重要的是自身生命的质量，生命的质量需要锻铸，阅读是锻铸的重要一环。&lt;/p&gt;
&lt;h3 id=&#34;二-要把阅读范围延伸到专业之外&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#二-要把阅读范围延伸到专业之外&#34;&gt;#&lt;/a&gt; 二、要把阅读范围延伸到专业之外&lt;/h3&gt;
&lt;p&gt;阅读专业书籍当然必要，但主要为了今后职业的需要。鲁迅说：“这样的读书，和木匠的磨斧头，裁缝的埋针线并没有什么分别，并不见得高尚，有时还很苦痛，很可怜。”（《读书杂谈》）&lt;/p&gt;
&lt;p&gt;诸位报考大学的时候，刚刚从中学出来，都还不到二十岁吧，大人们还习惯于把我们称作孩子，青春的生命那么可爱又那么具有可塑性，却一下子被浇注在某个专业的模坯里直至终老，真是于心何忍。&lt;/p&gt;
&lt;p&gt;生命的活力，在于它的弹性。大学时代的生命弹性，除了运动和娱乐，更重要的体现为对世界整体的自由接纳和自主反应，这当然是超越专业的。&lt;/p&gt;
&lt;p&gt;现在很多所大学都发现了学生只沉陷于专业的弊病，开设了通识教育课，这是一个很好的办法。但同样作为一门课程，即使通识教育也保留着某种难于克服的狭隘性和被动性。因此不管功课多重，时间多紧，自由的课外阅读不可缺少。&lt;/p&gt;
&lt;p&gt;更何况，时代的发展使每门专业的内在结构和外部界限发生了很大的变化，没有足够的整体视野，连专业都很难学好。&lt;/p&gt;
&lt;h3 id=&#34;三-先找一些名著垫底&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#三-先找一些名著垫底&#34;&gt;#&lt;/a&gt; 三、先找一些名著垫底&lt;/h3&gt;
&lt;p&gt;大学生的课外阅读，是走向精神成熟的起点，因而先要做一点垫底的工作。&lt;/p&gt;
&lt;p&gt;垫什么样的底，就会建什么样的楼。因此尽量要把底垫得结实一点，但时间不多，要寻找一种省俭方式。最省俭的垫底方式，是选读名著。&lt;/p&gt;
&lt;p&gt;有些青年人对名著有一种逆反心理，为了保持自由而故意避开，这是孩子气的举动。名著不管是不是够格，总是时间和空间节选的结果，我们可以不在乎名著，却不可以不在乎时间和空间。一部似乎并不怎么样的作品居然被时间和空间首肯，这本身就是一个极有文化深度的悬念，光凭着这个悬念也值得去读一读。&lt;/p&gt;
&lt;p&gt;更重要的是，名著因被很多人反复阅读，已成为当代社会词语的前提性素材，如果不了解名著，就会在文化沟通中产生严重障碍。&lt;/p&gt;
&lt;p&gt;名著和其他作品在文化方位上是不平等的，它们好像军事上的制高点，占领了它们，很大一片土地就不在话下了。对于专业之外的文化领地，我们没有时间去一寸一寸占领，收取几个制高点就可以了。&lt;/p&gt;
&lt;p&gt;对于名著不能平均施力，一个时间只能死啃一本，附带着集中阅读与它有关的书籍，务必把这个制高点完全占领。这是一个似慢实快的办法，书桌上不堆放多种类别的书，更不要摆出博览群书的派头一目十行、一天一本。如果本本都是泛泛而读，到头来就像愚熊掰玉米，掰一个丢一个，满地狼藉却食不果腹。应该反过来，慢慢地啃一本是一本，神定气稳地反复咀玩。每一本又都是高水平的作品，那么用不了多久，你的学问规模就影影绰绰地成型了。&lt;/p&gt;
&lt;p&gt;有人认为，名著总是艰深的，不如读第二、第三流的作品省力。其实，第一流的作品由于逻辑比较清晰，表述比较果断、个性比较鲜明、形态比较优美，阅读起来不见得比第二、第三流的作品费力。即使费点力，因你内心深知其足可以一当十，也会感到值得。&lt;/p&gt;
&lt;p&gt;那么，如何确认名著呢？这就需要寻求帮助了。过去很多大学者都为青年人开列过 “必读书目”，但他们既要顾及各门学问的完整性，又要顾及青年人的多种层面和多种可能，总是把书目开得太长。“必读书目” 其实变成了 “重要书目”，可能一辈子也读不完。&lt;/p&gt;
&lt;p&gt;因此我们需要寻找一种更有针对性的小书目。是否有针对性决定于书目开列者对阅读者的了解程度。青年学生不妨找自己信赖的师长作一些必读书目方面的交谈，交谈中要把自己的兴趣、欠缺和已读过的名著告诉师长，以求获得有的放矢的指导。&lt;/p&gt;
&lt;h3 id=&#34;四-名著读不下去也可以暂时放下&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#四-名著读不下去也可以暂时放下&#34;&gt;#&lt;/a&gt; 四、名著读不下去也可以暂时放下&lt;/h3&gt;
&lt;p&gt;即使是一位熟悉的师长很有针对性地为我们开了一份必读书目，书目里的名著也有读不下去的时候。&lt;/p&gt;
&lt;p&gt;读不下去就放下，不要硬读。这就是非专业阅读的潇洒之处。&lt;/p&gt;
&lt;p&gt;这么有名的著作也放下？是的，放下。因为你与它没有缘分，或许说暂时无缘。&lt;/p&gt;
&lt;p&gt;再有针对性的书目也只考虑到了你接受的必要性，而无法考虑到你接受的可能性。所谓可能，不是指阅读能力，而是指兴奋系统，这是你的生命秘密。别人谁也不会清楚。&lt;/p&gt;
&lt;p&gt;阅读是对外部世界的开发，也是对自己生命的开发。开发生命并不是重塑生命，我们的生命并不太坏，没有必要打碎了重塑。任何开发都应该顺应着地理地脉，开发生命也是同样，硬撬硬击会伤筋动骨。如果某个领域的几部代表性名著都读不下去，那就证明你与那个领域整体无缘，想开一点，整体放弃。也许几年后突然读得下去了，说明当初的无缘是短暂现象。但暂时现象也是真实的，不可为几年后的可能而硬来。&lt;/p&gt;
&lt;p&gt;茫茫书海，真正与你有缘的只是一小角。名著如林，真正属于你的也只是不多的几十本。有不少名著属于有缘无缘之间，那也不妨一读，因为知道的范围总应该大于熟悉的范围，熟悉的范围总应该大于拥有的范围。只要有时间，算不上名著的多种书籍也不妨广泛地浏览一下，那里也会有大量既能契合你，又能提高你的东西。名著是基础，但不是封闭我们的城堡。&lt;/p&gt;
&lt;p&gt;我刚进大学的时候，有两位年老的图书馆管理员笑眯眯地告诉我，他们能从一年级学生的借书卡上预测这些学生将来的成就，几乎是百试不爽。毫无规律胡乱借书的很难有希望，穷几年之力死啃一大堆名著的也不会有太大的出息；借书卡上过于疏空的当然令人叹息，借书卡上密密麻麻的也叫人摇头。我上面讲的这些道理，有不少正是从他们那里讨教来的。&lt;/p&gt;
&lt;h3 id=&#34;五-有一两个文化偶像不是坏事&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#五-有一两个文化偶像不是坏事&#34;&gt;#&lt;/a&gt; 五、有一两个文化偶像不是坏事&lt;/h3&gt;
&lt;p&gt;在选读名著的过程中，最终会遇到几部名著、几位名家最与你情投意合。你着迷了，不仅反复阅读，而且还会寻找作者的其他著作，搜罗他们的传记，成为他们的崇拜者。我的一位朋友说他一听到辛弃疾的名字就会脸红心跳，我在读大学时对法国作家雨果也有类似的情景。这就是平常所说的偶像。&lt;/p&gt;
&lt;p&gt;偶像的出现，是阅读的一个崭新阶段的开始。能够与一位世界级或国家级的文化名人魂魄与共，真是莫大的幸福。然而更深刻的问题在于，你为什么与他如此心心相印？不完全是由于他的学问、艺术和名声，因为有很多比他学问更高、艺术更精、名声更大的人物却没有在你心底产生这样强烈的感应。根本的理由也许是，你的生命与他的生命，有某种同构关系，他是你精神血缘上的前辈姻亲。暗暗地认下这门亲，对你很有好处。&lt;/p&gt;
&lt;p&gt;同构不等于同级。他是万人瞩目的文化名人，你是寂寂无名的青年学生，但他的存在证明，你所进入的生命系统的某些部分，一旦升腾，会达到何等壮美的高度，于是你也就找到了一条通向崇高的缆绳。&lt;/p&gt;
&lt;p&gt;有的同学把文化偶像的崇拜一律看作幼稚行为，成天懒洋洋地对一切可以仰望、可以进入的对象爱理不理，偶尔心有所动也快速地自我熄灭，实在是坐失了很多良机。&lt;/p&gt;
&lt;p&gt;那些读了一辈子书却说不出最喜爱哪几部著作。哪几位作者的人，哪怕是学富五车的老学者，我也不敢恭维，在如此广阔的文化天地中失去了仰望的兴致，失去了亲和的热量，失去了趋附的动力，整个儿成了一尊冷眼面世的泥塑木雕，那还说得上什么？&lt;/p&gt;
&lt;h3 id=&#34;六-青年人应立足于个人静读&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#六-青年人应立足于个人静读&#34;&gt;#&lt;/a&gt; 六、青年人应立足于个人静读&lt;/h3&gt;
&lt;p&gt;青年人读了书，喜欢互相讨论。互相讨论能构建起一种兴趣场和信息场，单独的感受流通起来了，而流通往往能够增殖。&lt;/p&gt;
&lt;p&gt;但是总的说来，阅读是个人的事。字字句句都要由自己的心灵去默默感应，很多最重要的感受无法诉诸言表。阅读的程序主要由自己的生命线索来缩接，而细若游丝的生命线索是要小心翼翼地抽理和维护的。这一切，都有可能被热闹所毁损。更何况我们还是学生，即使有点肤浅的感受也不具备向外传播的价值。在同学间高谈阔论易生意气，而一有意气就会坠入片面，肤浅变得更加肤浅。&lt;/p&gt;
&lt;p&gt;就像看完一部感人至深的电影，一个善于吸收的观众，总喜欢独个儿静静地走一会，慢慢体味着一个个镜头、一句句台词，咀嚼着艺术家埋藏其间的良苦用心，而不会像有些青年那样，还没有出电影院的门就热烈谈论开来了。在很多情况下，青年人竞争式的谈论很可能是一种耗散，面对越是精雅深致的作品越可能是这样。&lt;/p&gt;
&lt;p&gt;等到毕业之后，大家在人生感受上日趋成熟而在阅读上却成了孤立无援的流浪者，这倒需要寻找机会多交流读书信息了。那是后话，过一会儿再说。&lt;/p&gt;
&lt;h3 id=&#34;七-读书卡片不宜多做&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#七-读书卡片不宜多做&#34;&gt;#&lt;/a&gt; 七、读书卡片不宜多做&lt;/h3&gt;
&lt;p&gt;读书有一个经常被传授的方法，那就是勤奋地做读书卡片。读到自己有兴趣的观点和资料，立即抄录在卡片上，几个月之后把一大堆卡片整理一番，分门别类地存放好，以后什么时候要用，只要抽出有关的一叠，自己也就可以获得一种有论有据、旁征博引的从容。&lt;/p&gt;
&lt;p&gt;这种方法，对于专业研究、论文写作是有用的，但不适合青年学生的课外阅读。&lt;/p&gt;
&lt;p&gt;从技术上说，课外阅读的范围较大，又不针对某个具体问题，卡片无从做起，即使做了也没有太大用处，白白浪费了许多阅读时间。如果要摘录隽语挂句，不如买一本现成的《名人名言录》放在手边。&lt;/p&gt;
&lt;p&gt;但技术上的问题还是小事。最麻烦的是，做卡片的方法很可能以章句贮藏取代了整体感受，得不偿失。一部好的作品是一个不可割裂的有机整体，即使撷取了它的眉眼，也失去了它的灵魂。&lt;/p&gt;
&lt;p&gt;有人说，做卡片的原因是自己记忆力太差，读过的书老也记不住，记不住等于白读，留下几张卡片也算是自我安慰。&lt;/p&gt;
&lt;p&gt;实际上，阅读的记忆力有一种严格的选择功能，书中真正深切触动你的内容，想丢也丢不掉，对此你要有更多的洒脱和自信。&lt;/p&gt;
&lt;p&gt;记不住当然是大量的，但记不住的内容又分两个部分，一部分是真实的遗忘，一部分是无形的沉潜。&lt;/p&gt;
&lt;p&gt;属于真实遗忘的那部分，不必可惜，就让它遗忘吧，能遗忘也是一个人自由自主的表现。太监之所以要记住宫中生活的每一个细节，因为他不能自由自主，不敢遗忘。正是遗忘，验证着生命结构的独立。&lt;/p&gt;
&lt;p&gt;至于无形沉潜的那部分，我想大家都有过体会。在一定场合，由于一定的需要，居然把多年前早就淡忘了的印象搅动起来了，使自己也大吃一惊。苏辙曾说：“早岁读书无甚解，晚年省事有奇功。” 翻译成现代口语，大致意思是：早年读书似乎没有深刻理解的地方，在晚年审察事物时却发挥了奇特的功效。这便是记忆的沉潜。&lt;/p&gt;
&lt;p&gt;人类的大脑机能十分神奇，不要在乎表面上的记住记不住，该记住的总会记住，该忘记的总会忘记，该失而复得的总会失而复得，轻轻松松读下去就是了。&lt;/p&gt;
&lt;p&gt;我不主张在课外阅读中做很多卡片，却赞成写一些读书笔记，概括全书的神采和脉络、记述自己的理解和感受。这种读书笔记，既在描述书，又在描述自己。每一篇都不要太长，以便对即时的感受进行提炼，把感受提炼成见识。&lt;/p&gt;
&lt;h3 id=&#34;八-有空到书店走走&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#八-有空到书店走走&#34;&gt;#&lt;/a&gt; 八、有空到书店走走&lt;/h3&gt;
&lt;p&gt;大学生的阅读资源，主要来自图书馆。但是，我希望大家有空也到书店走走。书店当然比图书馆狭小得多，但它是很有意思的文化前沿。当代人的精神劳作有什么走向？这些走向与社会走向有什么关系？又被大众接受到什么程度？解答这些疑问的最好场所是书店。&lt;/p&gt;
&lt;p&gt;崭新的纸页，鲜亮的封面，夸张的宣传，繁忙的销售，处处让你感受到书籍文明热气腾腾的创造状态，而创造，总是给人一种愉悦的力量。这种力量对读书人是一种莫名的滋养，使你在长久的静读深思之后舒展筋骨，浑身通畅。&lt;/p&gt;
&lt;p&gt;你可以关注一下畅销书排行榜，判断一下买书的人群，然后，也准备为自己选几本书。在书店选书与在图书馆有所不同，对于重要的书，你会反复考虑永久性拥有的必要性，于是在书架前进行了一次短短的自我拷问。你也许会较少犹豫地购买儿本并不重要却有趣、可爱的新书，由此你对自己与书籍的奇异关系产生了某种疑问，这种疑问的每一个答案都让人开心。&lt;/p&gt;

 &lt;h2 id=&#34;摆脱童稚状态&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#摆脱童稚状态&#34;&gt;#&lt;/a&gt; 摆脱童稚状态&lt;/h2&gt;
&lt;p&gt;王小波  著&lt;/p&gt;
&lt;p&gt;在李银河所译约翰・盖格农《性社会学》一书中，第十七章 “性环境” 集中叙述了美国对含有性内容的作品审查制度的变迁，因而成为全书最有神采的一章。美国在二次大战前对 “色情作品” 的审查是最严的，受到打击的绝不止真正的色情作品。就以作家为例，不但海明威、雷马克有作品被禁，连最为 “道学” 的列夫・托尔斯泰也上了禁书榜。在本世纪二十年代，美国的禁书榜上不但包括了乔伊斯的《尤利西斯》，劳伦斯的《恋爱中的女人》等等，拉伯莱斯的《阿拉伯之夜》和雷马克的《西线无战事》也只能出节本。事有凑巧，我手上正好有一本国内出版的《西线无战事》，也是节本，而且节得上气不接下气。这种相似之处，我相信不仅仅是有趣而已。以前我们谈到国内对书刊、影视某些内容过于敏感时，总是归因于中外国情不同，社会制度不同，假如拿美国的三十年代和现在中国做个对比，就很容易发现新的线索。&lt;/p&gt;
&lt;p&gt;自一次大战后，美国对色情作品的检查呈稳步上升之势。一方面对性作品拼命压制，一方面严肃文学中性主题不断涌现，结果是从联邦到州、市政府开出了长得吓人的禁书书单。遭难的不只是上述作家，连《圣经》和莎翁的戏剧也只能通过节本和青少年见面。《圣经》抽掉了《雅歌》，莎翁抽掉了所谓猥亵的内容，结果是孩子们简直就看不明白。当然，受到限制的不仅是书刊，电影也没有逃出审查之网。在电影里禁止表现娼妓、长时间的做爱，禁止出现裸体、毒品、混血儿（！！）、性病、生育和嘲笑神职人员的镜头。&lt;/p&gt;
&lt;p&gt;当时严格的检查制度有其理论，这种理论认为一切对性的公开正面（非谴责性）的讨论都会导致性活动的泛滥，因为性知识是性行为的前兆。这就是说，性冲动是强大的，一受刺激就会自动表达出来。与此相辅相成的是另一个理论：性是危险的，人是薄弱的，必须控制性来保护人。这种观点和时下主张对文学作品严加控制的观点甚是相似。在我们国家里，现在正有人认为青少年的性犯罪和书籍、录像带有关系，还有一些家长反映孩子看了与性有关的书刊，影响了学习，因此主张对有性内容的书刊、录像严加限制。&lt;/p&gt;
&lt;p&gt;但是在我看来，像这样的观点因为是缺少科学训练的人提出的，多少总有点混乱不清的地方。比方说二十年代美国这种理论，在科学上我们只能承认它是一种假设，必须经过验证才能成立；而且它又是一种最糟不过的假设，定义不清，以致无法设计一种检验方法。我在报刊上看到一些统计数字，指出有多少性犯罪的青少年看过 “不良” 书刊或者黄色录像带，但是这样立论是错误的。实际上有效的立论应是指出有多少看过 “不良” 书刊的青少年犯了罪。在概率论上这是两个不同的反验概率，没有确定的关系，也不能够互相替代。至于家长说孩子看了与性有关的书刊，影响了学习，实际上是提出了一个因果模型 —— 看某些书刊→影响学习。有经验的社会学家都会同意，建立一个可靠的因果模型是非常困难的。就以前述家长的抱怨为例，首先你要证明，你的孩子是先看了某些书刊，而后学习成绩才下降的；其次你要证明没有一个因素既影响到孩子看某种书，也影响到孩子的学习。我知道有一个因素要影响到这两件事，就是孩子的性成熟。故而上述家长的抱怨不能成立。现在的孩子营养好，性成熟早，对性知识的需求比他们的父母要早。据我所知，这是造成普遍忧虑的一个原因。假如家长只给他们馒头和咸菜吃，倒可以解决问题（使其性成熟期晚些到来）。以上论述要说明的是，关于色情作品对青少年的腐蚀作用，公众从常识的观点得出的结论和专家能做出的结论是不一样的。倘非如此，专家就不成其为专家。&lt;/p&gt;
&lt;p&gt;当然，人们给所谓色情作品定下的罪名不仅是腐蚀青少年，而且是腐蚀社会。在这方面书中有一个例子，就是六十年代的丹麦实验。1967 年，丹麦开放了色情文学（真正的色情文学）作品，1969 年开放了色情照片，规定色情作品可以生产，并出售给十六岁以上的公民。这项实验有了两项重要结果：其一是，丹麦人只是在初开禁时买了一些色情品，后来就不买或是很少买，以致在开禁几年后，所有的色情商店从哥本哈根居民区绝迹，目前只在两个小小的地区还在营业，而且只靠旅游者生存。本书作者对此的结论是：“人有多种兴趣，性只是其中的一种，色情品又只是其中一个小小的侧面。几乎没有人会把性当作自己的主要生活兴趣，把色情品当作自己的主要生活兴趣的人就更少见。”&lt;/p&gt;
&lt;p&gt;丹麦实验的第二个重大发现是色情业的开放对某些类型的犯罪有重大影响。猥亵儿童发案率下降了百分之八十，露阴癖也有大幅度下降。暴力污辱罪（强 xx，猥亵）也减少了，其他犯罪数量没有改变。这个例子说明色情作品的开放会减少而不是增加性犯罪。笔者引述这个例子，并不是主张什么，只是说明有此一事实而已。&lt;/p&gt;
&lt;p&gt;美国对色情作品的审查浪潮在二次大战后忽然退潮了。本书作者的观点是：这和美国从一个保守的、乡村为主的单一清教国家，转变成了多元的国家有关。前者是反移民、反黑人、反共、排外的，社会掌握在道德警察手里；后来变成了一个都市化、工业化的社会，那种严格检查的背景就不存在了。这种说明对我们甚有意义，我们国家也是一个以乡村为主的国家。至于清教传统，我们没有过。清教徒认为人本性是恶的，必须加以限制。我们国家传统哲学认为人性本善，但是一到了 “慕少艾” 的年龄，他就不再是好东西了。所以对于青春期以后的人，两边的看法是完全一样的。本书作者给出了一个美国色情开放程度的时间表，在此列出，以备参考：&lt;/p&gt;
&lt;p&gt;早于四十年代：任何女性的裸体或能引起这类联想的东西，包括掀起的衣裙、乳头的暗示，都属禁止之列；&lt;/p&gt;
&lt;p&gt;四十年代：色情杂志上出现裸女背影；&lt;/p&gt;
&lt;p&gt;五十年代：乳房的侧影；&lt;/p&gt;
&lt;p&gt;六十年代：出现乳头，《花花公子》杂志上出现女性阴部；&lt;/p&gt;
&lt;p&gt;七十年代：男性生殖器出现在《维瓦》和《花花女郎》杂志上，女性的阴唇出现在《阁楼》和《花花公子》杂志上。&lt;/p&gt;
&lt;p&gt;每当杂志走得更远时，审查员就大声疾呼，灾难就要降临，但是后来也没闹什么灾。所以这些人就落入了喊 “狼来了” 那个孩子的窘境。&lt;/p&gt;
&lt;p&gt;《性社会学》这本书里把对影视出版的审查，看作一种性环境。这种审查的主要目标是色情作品，所以含有性内容的严肃作品在这里只是被 “捎带” 的。所谓严肃作品，在我看来应该是虽然写到了性，但不以写性为目的的作品。这其中包括了以艺术上完美为目标的文学、影视作品，社会学、人类学的专业书，医学心理学的一部分书。据我所知，这类作品有时会遇到些麻烦。从某种意义上讲，严肃的作家、影视从业人员也可以算作专家，从专家的角度来看审查制度，应该得到什么样的结论呢？&lt;/p&gt;
&lt;p&gt;改革开放之初，聂华苓、安格尔夫妇到中国来，访问了我国一批老一代作家。安格尔在会见时问：你们中国的作品里，怎么没有写性呢？性是生活中很重要的事呀。我国一位年长的作家答道：我们中国人对此不感兴趣！这当然是骗洋鬼子的话，实际情况远非如此。但是洋鬼子不吃骗，又问道：你们中国有好多小孩子，这是怎么一回事？这句话的潜台词就是这些孩子不是你捏着鼻子、忍着恶心造出来的吧。当然，我们可以回答：我们就是像吃苦药那样做这件事！但是这样说话就等于承认我们都是伪君子。事实上性在中国人生活里也是很重要的事，我们享受性生活的态度和外国人没有什么不同。在这个方面没必要装神弄鬼。既然它重要，自然就要讨论。严肃的文学不能回避它，社会学和人类学要研究它，艺术电影要表现它。这是为了科学和艺术的缘故。然而社会要在这方面限制它，于是，问题就不再是性环境，而是知识环境的问题了。&lt;/p&gt;
&lt;p&gt;《性社会学》这本书描述了二十年代美国是怎样判决淫秽书的：起诉人从大部头书里摘出一段来，念给陪审员听，然后对他们说：难道你希望你们的孩子读这样的书吗？结果海明威、劳伦斯、乔伊斯就这样被禁掉了。我不知道我们国家里现在有没有像海明威那样伟大的作家，但我知道假如有的话，他一定为难以发表作品而苦恼。海明威能写出让起诉人满意的书吗？不能。&lt;/p&gt;
&lt;p&gt;我本人就是个作者。任何作者的书出版以后，会卖给谁他是不能够控制的。假如一位严肃作家写了性，尽管其本心不是煽情、媚俗，而是追求表达生活的真谛，也不能防止这书到了某个男孩子手里，起到手淫前性唤起的作用。故此社会对作家的判决是：因为有这样的男孩子存在，所以你的书不能出。这不是太冤了吗？但我以为这样的事还不算冤，社会学家和心理学家比他还要冤。事实上社会要求每个严肃作家、专业作者把自己的读者想象成十六岁的男孩子，而且这些男孩似乎还是不求上进、随时要学坏的那一种。&lt;/p&gt;
&lt;p&gt;我本人又是个读者，年登不惑，需要看专业书，并且喜欢看严肃的文学书，但是市面上只有七十二个故事的《十日谈》、节本《金瓶梅》，和被宰得七零八落的雷马克，还有一些性心理学性社会学的书，不客气地说，出得完全是乌七八糟。前些日子买了一本福柯的《性史》，根本看不懂，现在正想办法找英文本来看。这种情形对我是一种极大的损害。在此我毫不谦虚他说，我是个高层次的读者，可是书刊检查却拿我当十六岁的孩子看待。&lt;/p&gt;
&lt;p&gt;这种事情背后隐含着一个逻辑，就是我们国家的出版事业必须就低不就高。一本书能不能出，并不取决于它将有众多的有艺术鉴赏力或者有专业知识的读者，这本书应该对他们有益，而是取决于社会上存在着一些没有鉴赏力或没有专业知识的读者，这本书不能对他们有害。对我来说，书刊审查不是个性环境，而是个知识环境问题，对其他知识分子也是这样的。这一点是《性社会学》上没有提到的。二三十年代，有头脑的美国人，如海明威等，全在欧洲待着。后来希特勒把知识分子又都撵回到美国去，所以美国才有了科学发达、人文荟萃的时代。假如希特勒不在欧洲烧书、杀犹太人，我敢说现在美国和欧洲相比，依然是个土得掉渣的国家。我不敢说国内人才凋零是书刊检查之故，但是美国如果现在出了希特勒，我们国内的人才一定会多起来。&lt;/p&gt;
&lt;p&gt;假如说市场上有我需要的书，可能会不利于某些顽劣少年的成长的话，有利于少年成长的书也不适合于我们。这一点与意识形态无关。举例而言，《雷锋的故事》这样的书对青年有益，把它译成英文，也很适合西点军校的学员阅读，但是对于那些秃顶教授，就不那么适宜。再比方说，《罗兰小语》、琼瑶的小说，对美国 highschool 的女生很适宜（可惜的是美国这类书已经很多了），但是对于年过四旬，拿了博士学位，在大学里讲社会学的知识分子就不适宜，如果强要他们读的话，大概会感到有点恶心。这种人甚至会读 StoryofO，虽然你问他时他不一定肯承认。有人会争辩说，孩子是我们的未来，应该为他们做牺牲。但是现在的问题是牺牲的代价是让成人也变成孩子。这样做的结果是我们根本就不会有什么未来。&lt;/p&gt;
&lt;p&gt;现在美国和欧洲把成人和儿童的知识环境分开，有些书、有些电影儿童不能看。这种做法的背后的逻辑是承认成人有自我控制的能力，无须法庭、教会来决定哪些他能够知道，哪些他不能知道。这不仅是因为成人接触这些知识是无害的，也不仅仅是因为这些知识里有他需要知道的成分，还因为这是对成年人人格的尊重。现代社会的前景是每个人都要成为知识分子，限制他获得知识就是限制他的成长。而正如孙隆基在《中国文化的深层结构》里指出的，目前中国人面对的知识环境是一种童稚状态，处于弗洛伊德所说的肛门时期。也许，因为种种原因，特别是历史原因，我们眼下还不能不有一些童稚的做法。那么，下一步怎么办？一种做法是继续保持童稚状态，一种做法是摆脱童稚状态，准备长大。相信前一种做法的人，也相信乔治・奥威尔在《1984》里杜撰的口号 —— 无知即力量；相信后一种做法的人，也相信培根的名言 —— 知识就是力量。这 “下一步” 当然不是把日历翻过去就是的明天，但是，也不应当是日历永远翻不到的明天。&lt;/p&gt;

 &lt;p&gt;&lt;strong&gt;文中插件点击标题即可跳转到官方下载界面&lt;/strong&gt;&lt;/p&gt;
&lt;h3 id=&#34;1akismet-反垃圾评论&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#1akismet-反垃圾评论&#34;&gt;#&lt;/a&gt; 1.&lt;strong&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9jbi53b3JkcHJlc3Mub3JnL3BsdWdpbnMvYWtpc21ldC8=&#34;&gt;Akismet 反垃圾评论&lt;/span&gt;&lt;/strong&gt;&lt;/h3&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/02/image-7.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;直接注册可以用免费版本的，会给个 API 密钥，这个插件可以减少垃圾评论的骚扰。&lt;/p&gt;
&lt;p&gt;一定要记住给的 API 密钥（好像没法找回）&lt;/p&gt;
&lt;h3 id=&#34;2ashuwp-invitaion-code&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#2ashuwp-invitaion-code&#34;&gt;#&lt;/a&gt; 2.&lt;strong&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9jbi53b3JkcHJlc3Mub3JnL3BsdWdpbnMvYXNodXdwLWludml0YWlvbi1jb2RlLw==&#34;&gt;Ashuwp invitaion code&lt;/span&gt;&lt;/strong&gt;&lt;/h3&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/02/image-8.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;可以生成一些邀请码，用户在注册的时候可以输入。非常好用的插件。&lt;/p&gt;
&lt;p&gt;用 Wordfence 扫描的话会出现提示说要升级，不用管它就行 (好几年没更新了的说ㄟ ( ▔, ▔) ㄏ)。&lt;/p&gt;
&lt;h3 id=&#34;3fonts-plugin&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#3fonts-plugin&#34;&gt;#&lt;/a&gt; &lt;strong&gt;3.&lt;/strong&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9jbi53b3JkcHJlc3Mub3JnL3BsdWdpbnMvb2x5bXB1cy1nb29nbGUtZm9udHMv&#34;&gt;Fonts Plugin&lt;/span&gt;&lt;/h3&gt;
&lt;p&gt;可以设置更多的字体，&lt;/p&gt;
&lt;p&gt;我个人还是喜欢比较适合阅读的字体 2333&amp;lt;---- 胡说你就是懒 (￣ε(#￣)☆╰╮o (￣皿￣///)&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/02/image-9-1024x480.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;只能在 “外观” 中的 “自定义” 模式里使用&lt;/p&gt;
&lt;h3 id=&#34;4wordfence&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#4wordfence&#34;&gt;#&lt;/a&gt; 4.&lt;strong&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9jbi53b3JkcHJlc3Mub3JnL3BsdWdpbnMvd29yZGZlbmNlLw==&#34;&gt;Wordfence&lt;/span&gt;&lt;/strong&gt;&lt;/h3&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/02/image-10-1024x438.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;网站安全防护插件，自动配置无法进行的话，可以使用手动配置。&lt;/p&gt;
&lt;p&gt;手动配置的话，要先找到建站目录下的 user.ini 话说这不就是官方教程吗&lt;/p&gt;
&lt;p&gt;然后打开加入这句话&lt;/p&gt;
&lt;h3 id=&#34;5wp-mail-smtp&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#5wp-mail-smtp&#34;&gt;#&lt;/a&gt; 5.&lt;strong&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9jbi53b3JkcHJlc3Mub3JnL3BsdWdpbnMvd3AtbWFpbC1zbXRwLw==&#34;&gt;WP Mail SMTP&lt;/span&gt;&lt;/strong&gt;&lt;/h3&gt;
&lt;p&gt;一般博客网站会有博主回复的邮件提示，这个插件就可以实现这个功能。&lt;/p&gt;
&lt;p&gt;可以申请个企业邮箱或者小号的邮箱来发邮件 2333&lt;/p&gt;
&lt;p&gt;记得要设置下 SMTP 主机。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/02/image-14-1024x603.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;QQ 邮箱的话可以在 “设置” 中的 “账户‘进行设置。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/02/image-15-1024x343.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;阿里云企业邮箱的话，我一开始没找到服务器，然后没不知道 SMTP 密码。后来找帖子找出来了，就是下面这个。&lt;/p&gt;
&lt;p&gt;下面这是个服务器&lt;/p&gt;
&lt;p&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cDovL3NtdHAubXhoaWNoaW5hLmNvbQ==&#34;&gt;smtp.mxhichina.com&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;至于 SMTP 密码，就是阿里云邮箱的登录密码了。&lt;/p&gt;
&lt;h3 id=&#34;6经典编辑器&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#6经典编辑器&#34;&gt;#&lt;/a&gt; 6.&lt;strong&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9jbi53b3JkcHJlc3Mub3JnL3BsdWdpbnMvY2xhc3NpYy1lZGl0b3Iv&#34;&gt; 经典编辑器&lt;/span&gt;&lt;/strong&gt;&lt;/h3&gt;
&lt;p&gt;这个比较适合单纯些文章的博客了。（写代码的话，不知道为啥，我的会出现代码缩进全部没了的情况&lt;/p&gt;
&lt;p&gt;然后花了快半个小时给 Python 加缩进，还没法用 Tab），当然两个编辑器也是可切换的。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/02/image-11.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;“设置” 里面的 “撰写设置” 切换&lt;/p&gt;
&lt;p&gt;如果在经典编辑器上写好的内容，转到区块编辑器会显示成一个名为 “经典” 的区块&lt;/p&gt;
&lt;p&gt;经典编辑器的效果就是这样的：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/02/image-12-1024x615.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;经典编辑器&lt;/p&gt;
&lt;p&gt;区块编辑器的是这样的：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/02/image-13-1024x503.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;区块编辑器&lt;/p&gt;
&lt;h3 id=&#34;7wp-china-yes&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#7wp-china-yes&#34;&gt;#&lt;/a&gt; 7.&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93cC1jaGluYS5vcmcv&#34;&gt;WP-China-Yes&lt;/span&gt;&lt;/h3&gt;
&lt;p&gt;这款插件可以更方便的下载 wordpress 插件不用麻烦的上传了。&lt;/p&gt;
&lt;p&gt;如何形容呢？&lt;/p&gt;
&lt;p&gt;比方说，原来下载是这样子：妮可妮可妮 &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cuYmlsaWJpbGkuY29tL3ZpZGVvL0JWMTNiNHkxUTd5Zz9zaGFyZV9zb3VyY2U9Y29weV93ZWI=&#34;&gt;妮可妮可妮（（（&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/02/2019632242261259.gif&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;安装之后是：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://tse1-mm.cn.bing.net/th/id/R-C.9858cc71083664437cdff38781824361?rik=D3oDxeqznHrKIA&amp;amp;riu=http%3a%2f%2fwww.bkill.com%2fu%2fupload%2f2018%2f10%2f21%2f212349295799.gif&amp;amp;ehk=pIEB9zGi%2bJH6ktmQ3BHTnnSdqBZyFh9ojAC%2b3RfLu7c%3d&amp;amp;risl=&amp;amp;pid=ImgRaw&amp;amp;r=0&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;8heimu&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#8heimu&#34;&gt;#&lt;/a&gt; 8.&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9jbi53b3JkcHJlc3Mub3JnL3BsdWdpbnMvaGVpbXUv&#34;&gt;Heimu&lt;/span&gt;&lt;/h3&gt;
&lt;p&gt;插件功能如其名，就是添加黑幕的。&lt;/p&gt;
&lt;p&gt;安装好后，就可以用了。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/02/image-28.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;像这样：我永远喜欢萌百娘！！！&lt;/p&gt;
&lt;h3 id=&#34;特别注意&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#特别注意&#34;&gt;#&lt;/a&gt; 特别注意&lt;/h3&gt;
&lt;p&gt;使用延迟加载插件有几率出现遮挡不全的 BUG，慎用&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/02/image-29-1024x506.webp&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;如图&lt;/p&gt;
&lt;p&gt;总之，这些插件需要者可以自己去安装，当然有不足之处，还请评论区指出。&lt;/p&gt;

 &lt;p&gt;本人是根据这个&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cDovLzQyLjE5Mi4xNTAuMjQ3Lz9wPTEwMQ==&#34;&gt;帖子&lt;/span&gt;找到的方法，还有这个&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cuY25ibG9ncy5jb20vc2hhd24xMjMvcC8xMjAzNjI3OC5odG1s&#34;&gt;帖子&lt;/span&gt;提供的代码做出来的。&lt;/p&gt;
&lt;p&gt;代码如下：&lt;/p&gt;
&lt;p&gt;在” 页尾信息 “可输入这段代码&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;网站运行：&amp;lt;span id=&amp;quot;htmer_time&amp;quot; style=&amp;quot;color: red;&amp;quot;&amp;gt;&amp;lt;/span&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;这个设置出来文字是红色，可以根据需要修改&lt;/p&gt;
&lt;p&gt;需要什么颜色就可以在上方代码中的 color 后修改成自己想要的颜色（英文名称或者 十六进制颜色表都可以）。&lt;/p&gt;
&lt;p&gt;我设置的是 #5e5e5e，仅供参考&lt;/p&gt;
&lt;p&gt;其中” 网站运行 “可以需改成需要的文字。&lt;/p&gt;
&lt;p&gt;后面的” 页尾附加代码 “部分则输入下面这段代码；&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;35&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;36&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;37&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;38&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;39&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;40&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;41&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;42&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;43&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&amp;lt;script&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; function secondToDate(second) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; if (!second) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; return 0;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; var time = new Array(0, 0, 0, 0, 0);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; if (second &amp;gt;= 365 * 24 * 3600) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; time[0] = parseInt(second / (365 * 24 * 3600));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; second %= 365 * 24 * 3600;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; if (second &amp;gt;= 24 * 3600) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; time[1] = parseInt(second / (24 * 3600));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; second %= 24 * 3600;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; if (second &amp;gt;= 3600) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; time[2] = parseInt(second / 3600);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; second %= 3600;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; if (second &amp;gt;= 60) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; time[3] = parseInt(second / 60);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; second %= 60;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; if (second &amp;gt; 0) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; time[4] = second;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; return time;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;lt;/script&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;lt;script type=&amp;quot;text/javascript&amp;quot; language=&amp;quot;javascript&amp;quot;&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; function setTime() &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; // 博客创建时间秒数，时间格式中，月比较特殊，是从 0 开始的，所以想要显示 5 月，得写 4 才行，如下&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; var create_time = Math.round(new Date(Date.UTC(2022, 1, 1, 10, 01, 0))//这里的(new Date(Date.UTC(2022, 1, 1, 10, 01, 0))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; .getTime() / 1000);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; // 当前时间秒数,增加时区的差异&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; var timestamp = Math.round((new Date().getTime() + 8 * 60 * 60 * 1000) / 1000);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; currentTime = secondToDate((timestamp - create_time));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; currentTimeHtml = currentTime[0] + &amp;#x27;年&amp;#x27; + currentTime[1] + &amp;#x27;天&amp;#x27;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; + currentTime[2] + &amp;#x27;时&amp;#x27; + currentTime[3] + &amp;#x27;分&amp;#x27; + currentTime[4]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; + &amp;#x27;秒&amp;#x27;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; document.getElementById(&amp;quot;htmer_time&amp;quot;).innerHTML = currentTimeHtml;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; setInterval(setTime, 1000);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;lt;/script&amp;gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;完成以后保存，可以去首页看看了。&lt;/p&gt;
&lt;p&gt;就是这样的一个效果：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/02/image-4.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;如果觉得这样在同一行不好看的话，可以加个换行符，这样：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/02/image-5-1024x217.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;br/&gt;就是 HTML 换行符。&lt;/p&gt;
&lt;p&gt;显示效果最后就是这样：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/02/image-6-1024x265.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;

 &lt;p&gt;这几天再整这个主题的时候 发现了个问题，就是设置的分类，点击会 404 报错，如下图：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/02/%E5%BE%AE%E4%BF%A1%E5%9B%BE%E7%89%87_20220206095731-1024x400.jpg&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;最初以为是我的 Nginx 的问题，就查了下，发现没有作用，之后就找到主题的&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9naXRodWIuY29tL21pcmFpLW1hbW9yaS9TYWt1cmFpcm8vaXNzdWVz&#34;&gt; GitHub 反馈页&lt;/span&gt;找了下才找到解决办法。&lt;/p&gt;
&lt;p&gt;在这个&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9naXRodWIuY29tL21pcmFpLW1hbW9yaS9TYWt1cmFpcm8vaXNzdWVzLzI4MA==&#34;&gt;帖子&lt;/span&gt;里找到的解决办法&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/02/image-1024x142.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;伪静态的话，我用的是宝塔 Linux 面板，就直接很容易找到：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/02/image-1.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;在站点的设置界面就可以找到了&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/02/image-3.png&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;就是这段代码:&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;location /&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; try_files $uri $uri/ /index.php?$args;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rewrite /wp-admin$ $scheme://$host$uri/ permanent;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;尽量不要用网上找到的代码，&lt;/p&gt;
&lt;p&gt;否则进入后台的时候会有如下错误：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://image.xenolies.xyz/2022/02/3cb29a4134d56c64.jpg&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt;让我折腾到了半夜&lt;/p&gt;
&lt;p&gt;设置好以后就可以舒舒服服的写文章啦╰(￣ω￣ｏ)&lt;/p&gt;
